-- Poems batch 480
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-0','奉和顏使君真卿與陸處士羽登妙喜寺三癸亭','皎然','唐','御定全唐诗','yuding','','[]','秋意西山多，列岑縈左次。繕亭曆三癸，疏趾鄰什寺。',132,'御定全唐詩/json/817.json','["秋意西山多，列岑縈左次。繕亭曆三癸，疏趾鄰什寺。", "元化隱靈蹤，始君啟高誄。誅榛養翹楚，鞭草理芳穗。", "俯砌披水容，逼天掃峰翠。境新耳目換，物遠風煙異。", "倚石忘世情，援雲得真意。嘉林幸勿剪，禪侶欣可庇。", "衛法大臣過，佐游群英萃。龍池護清澈，虎節到深邃。", "徒想嵊頂期，於今沒遺記。"]'),
('yuding-1','奉陪陸使君長源、裴端公樞春遊東西武丘寺','皎然','唐','御定全唐诗','yuding','','[]','雲水夾雙刹，遙疑湧平陂。入門見藏山，元化何由窺。',96,'御定全唐詩/json/817.json','["雲水夾雙刹，遙疑湧平陂。入門見藏山，元化何由窺。", "曳組探詭怪，停驄訪幽奇。情高氣為爽，德暖春亦隨。", "瑤草自的皪，蕙樓爭蔽虧。金精落壞陵，劍彩沈古池。", "一覽匝天界，中峰步未移。應嘉生公石，列坐援松枝。"]'),
('yuding-2','奉和陸使君長源夏月遊太湖','皎然','唐','御定全唐诗','yuding','','[]','庾公心曠遠，府事局耳目。遂與南湖遊，虛襟滌煩燠。',120,'御定全唐詩/json/817.json','["庾公心曠遠，府事局耳目。遂與南湖遊，虛襟滌煩燠。", "始知皇天意，積水在亭育。細流信不讓，動物欣所蓄。", "萬頃合天容，洗然無雲族。峭蒨矚仙嶺，超遙隨明牧。", "知公愛澄清，波靜氣亦肅。已見橫流極，況聞長鯨戮。", "中洲暫采蘋，南郡思剖竹。向夕分好風，飄然送歸舳。"]'),
('yuding-3','奉和崔中丞使君論李侍禦萼登爛柯山宿石橋寺效小謝體','皎然','唐','御定全唐诗','yuding','','[]','常愛謝公郡，幽期願相從。果回青驄臆，共躡玄仙蹤。',120,'御定全唐詩/json/817.json','["常愛謝公郡，幽期願相從。果回青驄臆，共躡玄仙蹤。", "靈境若仿佛，爛柯思再逢。飛梁丹霞接，古局蒼苔封。", "往想冥昧理，誰親冰雪容。蕙樓聳空界，蓮宇開中峰。", "昔化沖虛鶴，今藏護法龍。雲窺香樹遝，月見色天重。", "永夜寄岑寂，清言滌心胸。盛遊千年後，書在岩中松。"]'),
('yuding-4','同顏使君真卿、李侍禦萼游法華寺登鳳翅山望太湖','皎然','唐','御定全唐诗','yuding','','[]','雙峰開鳳翅，秀出南湖州。地勢抱郊樹，山威增郡樓。',96,'御定全唐詩/json/817.json','["雙峰開鳳翅，秀出南湖州。地勢抱郊樹，山威增郡樓。", "正逢周柱史，來會魯諸侯。緩步淩彩蒨，清鐃發颼飀。", "披雲得靈境，拂石臨芳洲。積翠遙空碧，含風廣澤秋。", "蕭辰資麗思，高論驚精修。何似鐘山集，徵文及惠休。"]'),
('yuding-5','奉陪陸使君長源諸公游支硎寺','皎然','唐','御定全唐诗','yuding','','[]','嘗覽高逸傳，山僧有遺蹤。佐遊繼雅篇，嘉會何由逢。',85,'御定全唐詩/json/817.json','["嘗覽高逸傳，山僧有遺蹤。佐遊繼雅篇，嘉會何由逢。", "塵世即下界，色天當上峰。春暉遍眾草，寒色留高松。", "繚繞彩雲合，參差綺樓重。瓊葩灑巾舄，石de清心胸。", "靈境若可托，道情知所從。"]'),
('yuding-6','奉陪鄭使君諤遊太湖至洞庭山登上真觀卻望湖水','皎然','唐','御定全唐诗','yuding','','[]','郡齋得無事，放舟下南湖。湖中見仙邸，果與心賞俱。',108,'御定全唐詩/json/817.json','["郡齋得無事，放舟下南湖。湖中見仙邸，果與心賞俱。", "不遠風物變，忽如寰宇殊。背雲視層崖，別是登蓬壺。", "突兀盤水府，參差遝天衢。回瞻平蕪盡，洪流豁中區。", "氣吞江山勢，色淨氛靄無。靈長習水德，勝勢當地樞。", "朝宗動歸心，萬里思鴻途。"]'),
('yuding-7','奉和袁使君高，郡中新亭會張煉師晝會二上人','皎然','唐','御定全唐诗','yuding','','[]','置亭隱城堞，事簡跡易幽。公性崇儉素，雅才非廣求。',84,'御定全唐詩/json/817.json','["置亭隱城堞，事簡跡易幽。公性崇儉素，雅才非廣求。", "傍簷竹雨清，拂案杉風秋。不移府中步，登茲如遠遊。", "坐覺詩思高，俯知物役休。虛寂偶禪子，逍遙親道流。", "更聞臨川作，下節安能酬。"]'),
('yuding-8','奉和陸使君長源水堂納涼效曹劉體','皎然','唐','御定全唐诗','yuding','','[]','柳家陶暑亭，意遠不可齊。煩襟蕩朱弦，高步援綠荑。',96,'御定全唐詩/json/817.json','["柳家陶暑亭，意遠不可齊。煩襟蕩朱弦，高步援綠荑。", "愛公滿亭客，來是清風攜。瀅渟前溪上，曠望古郡西。", "六月正中伏，水軒氣常淒。野香襲荷芰，道性親鳧鷖。", "禪子顧惠休，逸民重劉黎。乃知高世量，不以出處暌。"]'),
('yuding-9','夏日奉陪陸使君長源公堂集','皎然','唐','御定全唐诗','yuding','','[]','府中自清遠，六月高梧間。寥亮泛雅瑟，逍遙扣玄關。',48,'御定全唐詩/json/817.json','["府中自清遠，六月高梧間。寥亮泛雅瑟，逍遙扣玄關。", "嶺雲與人靜，庭鶴隨公閑。動息諒兼遂，茲情即東山。"]'),
('yuding-10','九日和於使君思上京親故','皎然','唐','御定全唐诗','yuding','','[]','霽景滿水國，我公望江城。碧山與黃花，爛熳多秋情。',48,'御定全唐詩/json/817.json','["霽景滿水國，我公望江城。碧山與黃花，爛熳多秋情。", "搖落見松柏，歲寒比忠貞。歡娛在鴻都，是日思朝英。"]'),
('yuding-11','伏日就湯評事衡湖上避暑','皎然','唐','御定全唐诗','yuding','','[]','大火方燥石，停雲晝亦收。將從賞心侶，寸景難遠遊。',72,'御定全唐詩/json/817.json','["大火方燥石，停雲晝亦收。將從賞心侶，寸景難遠遊。", "擁幾苦炎伏，出門望汀洲。回溪照軒宇，廣陌臨梧楸。", "釋悶命雅瑟，放情思亂流。更持無生論，可以清煩憂。"]'),
('yuding-12','《奉和顏使君真卿修韻海》畢會諸文士東堂重校','皎然','唐','御定全唐诗','yuding','','[]','外學宗碩儒，遊焉從後進。恃以仁恕廣，不學門欄峻。',84,'御定全唐詩/json/817.json','["外學宗碩儒，遊焉從後進。恃以仁恕廣，不學門欄峻。", "著書裨理化，奉上表誠信。探討始河圖，紛綸歸海韻。", "親承大匠琢，況睹頹波振。錯簡記鉛槧，閱書移玉鎮。", "曷由旌不朽，盛美流歌引。"]'),
('yuding-13','喜義興權明府自君山至，集陸處士羽青塘別業','皎然','唐','御定全唐诗','yuding','','[]','應難久辭秩，暫寄君陽隱。已見縣名花，會逢闈是粉。',60,'御定全唐詩/json/817.json','["應難久辭秩，暫寄君陽隱。已見縣名花，會逢闈是粉。", "本自尋人至，寧因看竹引。身關白雲多，門占春山盡。", "最賞無事心，籬邊釣溪近。"]'),
('yuding-14','夏日集李司直縱溪齋','皎然','唐','御定全唐诗','yuding','','[]','修景屬良會，遠飆生煩襟。泄雲收淨綠，眾木積芳陰。',72,'御定全唐詩/json/817.json','["修景屬良會，遠飆生煩襟。泄雲收淨綠，眾木積芳陰。", "疏滌府中務，迢遙湖上心。習閑得招我，賞夜宜泛琴。", "山近資性靜，月來寄情深。澹然若事外，豈藉隳華簪。"]'),
('yuding-15','夏日題桐廬楊明府納涼山齋','皎然','唐','御定全唐诗','yuding','','[]','陶家無炎暑，自有林中峰。席上落山影，桐梢回水容。',48,'御定全唐詩/json/817.json','["陶家無炎暑，自有林中峰。席上落山影，桐梢回水容。", "放懷涼風至，緩步清陰重。何事親堆案，猶多高世蹤。"]'),
('yuding-16','和楊明府早秋游法華寺','皎然','唐','御定全唐诗','yuding','','[]','釋事出縣合，初聞茲山靈。寺扉隱天色，影刹遙丁丁。',96,'御定全唐詩/json/817.json','["釋事出縣合，初聞茲山靈。寺扉隱天色，影刹遙丁丁。", "碧峰委合遝，香蔓垂蓂苓。清景為公有，放曠雲邊亭。", "秋賞石潭潔，夜嘉杉月清。誦空性不昧，助道跡又經。", "是以於物理，紛然若未形。移來字人要，全與此道冥。"]'),
('yuding-17','宿道士觀','皎然','唐','御定全唐诗','yuding','','[]','古觀秋木秀，冷然屬鮮飆。瓊葩被修蔓，柏實滿寒條。',60,'御定全唐詩/json/817.json','["古觀秋木秀，冷然屬鮮飆。瓊葩被修蔓，柏實滿寒條。", "影殿山寂寂，寥天月昭昭。幽期寄仙侶，習定至中宵。", "清佩聞虛步，真官方宿朝。"]'),
('yuding-18','冬日天井西峰張煉師所居','皎然','唐','御定全唐诗','yuding','','[]','采薪逢野泉，漸見棲閑所。坎坎山上聲，幽幽林中語。',72,'御定全唐詩/json/817.json','["采薪逢野泉，漸見棲閑所。坎坎山上聲，幽幽林中語。", "仙鄉何代隱，鄉服言亦楚。開水淨藥苗，掃雪候山侶。", "零葉聚敗籬，幽花積寒渚。冥冥孤鶴性，天外思輕舉。"]'),
('yuding-19','奉同顏使君真卿開元寺經藏院會觀樹文殊碑','皎然','唐','御定全唐诗','yuding','','[]','萬國布殊私，千年降祖師。雁門傳法至，龍藏立言時。',48,'御定全唐詩/json/817.json','["萬國布殊私，千年降祖師。雁門傳法至，龍藏立言時。", "故實刊周典，新聲播魯詩。六銖那更拂，劫石盡無期。"]'),
('yuding-20','奉同盧使君幼平遊精舍寺','皎然','唐','御定全唐诗','yuding','','[]','影刹西方在，虛空翠色分。人天霽後見，猿鳥定中聞。',48,'御定全唐詩/json/817.json','["影刹西方在，虛空翠色分。人天霽後見，猿鳥定中聞。", "真界隱青壁，春山淩白雲。今朝石門會，千古仰斯文。"]'),
('yuding-21','奉同顏使君真卿、袁侍禦駱駝橋玩月','皎然','唐','御定全唐诗','yuding','','[]','山中常見月，不及共游時。水上恐將缺，林端愛落遲。',48,'御定全唐詩/json/817.json','["山中常見月，不及共游時。水上恐將缺，林端愛落遲。", "烏驚憲府客，人詠鮑家詩。永夜南橋望，裴回若有期。"]'),
('yuding-22','和邢端公登臺春望句，句有春字之什','皎然','唐','御定全唐诗','yuding','','[]','春日繡衣輕，春台別有情。春煙間草色，春鳥隔花聲。',48,'御定全唐詩/json/817.json','["春日繡衣輕，春台別有情。春煙間草色，春鳥隔花聲。", "春樹亂無次，春山遙得名。春風正飄蕩，春甕莫須傾。"]'),
('yuding-23','經仙人渚即沈山下古人沈義白日升仙處','皎然','唐','御定全唐诗','yuding','','[]','日月人間短，何時此得仙。古山春已盡，遺渚事空傳。',48,'御定全唐詩/json/817.json','["日月人間短，何時此得仙。古山春已盡，遺渚事空傳。", "不見騰雲駕，徒臨洗藥泉。如今成逝水，翻使恨流年。"]'),
('yuding-24','獨遊二首','皎然','唐','御定全唐诗','yuding','','[]','性野趣無端，春晴路又幹。逢泉破石弄，放鶴向雲看。',96,'御定全唐詩/json/817.json','["性野趣無端，春晴路又幹。逢泉破石弄，放鶴向雲看。", "好僻誰相似，從狂我自安。芳洲亦有意，步上白沙灘。", "臨水興不盡，虛舟可同嬉。還雲與歸鳥，若共山僧期。", "世事吾不預，此心誰得知。西峰有禪老，應見獨游時。"]'),
('yuding-25','遊溪待月','皎然','唐','御定全唐诗','yuding','','[]','溪色思泛月，沿洄欲未歸。殘燈逢水店，疏磬憶山扉。',48,'御定全唐詩/json/817.json','["溪色思泛月，沿洄欲未歸。殘燈逢水店，疏磬憶山扉。", "夜浦魚驚少，空林鵲繞稀。可中才望見，撩亂搗寒衣。"]'),
('yuding-26','西溪獨泛','皎然','唐','御定全唐诗','yuding','','[]','道情何所寄，素舸漫流間。真性憐高鶴，無名羨野山。',48,'御定全唐詩/json/817.json','["道情何所寄，素舸漫流間。真性憐高鶴，無名羨野山。", "經寒叢竹秀，人靜片雲閑。泛泛誰為侶，唯應共月還。"]'),
('yuding-27','早秋陪韓明府泛阮元公溪','皎然','唐','御定全唐诗','yuding','','[]','雨信清殘暑，蕭條古縣西。早涼生浦漵，秋意滿高低。',48,'御定全唐詩/json/817.json','["雨信清殘暑，蕭條古縣西。早涼生浦漵，秋意滿高低。", "前事雖堆案，閒情得溯溪。何言戰未勝，空寂用還齊。"]'),
('yuding-28','九日陪顏使君真卿登水樓','皎然','唐','御定全唐诗','yuding','','[]','重陽荊楚尚，高會此難陪。偶見登龍客，同遊戲馬台。',48,'御定全唐詩/json/817.json','["重陽荊楚尚，高會此難陪。偶見登龍客，同遊戲馬台。", "風文向水疊，雲態擁歌回。持菊煩相問，捫襟愧不才。"]'),
('yuding-29','與盧孟明別後宿南湖對月','皎然','唐','御定全唐诗','yuding','','[]','五湖生夜月，千里滿寒流。曠望煙霞盡，淒涼天地秋。',48,'御定全唐詩/json/817.json','["五湖生夜月，千里滿寒流。曠望煙霞盡，淒涼天地秋。", "相思路渺渺，獨夢水悠悠。何處空江上，裴回送客舟。"]'),
('yuding-30','自義亭驛送李長史縱，夜泊臨平東湖','皎然','唐','御定全唐诗','yuding','','[]','長亭賓馭散，岐路起悲風。千里勤王事，驅車明月中。',48,'御定全唐詩/json/817.json','["長亭賓馭散，岐路起悲風。千里勤王事，驅車明月中。", "寒生洞庭水，夜度塞門鴻。處處堪傷別，歸來山又空。"]'),
('yuding-31','出遊','皎然','唐','御定全唐诗','yuding','','[]','少時不見山，便覺無奇趣。狂發從亂歌，情來任閒步。',36,'御定全唐詩/json/817.json','["少時不見山，便覺無奇趣。狂發從亂歌，情來任閒步。", "此心誰共證，笑看風吹樹。"]'),
('yuding-32','界石守風，望天竺、靈隱二寺','皎然','唐','御定全唐诗','yuding','','[]','山頂東西寺，江中旦暮潮。歸心不可到，松路在青霄。',24,'御定全唐詩/json/817.json','["山頂東西寺，江中旦暮潮。歸心不可到，松路在青霄。"]'),
('yuding-33','《奉和顏使君真卿修韻海》畢，州中重宴','皎然','唐','御定全唐诗','yuding','','[]','世學高南郡，身封盛魯邦。九流宗韻海，七字揖文江。',48,'御定全唐詩/json/817.json','["世學高南郡，身封盛魯邦。九流宗韻海，七字揖文江。", "借賞雲歸堞，留歡月在窗。不知名教樂，千載與誰雙。"]'),
('yuding-34','晦日陪顏使君白蘋洲集','皎然','唐','御定全唐诗','yuding','','[]','南朝分古郡，山水似湘東。堤月吳風在，湔裾楚客同。',48,'御定全唐詩/json/817.json','["南朝分古郡，山水似湘東。堤月吳風在，湔裾楚客同。", "桂寒初結旆，蘋小欲成叢。時晦佳游促，高歌聽未終。"]'),
('yuding-35','冬至日陪裴端公使君清水堂集','皎然','唐','御定全唐诗','yuding','','[]','亞歲崇佳宴，華軒照淥波。渚芳迎氣早，山翠向晴多。',48,'御定全唐詩/json/817.json','["亞歲崇佳宴，華軒照淥波。渚芳迎氣早，山翠向晴多。", "推往知時訓，書祥辨政和。從公惜日短，留賞夜如何。"]'),
('yuding-36','陪盧判官水堂夜宴','皎然','唐','御定全唐诗','yuding','','[]','暑氣當宵盡，裴回坐月前。靜依山堞近，涼入水扉偏。',48,'御定全唐詩/json/817.json','["暑氣當宵盡，裴回坐月前。靜依山堞近，涼入水扉偏。", "久是棲林客，初逢佐幕賢。愛君高野意，烹茗釣淪漣。"]'),
('yuding-37','新秋同盧侍禦、薛員外白蘋洲月夜','皎然','唐','御定全唐诗','yuding','','[]','隔暑蘋洲近，迎涼欲泛舟。榮從憲府至，喜會夕郎遊。',48,'御定全唐詩/json/817.json','["隔暑蘋洲近，迎涼欲泛舟。榮從憲府至，喜會夕郎遊。", "氣奪滄浪色，風欺汗漫流。誰言三伏夜，獨此月前秋。"]'),
('yuding-38','夏日集裴錄事北亭避暑','皎然','唐','御定全唐诗','yuding','','[]','前林夏雨歇，為我生涼風。一室煩暑外，眾山清景中。',48,'御定全唐詩/json/817.json','["前林夏雨歇，為我生涼風。一室煩暑外，眾山清景中。", "忘歸親野水，適性許雲鴻。蕭散都曹吏，還將靜者同。"]'),
('yuding-39','與王錄事會張征君姊妹煉師院玩雪兼懷清會上人','皎然','唐','御定全唐诗','yuding','','[]','何意廉從事，還來會默仙。寒空驚雪遍，春意入歌偏。',48,'御定全唐詩/json/817.json','["何意廉從事，還來會默仙。寒空驚雪遍，春意入歌偏。", "瑤草三花發，瓊林七葉連。飄颻過柳寺，應滿譯經前。"]'),
('yuding-40','和李侍禦萼歲初夜集處士書閣','皎然','唐','御定全唐诗','yuding','','[]','遲賢新置閣，高意此郊居。古徑行春早，新窗見月初。',48,'御定全唐詩/json/817.json','["遲賢新置閣，高意此郊居。古徑行春早，新窗見月初。", "放歌還倚瑟，講道亦觀書。為我留禪位，來逢此會疏。"]'),
('yuding-41','湯評事衡水亭會覺禪師','皎然','唐','御定全唐诗','yuding','','[]','山侶相逢少，清晨會水亭。雪晴松葉翠，煙暖藥苗青。',48,'御定全唐詩/json/817.json','["山侶相逢少，清晨會水亭。雪晴松葉翠，煙暖藥苗青。", "靜對滄洲鶴，閑看古寺經。應憐叩關子，了義共心冥。"]'),
('yuding-42','與朝陽山人張朝夜集湖亭，賦得各言其志','皎然','唐','御定全唐诗','yuding','','[]','洞庭孤月在，秋色望無邊。零露積衰草，寒螿鳴古田。',48,'御定全唐詩/json/817.json','["洞庭孤月在，秋色望無邊。零露積衰草，寒螿鳴古田。", "茫茫區中想，寂寂塵外緣。從此悟浮世，胡為傷暮年。"]'),
('yuding-43','晦夜李侍禦萼宅集招潘述、湯衡、海上人飲茶賦','皎然','唐','御定全唐诗','yuding','','[]','晦夜不生月，琴軒猶為開。牆東隱者在，淇上逸僧來。',48,'御定全唐詩/json/817.json','["晦夜不生月，琴軒猶為開。牆東隱者在，淇上逸僧來。", "茗愛傳花飲，詩看卷素裁。風流高此會，曉景屢裴回。"]'),
('yuding-44','寄昱上人上方居','皎然','唐','御定全唐诗','yuding','','[]','厭向人間住，逢山欲懶歸。片雲閑似我，日日在禪扉。',48,'御定全唐詩/json/817.json','["厭向人間住，逢山欲懶歸。片雲閑似我，日日在禪扉。", "地靜松陰遍，門空鳥語稀。夜涼疏磬盡，師友自相依。"]'),
('yuding-45','夏日與綦毋居士、昱上人納涼','皎然','唐','御定全唐诗','yuding','','[]','為依爐峰住，境勝增道情。涼日暑不變，空門風自清。',48,'御定全唐詩/json/817.json','["為依爐峰住，境勝增道情。涼日暑不變，空門風自清。", "坐援香實近，轉愛綠蕪生。宗炳青霞士，如何知我名。"]'),
('yuding-46','建元寺集皇甫侍禦書閣','皎然','唐','御定全唐诗','yuding','','[]','不因居佛裏，無事得相逢。名重朝端望，身高俗外蹤。',48,'御定全唐詩/json/817.json','["不因居佛裏，無事得相逢。名重朝端望，身高俗外蹤。", "機閑看淨水，境寂聽疏鐘。宣室恩長在，知君志未從。"]'),
('yuding-47','郭北尋徐主簿別業','皎然','唐','御定全唐诗','yuding','','[]','近依城北住，幽遠少人知。積雪行深巷，閑雲繞古籬。',48,'御定全唐詩/json/817.json','["近依城北住，幽遠少人知。積雪行深巷，閑雲繞古籬。", "竹花冬更發，橙實晚仍垂。還共岩中鶴，今朝下淥池。"]'),
('yuding-48','題報德寺清幽上人西峰','皎然','唐','御定全唐诗','yuding','','[]','陳世凋亡後，仁祠識舊山。帝鄉喬木在，空見白雲還。',48,'御定全唐詩/json/817.json','["陳世凋亡後，仁祠識舊山。帝鄉喬木在，空見白雲還。", "雙塔寒林外，三陵暮雨間。此中難戰勝，君獨啟禪關。"]'),
('yuding-49','題鄭谷江畔桐齋','皎然','唐','御定全唐诗','yuding','','[]','客齋開別住，坐占綠江濆。流水非外物，閑雲長屬君。',48,'御定全唐詩/json/817.json','["客齋開別住，坐占綠江濆。流水非外物，閑雲長屬君。", "浮榮未可累，曠達若為群。風起高梧下，清弦日日聞。"]'),
('yuding-50','和閻士和李蕙冬夜重集','皎然','唐','御定全唐诗','yuding','','[]','郡理日閑曠，洗心宿香峰。雙林秋見月，萬壑靜聞鐘。',48,'御定全唐詩/json/817.json','["郡理日閑曠，洗心宿香峰。雙林秋見月，萬壑靜聞鐘。", "佩玉行山翠，交麾動水容。如何股肱守，塵外得相從。"]'),
('yuding-51','《春日陪顏使君真卿、皇甫曾西亭重會韻海》諸生','皎然','唐','御定全唐诗','yuding','','[]','為重南台客，朝朝會魯儒。暄風眾木變，清景片雲無。',48,'御定全唐詩/json/817.json','["為重南台客，朝朝會魯儒。暄風眾木變，清景片雲無。", "峰翠飄簷下，溪光照座隅。不將簪艾隔，知與道情俱。"]'),
('yuding-52','寒食日同陸處士行報德寺，宿解公房','皎然','唐','御定全唐诗','yuding','','[]','古寺章陵下，潛公住幾年。安心生軟草，灌頂引春泉。',48,'御定全唐詩/json/817.json','["古寺章陵下，潛公住幾年。安心生軟草，灌頂引春泉。", "寂寂傳燈地，寥寥禁火天。世間多暗室，白日為誰懸。"]'),
('yuding-53','兵馬曹季良宅夜集','皎然','唐','御定全唐诗','yuding','','[]','清景不可失，尋君趣有餘。身高避事後，道長問心初。',72,'御定全唐詩/json/817.json','["清景不可失，尋君趣有餘。身高避事後，道長問心初。", "出處名則異，游從跡何疏。吟看刻盡燭，笑卷讀殘書。", "露彩生筆硯，風音入庭除。平明仙侶散，觳觫動回車。"]'),
('yuding-54','同李侍禦萼、李判官集陸處士羽新宅','皎然','唐','御定全唐诗','yuding','','[]','素風千戶敵，新語陸生能。借宅心常遠，移籬力更弘。',72,'御定全唐詩/json/817.json','["素風千戶敵，新語陸生能。借宅心常遠，移籬力更弘。", "釣絲初種竹，衣帶近裁藤。戎佐推兄弟，詩流得友朋。", "柳陰容過客，花徑許招僧。不為牆東隱，人家到未曾。"]'),
('yuding-55','題報恩寺惟照上人房','皎然','唐','御定全唐诗','yuding','','[]','上界雨色幹，涼宮日遲遲。水文披菡萏，山翠動罘罳。',60,'御定全唐詩/json/817.json','["上界雨色幹，涼宮日遲遲。水文披菡萏，山翠動罘罳。", "中有清真子，愔愔步閑墀。手縈頗黎縷，願證黃金姿。", "旋草階下生，看心當此時。"]'),
('yuding-56','尋天目徐君','皎然','唐','御定全唐诗','yuding','','[]','常見仙翁變姓名，豈知松子號初平。逢人不道往來處，',40,'御定全唐詩/json/817.json','["常見仙翁變姓名，豈知松子號初平。逢人不道往來處，", "三花落地君猶在，笑撫安期昨日生。"]'),
('yuding-57','同李著作縱題塵外上人院','皎然','唐','御定全唐诗','yuding','','[]','百緣唯有什公瓶，萬法但看一字經。從遣鳥喧心不動，',40,'御定全唐詩/json/817.json','["百緣唯有什公瓶，萬法但看一字經。從遣鳥喧心不動，", "禪伴欲邀何著作，空音宜向夜中聽。"]'),
('yuding-58','題周諫別業','皎然','唐','御定全唐诗','yuding','','[]','隱身苕上欲如何，不著青袍愛綠蘿。柳巷任疏容馬入，',40,'御定全唐詩/json/817.json','["隱身苕上欲如何，不著青袍愛綠蘿。柳巷任疏容馬入，", "若訪禪齋遙可見，竹窗書幌共煙波。"]'),
('yuding-59','同李中丞洪水亭夜集','皎然','唐','御定全唐诗','yuding','','[]','佳人但莫吹參差，正憐月色生酒卮。',32,'御定全唐詩/json/817.json','["佳人但莫吹參差，正憐月色生酒卮。", "山公取醉不關我，為愛尊前白鷺鶿。"]'),
('yuding-60','題秦系山人麗句亭','皎然','唐','御定全唐诗','yuding','','[]','獨將詩教領諸生，但看青山不愛名。',32,'御定全唐詩/json/817.json','["獨將詩教領諸生，但看青山不愛名。", "滿院竹聲堪愈疾，亂床花片足忘情。"]'),
('yuding-61','春夜集陸處士居玩月','皎然','唐','御定全唐诗','yuding','','[]','欲賞芳菲肯待辰，忘情人訪有情人。',32,'御定全唐詩/json/817.json','["欲賞芳菲肯待辰，忘情人訪有情人。", "西林可是無清景，只為忘情不記春。"]'),
('yuding-62','寄題雲門寺梵月無側房','皎然','唐','御定全唐诗','yuding','','[]','越山千萬雲門絕，西僧貌古還名月。',32,'御定全唐詩/json/817.json','["越山千萬雲門絕，西僧貌古還名月。", "清朝掃石行道歸，林下眠禪看松雪。"]'),
('yuding-63','法華寺上方題江上人禪空','皎然','唐','御定全唐诗','yuding','','[]','路入松聲遠更奇，山光水色共參差。',32,'御定全唐詩/json/817.json','["路入松聲遠更奇，山光水色共參差。", "中峰禪寂一僧在，坐對梁朝老桂枝。"]'),
('yuding-64','冬日山行過薛征君','皎然','唐','御定全唐诗','yuding','','[]','我行倦修阪，四顧無平陸。雨霽鳴鷹鸇，天寒聚麋鹿。',72,'御定全唐詩/json/817.json','["我行倦修阪，四顧無平陸。雨霽鳴鷹鸇，天寒聚麋鹿。", "幽人訪名士，家在南岡曲。菜實縈小園，稻花繞山屋。", "深居寡憂悔，勝境怡耳目。征心尚與我，永言謝浮俗。"]'),
('yuding-65','往丹陽尋陸處士不遇','皎然','唐','御定全唐诗','yuding','','[]','遠客殊未歸，我來幾惆悵。叩關一日不見人，',60,'御定全唐詩/json/817.json','["遠客殊未歸，我來幾惆悵。叩關一日不見人，", "行人無數不相識，獨立雲陽古驛邊。鳳翅山中思本寺，", "他日相期那可定，閑僧著處即經年。"]'),
('yuding-66','集湯評事衡湖上望微雨','皎然','唐','御定全唐诗','yuding','','[]','蒼涼遠景中，雨色緣山有。雲送滿洞庭，風吹繞楊柳。',36,'御定全唐詩/json/817.json','["蒼涼遠景中，雨色緣山有。雲送滿洞庭，風吹繞楊柳。", "蕭蕭解輕袂，盡日隨林叟。"]'),
('yuding-67','九日與陸處士羽飲茶','皎然','唐','御定全唐诗','yuding','','[]','九日山僧院，東籬菊也黃。俗人多泛酒，誰解助茶香。',24,'御定全唐詩/json/817.json','["九日山僧院，東籬菊也黃。俗人多泛酒，誰解助茶香。"]'),
('yuding-68','夜過康錄事造會兄弟','皎然','唐','御定全唐诗','yuding','','[]','愛君門館夜來清，瓊樹雙枝是弟兄。',32,'御定全唐詩/json/817.json','["愛君門館夜來清，瓊樹雙枝是弟兄。", "月在詩家偏足思，風過客位更多情。"]'),
('yuding-69','題沈少府書齋','皎然','唐','御定全唐诗','yuding','','[]','不下南昌縣，書齋每日閑。野花當砌落，溪鳥逐人還。',48,'御定全唐詩/json/817.json','["不下南昌縣，書齋每日閑。野花當砌落，溪鳥逐人還。", "有興常臨水，無時不見山。千峰數可盡，不出小窗間。"]'),
('yuding-70','春夜與諸公同宴呈陸郎中','皎然','唐','御定全唐诗','yuding','','[]','南國宴佳賓，交情老倍親。月慚紅淚燭，花笑白頭人。',48,'御定全唐詩/json/817.json','["南國宴佳賓，交情老倍親。月慚紅淚燭，花笑白頭人。", "寶瑟縆餘怨，瓊枝不讓春。更聞歌子夜，桃李豔妝新。"]'),
('yuding-71','九日阻雨簡高侍禦','皎然','唐','御定全唐诗','yuding','','[]','江上重雲起，何曾裛□塵。不能成落帽，翻欲更摧巾。',48,'御定全唐詩/json/817.json','["江上重雲起，何曾裛□塵。不能成落帽，翻欲更摧巾。", "素發閑依枕，黃花暗待人。且應攜下價，芒屨就諸鄰。"]'),
('yuding-72','晚春尋桃源觀','皎然','唐','御定全唐诗','yuding','','[]','武陵何處訪仙鄉，古觀雲根路已荒。細草擁壇人跡絕，',40,'御定全唐詩/json/817.json','["武陵何處訪仙鄉，古觀雲根路已荒。細草擁壇人跡絕，", "全覺此身離俗境，玄機亦可照迷方。"]'),
('yuding-73','同盧使君幼平郊外送閻侍禦歸台','皎然','唐','御定全唐诗','yuding','','[]','留餞飛旌駐，離亭草色間。柏台今上客，竹使舊朝班。',72,'御定全唐詩/json/817.json','["留餞飛旌駐，離亭草色間。柏台今上客，竹使舊朝班。", "日落東西水，天寒遠近山。古江分楚望，殘柳入隋關。", "戀闕心常積，回軒日不閑。芳辰倚門道，猶得及春還。"]'),
('yuding-0','送梁拾遺肅歸朝','皎然','唐','御定全唐诗','yuding','','[]','明主重文諫，才臣出江東。束書辭東山，改服臨北風。',84,'御定全唐詩/json/818.json','["明主重文諫，才臣出江東。束書辭東山，改服臨北風。", "萬里望皇邑，九重當曙空。天開芙蓉闕，日上蒲桃宮。", "天子初未起，金閨籍先通。身逢軒轅世，名貴鴛鸞中。", "故人榮此別，何用悲絲桐。"]'),
('yuding-1','奉陪楊使君頊送段校書赴南海幕','皎然','唐','御定全唐诗','yuding','','[]','碩賢靜廣州，信為天下貞。屈茲大將佐，藉彼延閣英。',96,'御定全唐詩/json/818.json','["碩賢靜廣州，信為天下貞。屈茲大將佐，藉彼延閣英。", "聲動柳吳興，郊餞意不輕。吾知段夫子，高論關蒼生。", "處以德為藩，出則道可行。遙知南樓會，新景當詩情。", "天高林瘴洗，秋遠海色清。時泰罷飛檄，唯應頌公成。"]'),
('yuding-2','送陸侍禦士佳赴上京','皎然','唐','御定全唐诗','yuding','','[]','長安三千里，喜行不言永。清路黃塵飛，大河滄流靜。',72,'御定全唐詩/json/818.json','["長安三千里，喜行不言永。清路黃塵飛，大河滄流靜。", "更懷西川府，主公昔和鼎。伊鬱瑤瑟情，威遲花驄影。", "此時已難別，日又無停景。出餞闕相從，心隨過前嶺。"]'),
('yuding-3','奉陪顏使君真卿登峴山，送張侍禦嚴歸台','皎然','唐','御定全唐诗','yuding','','[]','峴首千里情，北轅自茲發。煙霞正登覽，簪筆限趨謁。',72,'御定全唐詩/json/818.json','["峴首千里情，北轅自茲發。煙霞正登覽，簪筆限趨謁。", "黃鶴望天衢，白雲歸帝闕。客心南浦柳，離思西樓月。", "留賞景不延，感時芳易歇。他晨有山信，一為訪林樾。"]'),
('yuding-4','酬元主簿子球別贈','皎然','唐','御定全唐诗','yuding','','[]','故人方遠適，訪我陳別情。此夜偶禪室，一言了無生。',132,'御定全唐詩/json/818.json','["故人方遠適，訪我陳別情。此夜偶禪室，一言了無生。", "覽君緘中寶，如搴清玉瑛。胡為蘊高價，歲晚徒營營。", "辭秩貧且病，何人見艱貞。出無黃金橐，空歌白苧行。", "威遲策駑馬，獨望故關樹。渺渺千里心，春風起中路。", "近聞新拜命，鸞鳳猶棲棘。勸君寄一枝，且養冥冥翼。", "甘泉多竹花，明年待君食。"]'),
('yuding-5','答道素上人別','皎然','唐','御定全唐诗','yuding','','[]','春色遍遠道，寂寞閩中行。碧水何渺渺，白雲亦英英。',168,'御定全唐詩/json/818.json','["春色遍遠道，寂寞閩中行。碧水何渺渺，白雲亦英英。", "離人不可望，日暮芳洲情。黃鶴有逸翮，翹首白雲傾。", "欲為山中侶，肯秘遼天聲。藍縷真子褐，葳蕤近臣纓。", "以茲奪爾懷，常恐道不成。吾門弟子中，不減惠休名。", "一性研已遠，五言功更精。從君汗漫遊，莫廢學無生。", "忍草肯搖落，禪枝不枯榮。采采慰長路，知吾心不輕。", "幻情有去住，真性無離別。留取老桂枝，歸來共攀折。"]'),
('yuding-6','霅溪館送韓明府章辭滿歸','皎然','唐','御定全唐诗','yuding','','[]','洛令從告還，故人東門餞。惠愛三年積，軒車一夜遠。',60,'御定全唐詩/json/818.json','["洛令從告還，故人東門餞。惠愛三年積，軒車一夜遠。", "曉月離館空，秋風故山晚。榮君有嘉薦，顧我阻遊衍。", "宿昔峰頂心，依依不可卷。"]'),
('yuding-7','送穆寂赴舉','皎然','唐','御定全唐诗','yuding','','[]','天子錫玄纁，傾山禮隱淪。君拋青霞去，榮資觀國賓。',96,'御定全唐詩/json/818.json','["天子錫玄纁，傾山禮隱淪。君拋青霞去，榮資觀國賓。", "劍光既陸離，瓊彩何璘玢。夙駕別情遠，商弦秋意新。", "冥冥鴻鵠姿，數尺看蒼旻。殘寇近宋郊，西行惡飆塵。", "立身素耿介，處難思經綸。春府搜才日，高科得一人。"]'),
('yuding-8','送張彝歸長沙','皎然','唐','御定全唐诗','yuding','','[]','早聞淩雲彩，謂在鴛鷺儔。華髮始相遇，滄江仍旅遊。',96,'御定全唐詩/json/818.json','["早聞淩雲彩，謂在鴛鷺儔。華髮始相遇，滄江仍旅遊。", "策名忘苟進，澹慮輕所求。常服遠遊誡，緬懷經世謀。", "片帆背風渚，萬里還湘洲。別望荊雲積，歸心漢水流。", "蘭苕行采采，桂棹思悠悠。宿昔無機者，為君動離憂。"]'),
('yuding-9','秋日毗陵南寺送潘述之揚州','皎然','唐','御定全唐诗','yuding','','[]','孤客秋易傷，嘶蟬靜仍續。佳晨亦已屢，歡會常不足。',84,'御定全唐詩/json/818.json','["孤客秋易傷，嘶蟬靜仍續。佳晨亦已屢，歡會常不足。", "禪地非路岐，我心豈羈束。情生遠別時，坐恨清景促。", "望中千里隔，暮歸西山曲。蕭條月中道，彩蒨原上綠。", "不見同心人，幽懷增躑躅。"]'),
('yuding-10','春日又送潘述之揚州','皎然','唐','御定全唐诗','yuding','','[]','別渚望邗城，岐路春日遍。柔風吹楊柳，芳景流郊甸。',72,'御定全唐詩/json/818.json','["別渚望邗城，岐路春日遍。柔風吹楊柳，芳景流郊甸。", "日日東林期，今夕異鄉縣。文房曠佳士，禪室阻清盼。", "離恨奪賞心，不得諧所願。莫憶山中人，碧雲遙可見。"]'),
('yuding-11','新秋送盧判官','皎然','唐','御定全唐诗','yuding','','[]','故人念宿昔，欲別增遠情。入座炎氣屏，為君秋景清。',48,'御定全唐詩/json/818.json','["故人念宿昔，欲別增遠情。入座炎氣屏，為君秋景清。", "由來空山客，不怨離弦聲。唯有暮蟬起，相思碧雲生。"]'),
('yuding-12','奉送袁高使君詔征赴行在，效曹劉體','皎然','唐','御定全唐诗','yuding','','[]','皇心亭毒廣，蝥賊皆陶甄。未刈蚩尤旗，方同軒後年。',120,'御定全唐詩/json/818.json','["皇心亭毒廣，蝥賊皆陶甄。未刈蚩尤旗，方同軒後年。", "天子幸漢中，轘轅阻氛煙。璽書召幕牧，名在列嶽仙。", "國難倚長城，廟謀資大賢。清損休汝騎，仁留述職篇。", "遐路渺天末，繁笳思河邊。飾徒促遠期，祗命赴急宣。", "謏才豈足稱，深仁顧何偏。那堪臨流意，千里望旗旃。"]'),
('yuding-13','奉送陸中丞長源詔征入朝','皎然','唐','御定全唐诗','yuding','','[]','詔下酂侯幕，征賢寵上勳。才當持漢典，道可致堯君。',72,'御定全唐詩/json/818.json','["詔下酂侯幕，征賢寵上勳。才當持漢典，道可致堯君。", "藩牧今榮餞，詩流此盛文。水從吳渚別，樹向楚門分。", "宿寺期嘉月，看山識故雲。歸心複何奈，怊悵在江濆。"]'),
('yuding-14','奉送李中丞道昌入朝','皎然','唐','御定全唐诗','yuding','','[]','文憲中司盛，恩榮外鎮崇。諸侯皆取則，八使獨推功。',72,'御定全唐詩/json/818.json','["文憲中司盛，恩榮外鎮崇。諸侯皆取則，八使獨推功。", "詔喜新銜鳳，車看舊飾熊。去思今武子，餘教昔文翁。", "清在如江水，仁留是國風。光征二千石，掃第望司空。"]'),
('yuding-15','冬日送顏延之明府撫州覲叔父','皎然','唐','御定全唐诗','yuding','','[]','臨川千里別，惆悵上津橋。日暮人歸盡，山空雪未消。',72,'御定全唐詩/json/818.json','["臨川千里別，惆悵上津橋。日暮人歸盡，山空雪未消。", "鄉雲心渺渺，楚水路遙遙。林下方歡會，山中獨寂寥。", "天寒驚斷雁，江信望回潮。歲晚流芳歇，思君在此宵。"]'),
('yuding-16','送關小師還金陵','皎然','唐','御定全唐诗','yuding','','[]','如何有歸思，愛別欲忘難。白鷺沙洲晚，青龍水寺寒。',48,'御定全唐詩/json/818.json','["如何有歸思，愛別欲忘難。白鷺沙洲晚，青龍水寺寒。", "蕉花鋪淨地，桂子落空壇。持此心為境，應堪月夜看。"]'),
('yuding-17','峴山送裴秀才赴舉','皎然','唐','御定全唐诗','yuding','','[]','漢家招秀士，峴上送君行。萬里見秋色，兩河傷遠情。',48,'御定全唐詩/json/818.json','["漢家招秀士，峴上送君行。萬里見秋色，兩河傷遠情。", "王師出西鎬，虜寇避東平。天府登名後，回看楚水清。"]'),
('yuding-18','酬別襄陽詩僧少微','皎然','唐','御定全唐诗','yuding','','[]','證心何有夢，示說夢歸頻。文字齎秦本，詩騷學楚人。',48,'御定全唐詩/json/818.json','["證心何有夢，示說夢歸頻。文字齎秦本，詩騷學楚人。", "蘭開衣上色，柳向手中春。別後須相見，浮雲是我身。"]'),
('yuding-19','送契上人遊揚州','皎然','唐','御定全唐诗','yuding','','[]','西陵古江口，遠見東揚州。淥水不同泛，春山應獨遊。',48,'御定全唐詩/json/818.json','["西陵古江口，遠見東揚州。淥水不同泛，春山應獨遊。", "尋僧白岩寺，望月謝家樓。宿昔心期在，人寰非久留。"]'),
('yuding-20','送德清衛明府赴選','皎然','唐','御定全唐诗','yuding','','[]','八使慎求能，東人獨薦君。身猶千里限，名已九霄聞。',48,'御定全唐詩/json/818.json','["八使慎求能，東人獨薦君。身猶千里限，名已九霄聞。", "遠路翻喜別，離言暫惜分。鳳門多士會，擁佩入卿雲。"]'),
('yuding-21','送鄭孝廉淮西覲省','皎然','唐','御定全唐诗','yuding','','[]','離袂翠華滿，晨羞欲早行。春風生楚樹，曉角發隋城。',48,'御定全唐詩/json/818.json','["離袂翠華滿，晨羞欲早行。春風生楚樹，曉角發隋城。", "野靄濕衣彩，江鴻增客情。征途不用戒，坐見白波清。"]'),
('yuding-22','送沈秀才之閩中','皎然','唐','御定全唐诗','yuding','','[]','越客不成歌，春風起淥波。嶺重寒不到，海近瘴偏多。',48,'御定全唐詩/json/818.json','["越客不成歌，春風起淥波。嶺重寒不到，海近瘴偏多。", "野戍桄榔發，人家翡翠過。翻疑此中好，君問定如何。"]'),
('yuding-23','送清會上人遊京','皎然','唐','御定全唐诗','yuding','','[]','佳遊限衰疾，一笑向西風。思見青門外，曾臨素滻東。',48,'御定全唐詩/json/818.json','["佳遊限衰疾，一笑向西風。思見青門外，曾臨素滻東。", "峰明雲際寺，日出露寒宮。行道禪長在，香塵不染空。"]'),
('yuding-24','送沈居士還太原','皎然','唐','御定全唐诗','yuding','','[]','辭官因世難，家族盛南朝。名重郊居賦，才高獨酌謠。',48,'御定全唐詩/json/818.json','["辭官因世難，家族盛南朝。名重郊居賦，才高獨酌謠。", "浪花飄一葉，峰色向三條。高逸雖成性，弓旌肯忘招。"]'),
('yuding-25','同顏使君真卿峴山送李法曹陽冰西上獻書時會有詔征赴京','皎然','唐','御定全唐诗','yuding','','[]','漢日中郎妙，周王太史才。雲書捧日去，鶴版下天來。',48,'御定全唐詩/json/818.json','["漢日中郎妙，周王太史才。雲書捧日去，鶴版下天來。", "草見吳洲發，花思御苑開。羊公惜風景，欲別幾遲回。"]'),
('yuding-26','兵後送姚太祝赴選','皎然','唐','御定全唐诗','yuding','','[]','兩河兵已偃，處處見歸舟。日夜故人散，江皋芳樹秋。',48,'御定全唐詩/json/818.json','["兩河兵已偃，處處見歸舟。日夜故人散，江皋芳樹秋。", "楚雲傷遠思，秦月憶佳遊。名動春官籍，翩翩才少儔。"]'),
('yuding-27','兵後送薛居士移家安吉','皎然','唐','御定全唐诗','yuding','','[]','舊遊經喪亂，道在複何人。寒草心易折，閑雲性常真。',48,'御定全唐詩/json/818.json','["舊遊經喪亂，道在複何人。寒草心易折，閑雲性常真。", "交情別後見，詩句比來新。向我桃州住，惜君東嶺春。"]'),
('yuding-28','送鄔傪之洪州覲兄弟','皎然','唐','御定全唐诗','yuding','','[]','年少足詩情，西江楚月清。書囊山翠濕，琴匣雪花輕。',48,'御定全唐詩/json/818.json','["年少足詩情，西江楚月清。書囊山翠濕，琴匣雪花輕。", "久別經離亂，新正憶弟兄。贈君題樂府，為是豫章行。"]'),
('yuding-29','送幹封李成','皎然','唐','御定全唐诗','yuding','','[]','羽檄飛未息，離情遠近同。感君由泛瑟，關我是征鴻。',48,'御定全唐詩/json/818.json','["羽檄飛未息，離情遠近同。感君由泛瑟，關我是征鴻。", "眇默歸人盡，疏蕪夜渡空。還期當歲晚，獨在路行中。"]'),
('yuding-30','送崔判官還揚子','皎然','唐','御定全唐诗','yuding','','[]','輕傳祗遠役，依依下姑亭。秋聲滿楊柳，暮色繞郊坰。',36,'御定全唐詩/json/818.json','["輕傳祗遠役，依依下姑亭。秋聲滿楊柳，暮色繞郊坰。", "煙水搖歸思，山當楚驛青。"]'),
('yuding-31','奉酬袁使君西樓餞秦山人與晝同赴李侍禦招三韻','皎然','唐','御定全唐诗','yuding','','[]','秋風怨別情，江守上西城。竹署寒流淺，琴窗宿雨晴。',36,'御定全唐詩/json/818.json','["秋風怨別情，江守上西城。竹署寒流淺，琴窗宿雨晴。", "治書招遠意，知共楚狂行。"]'),
('yuding-32','送清涼上人','皎然','唐','御定全唐诗','yuding','','[]','何意欲歸山，道高由境勝。花空覺性了，月盡知心證。',36,'御定全唐詩/json/818.json','["何意欲歸山，道高由境勝。花空覺性了，月盡知心證。", "永夜出禪吟，清猿自相應。"]'),
('yuding-33','送李丞使宣州','皎然','唐','御定全唐诗','yuding','','[]','結駟何翩翩，落葉暗寒渚。夢裏春穀泉，愁中洞庭雨。',36,'御定全唐詩/json/818.json','["結駟何翩翩，落葉暗寒渚。夢裏春穀泉，愁中洞庭雨。", "聊持剡山茗，以代宜城醑。"]'),
('yuding-34','送至洪沙彌遊越','皎然','唐','御定全唐诗','yuding','','[]','知爾學無生，不應傷此別。相逢宿我寺，獨往遊靈越。',36,'御定全唐詩/json/818.json','["知爾學無生，不應傷此別。相逢宿我寺，獨往遊靈越。", "早晚花會中，經行剡山月。"]'),
('yuding-35','送皇甫侍禦曾還丹陽別業','皎然','唐','御定全唐诗','yuding','','[]','雲陽別夜憶春耕，花發菱湖問去程。積水悠揚何處夢，',40,'御定全唐詩/json/818.json','["雲陽別夜憶春耕，花發菱湖問去程。積水悠揚何處夢，", "朝右要君持漢典，明年北墅可須營。"]'),
('yuding-36','白蘋洲送洛陽李丞使還','皎然','唐','御定全唐诗','yuding','','[]','蘋洲北望楚山重，千里回軺止一封。臨水情來還共載，',40,'御定全唐詩/json/818.json','["蘋洲北望楚山重，千里回軺止一封。臨水情來還共載，", "後會那應似疇昔，年年覺老雪山容。"]'),
('yuding-37','送履霜上人還金陵西山','皎然','唐','御定全唐诗','yuding','','[]','攜錫西山步綠莎，禪心未了奈情何。',32,'御定全唐詩/json/818.json','["攜錫西山步綠莎，禪心未了奈情何。", "湘宮水寺清秋夜，月落風悲松柏多。"]'),
('yuding-38','送辨聰上人還廣陵','皎然','唐','御定全唐诗','yuding','','[]','莫學休公學遠公，了心須與我心同。',32,'御定全唐詩/json/818.json','["莫學休公學遠公，了心須與我心同。", "隋家古柳數株在，看取人間萬事空。"]'),
('yuding-39','送清勵上人游福建','皎然','唐','御定全唐诗','yuding','','[]','禪子自矜禪性成，將來擬照建溪清。',32,'御定全唐詩/json/818.json','["禪子自矜禪性成，將來擬照建溪清。", "南看閩樹花不落，更取何緣了妄情。"]'),
('yuding-40','送顧道士游洞庭山','皎然','唐','御定全唐诗','yuding','','[]','見說洞庭無上路，春遊亂踏五靈芝。',32,'御定全唐詩/json/818.json','["見說洞庭無上路，春遊亂踏五靈芝。", "含桃風起花狼藉，正是仙翁棋散時。"]'),
('yuding-41','送邢臺州濟','皎然','唐','御定全唐诗','yuding','','[]','海上仙山屬使君，石橋琪樹古來聞。',32,'御定全唐詩/json/818.json','["海上仙山屬使君，石橋琪樹古來聞。", "他時畫出白團扇，乞取天臺一片雲。"]'),
('yuding-42','送柳察諫議叔','皎然','唐','御定全唐诗','yuding','','[]','東城南陌強經過，怨別無心亦放歌。',32,'御定全唐詩/json/818.json','["東城南陌強經過，怨別無心亦放歌。", "明日院公應問我，閑雲長在石門多。"]'),
('yuding-43','送柳淡扶侍赴洪州','皎然','唐','御定全唐诗','yuding','','[]','中林許師友，忽阻夙心期。自顧青緺好，來將黃鶴辭。',72,'御定全唐詩/json/818.json','["中林許師友，忽阻夙心期。自顧青緺好，來將黃鶴辭。", "少年輕遠涉，世道得無欺。煙雨孤舟上，晨昏千里時。", "離魂渺天末，相望在江湄。無限江南柳，春風卷亂絲。"]'),
('yuding-44','同李司直題武丘寺兼留諸公與陸羽之無錫','皎然','唐','御定全唐诗','yuding','','[]','陵寢成香阜，禪枝出白楊。劍池留故事，月樹即他方。',48,'御定全唐詩/json/818.json','["陵寢成香阜，禪枝出白楊。劍池留故事，月樹即他方。", "應世緣須別，棲心趣不忘。還將陸居士，晨發泛歸航。"]'),
('yuding-45','夏日題鄭谷江上納涼館','皎然','唐','御定全唐诗','yuding','','[]','迢遙山意外，清風又對君。若為於此地，翻作路岐分。',48,'御定全唐詩/json/818.json','["迢遙山意外，清風又對君。若為於此地，翻作路岐分。", "別館琴徒語，前洲鶴自群。明朝天畔遠，何處逐閑雲。"]'),
('yuding-46','太湖館送殷秀才赴舉','皎然','唐','御定全唐诗','yuding','','[]','春風洞庭路，搖盪暮天多。衰疾見芳草，別離傷遠波。',48,'御定全唐詩/json/818.json','["春風洞庭路，搖盪暮天多。衰疾見芳草，別離傷遠波。", "詩名推首薦，賦甲擬前科。數日聞天府，山衣制芰荷。"]'),
('yuding-47','送重鈞上人遊天臺','皎然','唐','御定全唐诗','yuding','','[]','漸看華頂出，幽賞意隨生。十裏行松色，千重過水聲。',48,'御定全唐詩/json/818.json','["漸看華頂出，幽賞意隨生。十裏行松色，千重過水聲。", "海容雲正盡，山色雨初晴。事事將心證，知君道可成。"]'),
('yuding-48','早春送顏主簿遊越東，兼謁元中丞','皎然','唐','御定全唐诗','yuding','','[]','輕舸趣不已，東風吹綠蘋。欲看梅市雪，知賞柳家春。',48,'御定全唐詩/json/818.json','["輕舸趣不已，東風吹綠蘋。欲看梅市雪，知賞柳家春。", "別意傾吳醑，芳聲動越人。山陰三月會，內史得嘉賓。"]'),
('yuding-49','同顏使君清明日遊，因送蕭主簿','皎然','唐','御定全唐诗','yuding','','[]','誰知賞嘉節，別意忽相和。暮色汀洲遍，春情楊柳多。',48,'御定全唐詩/json/818.json','["誰知賞嘉節，別意忽相和。暮色汀洲遍，春情楊柳多。", "高城戀旌旆，極浦宿風波。惆悵支山月，今宵不再過。"]'),
('yuding-50','送道琚上人還金陵','皎然','唐','御定全唐诗','yuding','','[]','一與鐘山別，山中得信稀。經年求法後，及夏問安歸。',48,'御定全唐詩/json/818.json','["一與鐘山別，山中得信稀。經年求法後，及夏問安歸。", "野實充甘膳，池花當彩衣。慈親莫返拜，外禮欲無為。"]'),
('yuding-51','送裴邕之上京','皎然','唐','御定全唐诗','yuding','','[]','辭山偶世清，挾策忽西行。帆過隨江疾，衣沾楚雪輕。',48,'御定全唐詩/json/818.json','["辭山偶世清，挾策忽西行。帆過隨江疾，衣沾楚雪輕。", "尚文須獻賦，重道莫論兵。東觀今多事，應高白馬生。"]'),
('yuding-52','送珍上人還天竺，兼寄廣通上人、秦山人','皎然','唐','御定全唐诗','yuding','','[]','江寺名天竺，多居躡遠蹤。春帆依柳浦，輕履上蓮峰。',48,'御定全唐詩/json/818.json','["江寺名天竺，多居躡遠蹤。春帆依柳浦，輕履上蓮峰。", "禪子兼三隱，空書共一封。因君達山信，應向白雲逢。"]'),
('yuding-53','送張孝廉赴舉','皎然','唐','御定全唐诗','yuding','','[]','名在諸生右，家經見素風。春田休學稼，秋賦出儒宮。',48,'御定全唐詩/json/818.json','["名在諸生右，家經見素風。春田休學稼，秋賦出儒宮。", "別路殘雲濕，離情晚桂叢。明年石渠署，應繼叔孫通。"]'),
('yuding-54','送劉司法之越','皎然','唐','御定全唐诗','yuding','','[]','蕭蕭鳴夜角，驅馬背城濠。雨後寒流急，秋來朔吹高。',48,'御定全唐詩/json/818.json','["蕭蕭鳴夜角，驅馬背城濠。雨後寒流急，秋來朔吹高。", "三山期望海，八月欲觀濤。幾日西陵路，應逢謝法曹。"]'),
('yuding-55','送簡棲上人之建州覲使君舅','皎然','唐','御定全唐诗','yuding','','[]','亂峰江上色，羨爾及秋行。釋氏推真子，郗家許貴甥。',48,'御定全唐詩/json/818.json','["亂峰江上色，羨爾及秋行。釋氏推真子，郗家許貴甥。", "氎花新雨淨，帆葉好風輕。千里依元舅，回潮亦有情。"]'),
('yuding-56','登開元寺樓送崔少府還平望驛','皎然','唐','御定全唐诗','yuding','','[]','登望思慮積，長亭樹連連。悠揚下樓日，杳映傍帆煙。',36,'御定全唐詩/json/818.json','["登望思慮積，長亭樹連連。悠揚下樓日，杳映傍帆煙。", "入夜四郊靜，南湖月待船。"]'),
('yuding-57','送王居士游越','皎然','唐','御定全唐诗','yuding','','[]','野性配雲泉，詩情屬風景。愛作爛熳遊，閑尋東路永。',36,'御定全唐詩/json/818.json','["野性配雲泉，詩情屬風景。愛作爛熳遊，閑尋東路永。", "何山最好望，須上蕭然嶺。"]'),
('yuding-58','雜言重送皇甫侍禦曾','皎然','唐','御定全唐诗','yuding','','[]','人獨歸，日將暮。孤帆帶孤嶼，遠水連遠樹。',32,'御定全唐詩/json/818.json','["人獨歸，日將暮。孤帆帶孤嶼，遠水連遠樹。", "難作別時心，還看別時路。"]'),
('yuding-59','送演上人之撫州覲使君叔','皎然','唐','御定全唐诗','yuding','','[]','臨川內史憐諸謝，爾在生緣比惠宗。遠別應將秦本去，',40,'御定全唐詩/json/818.json','["臨川內史憐諸謝，爾在生緣比惠宗。遠別應將秦本去，", "便道須過大師寺，白蓮池上訪高蹤。"]'),
('yuding-60','送大寶上人歸楚山','皎然','唐','御定全唐诗','yuding','','[]','厭上烏橋送別頻，湖光爛熳望行人。欲將夜舸陪嘉月，',40,'御定全唐詩/json/818.json','["厭上烏橋送別頻，湖光爛熳望行人。欲將夜舸陪嘉月，", "從何得道懷惆悵，莫是人間屢見春。"]'),
('yuding-61','送侯秀才南游','皎然','唐','御定全唐诗','yuding','','[]','芳草隨君自有情，不關山色與猿聲。',32,'御定全唐詩/json/818.json','["芳草隨君自有情，不關山色與猿聲。", "為看嚴子灘頭石，曾憶題詩不著名。"]'),
('yuding-62','別洞庭維諒上人','皎然','唐','御定全唐诗','yuding','','[]','白雲關我不關他，此物留君情最多。',32,'御定全唐詩/json/818.json','["白雲關我不關他，此物留君情最多。", "情著春風生橘樹，歸心不怕洞庭波。"]'),
('yuding-63','康造錄事宅送太祝侄之虔吉訪兄弟','皎然','唐','御定全唐诗','yuding','','[]','阮咸別曲四座愁，賴是春風不是秋。',32,'御定全唐詩/json/818.json','["阮咸別曲四座愁，賴是春風不是秋。", "漫漫江行訪兄弟，猿聲幾夜宿蘆洲。"]'),
('yuding-64','冬日梅溪送裴方舟宣州','皎然','唐','御定全唐诗','yuding','','[]','平明匹馬上村橋，花發梅溪雪未消。',32,'御定全唐詩/json/818.json','["平明匹馬上村橋，花發梅溪雪未消。", "日短天寒愁送客，楚山無限路遙遙。"]'),
('yuding-65','送韋向睦州謁獨孤使君汜','皎然','唐','御定全唐诗','yuding','','[]','才子南看多遠情，閑舟蕩漾任春行。',32,'御定全唐詩/json/818.json','["才子南看多遠情，閑舟蕩漾任春行。", "新安江色長如此，何似新安太守清。"]'),
('yuding-66','送至嚴山人歸山','皎然','唐','御定全唐诗','yuding','','[]','初到人間柳始陰，山書昨夜報春深。',32,'御定全唐詩/json/818.json','["初到人間柳始陰，山書昨夜報春深。", "朝朝花落幾株樹，惱殺禪僧未證心。"]'),
('yuding-67','送僧遊揚州','皎然','唐','御定全唐诗','yuding','','[]','平明擇缽向風輕，正及隋堤柳色行。',32,'御定全唐詩/json/818.json','["平明擇缽向風輕，正及隋堤柳色行。", "知爾禪心還似我，故宮春物肯傷情。"]'),
('yuding-68','對陸迅飲天目山茶，因寄元居士晟','皎然','唐','御定全唐诗','yuding','','[]','喜見幽人會，初開野客茶。日成東井葉，露采北山芽。',72,'御定全唐詩/json/818.json','["喜見幽人會，初開野客茶。日成東井葉，露采北山芽。", "文火香偏勝，寒泉味轉嘉。投鐺湧作沫，著碗聚生花。", "稍與禪經近，聊將睡網賒。知君在天目，此意日無涯。"]'),
('yuding-69','渡前溪','皎然','唐','御定全唐诗','yuding','','[]','不意入前溪，愛溪從錯落。清清鑒不足，非是深難度。',24,'御定全唐詩/json/818.json','["不意入前溪，愛溪從錯落。清清鑒不足，非是深難度。"]'),
('yuding-70','送靈澈','皎然','唐','御定全唐诗','yuding','','[]','我欲長生夢，無心解傷別。千里萬里心，只似眼前月。',24,'御定全唐詩/json/818.json','["我欲長生夢，無心解傷別。千里萬里心，只似眼前月。"]'),
('yuding-71','寄路溫州','皎然','唐','御定全唐诗','yuding','','[]','欲問采靈藥，如何學無生。愛鶴頗似君，且非求仙情。',24,'御定全唐詩/json/818.json','["欲問采靈藥，如何學無生。愛鶴頗似君，且非求仙情。"]'),
('yuding-72','浣紗女','皎然','唐','御定全唐诗','yuding','','[]','清淺白沙灘，綠蒲尚堪把。家住水東西，浣紗明月下。',24,'御定全唐詩/json/818.json','["清淺白沙灘，綠蒲尚堪把。家住水東西，浣紗明月下。"]'),
('yuding-73','待山月','皎然','唐','御定全唐诗','yuding','','[]','夜夜憶故人，長教山月待。今宵故人至，山月知何在。',24,'御定全唐詩/json/818.json','["夜夜憶故人，長教山月待。今宵故人至，山月知何在。"]'),
('yuding-74','雜興','皎然','唐','御定全唐诗','yuding','','[]','人生分已定，富貴豈妄來。不見海底泥，飛上成塵埃。',24,'御定全唐詩/json/818.json','["人生分已定，富貴豈妄來。不見海底泥，飛上成塵埃。"]'),
('yuding-75','舂陵登望','皎然','唐','御定全唐诗','yuding','','[]','西底空流水，東垣但聚雲。最傷梅嶺望，花雪正紛紛。',24,'御定全唐詩/json/818.json','["西底空流水，東垣但聚雲。最傷梅嶺望，花雪正紛紛。"]'),
('yuding-76','投知己','皎然','唐','御定全唐诗','yuding','','[]','若為令憶洞庭春，上有閑雲可隱身。',32,'御定全唐詩/json/818.json','["若為令憶洞庭春，上有閑雲可隱身。", "無限白雲山要買，不知山價出何人。"]'),
('yuding-0','兵後餘不亭重送盧孟明遊江西','皎然','唐','御定全唐诗','yuding','','[]','攜手曾此分，怳如隔胡越。倫侯古封邑，榮盛風雨歇。',144,'御定全唐詩/json/819.json','["攜手曾此分，怳如隔胡越。倫侯古封邑，榮盛風雨歇。", "饑鼯號空亭，野草生故轍。如何此路岐，更作千年別。", "馮軾望遠道，春山無斷絕。朝行入郢樹，夜泊依楚月。", "佳士持操高，揚才日昭晰。離言何所贈，盈滿有虧缺。", "時節傷蟪蛄，芳菲忌鶗鴂。予思鹿門隱，心跡貴冥滅。", "頹顏反芝朮，昔貌成冰雪。歲晏期爾來，銷聲坐岩穴。"]'),
('yuding-1','別山詩','皎然','唐','御定全唐诗','yuding','','[]','山翁亦好禪，借我風溪樹。采藥多近峰，汲泉有春渡。',96,'御定全唐詩/json/819.json','["山翁亦好禪，借我風溪樹。采藥多近峰，汲泉有春渡。", "幽僧時相偶，仙子或與晤。自許戰勝心，彌高獨游步。", "如何區中事，奪我林棲趣。辭山下複上，戀石行仍顧。", "宿昔情或乖，庶幾跡無誤。松聲莫相誚，此心冥去住。"]'),
('yuding-2','同袁高使君送李判官使回','皎然','唐','御定全唐诗','yuding','','[]','庾公歡此別，路遠意猶賒。為出塘邊柳，榮歸府中花。',60,'御定全唐詩/json/819.json','["庾公歡此別，路遠意猶賒。為出塘邊柳，榮歸府中花。", "馳陽照古堞，遙思凝寒笳。延步下前渚，溯觴流淺沙。", "湖光引行色，輕舸傍殘霞。"]'),
('yuding-3','陪顏使君餞宣諭蕭常侍','皎然','唐','御定全唐诗','yuding','','[]','江濤凋瘵後，遠使發天都。昏墊宸心及，哀矜詔命敷。',120,'御定全唐詩/json/819.json','["江濤凋瘵後，遠使發天都。昏墊宸心及，哀矜詔命敷。", "恤民驅急傳，訪舊枉征艫。外鎮藩條最，中朝顧問殊。", "文皆正風俗，名共溢寰區。已事方懷闕，歸期早戒塗。", "繁笳咽水閣，高蓋擁雲衢。暮色生千嶂，秋聲入五湖。", "離歌猶宛轉，歸馭已踟躇。今夕庾公意，西樓月亦孤。"]'),
('yuding-4','《奉陪顏使君修韻海》畢，東溪泛舟餞諸文士','皎然','唐','御定全唐诗','yuding','','[]','諸侯崇魯學，羔雁日成群。外史刊新韻，中郎定古文。',72,'御定全唐詩/json/819.json','["諸侯崇魯學，羔雁日成群。外史刊新韻，中郎定古文。", "菁華兼百氏，縑素備三墳。國語思開物，王言欲致君。", "研精業已就，歡宴惜應分。獨望西山去，將身寄白雲。"]'),
('yuding-5','今上初登極歲送皇甫孝廉赴選','皎然','唐','御定全唐诗','yuding','','[]','行應會府春，欲勸及芳辰。北極天文正，東風漢律新。',48,'御定全唐詩/json/819.json','["行應會府春，欲勸及芳辰。北極天文正，東風漢律新。", "少年逢聖代，歡笑別情親。況是勳庸後，恩榮襲爾身。"]'),
('yuding-6','同楊使君白蘋洲送陸侍禦士佳入朝','皎然','唐','御定全唐诗','yuding','','[]','久愛吳興客，來依道德藩。旋師聞杕杜，歸路憶轘轅。',48,'御定全唐詩/json/819.json','["久愛吳興客，來依道德藩。旋師聞杕杜，歸路憶轘轅。", "舊佩蒼玉在，新歌白芷繁。今朝天地靜，北望重飛翻。"]'),
('yuding-7','雪夜送海上人常州覲叔父，上人殷仲文後','皎然','唐','御定全唐诗','yuding','','[]','繼世風流在，傳心向一燈。望雲裁衲慣，玩雪步花能。',48,'御定全唐詩/json/819.json','["繼世風流在，傳心向一燈。望雲裁衲慣，玩雪步花能。", "交戰情忘久，銷魂別未曾。明朝阮家集，知有竹林僧。"]'),
('yuding-8','送常清上人還舒州','皎然','唐','御定全唐诗','yuding','','[]','灊人思爾法，楚信有回船。估客親宵語，閑鷗偶晝禪。',48,'御定全唐詩/json/819.json','["灊人思爾法，楚信有回船。估客親宵語，閑鷗偶晝禪。", "經聲含石瀲，麈尾拂江煙。常說歸山意，誅茅廬霍前。"]'),
('yuding-9','峴山送崔子向之宣州謁裴使君','皎然','唐','御定全唐诗','yuding','','[]','楚思入詩清，晨登峴山情。秋天水西寺，古木宛陵城。',48,'御定全唐詩/json/819.json','["楚思入詩清，晨登峴山情。秋天水西寺，古木宛陵城。", "琴匣應將往，書車亦共行。吾知江太守，一顧重君名。"]'),
('yuding-10','送嚴明府入關謁黎京兆','皎然','唐','御定全唐诗','yuding','','[]','春日異秋風，何為怨別同。潮回芳渚沒，花落晝山空。',48,'御定全唐詩/json/819.json','["春日異秋風，何為怨別同。潮回芳渚沒，花落晝山空。", "旅候聞嘶馬，殘陽望斷鴻。應思右內史，相見直城中。"]'),
('yuding-11','送丘秀才游越','皎然','唐','御定全唐诗','yuding','','[]','山情與詩思，爛熳欲何從。夜舸誰相逐，空江月自逢。',48,'御定全唐詩/json/819.json','["山情與詩思，爛熳欲何從。夜舸誰相逐，空江月自逢。", "春期越草秀，晴憶剡雲濃。便擬將輕錫，攜居入亂峰。"]'),
('yuding-12','送楊校書還濟源','皎然','唐','御定全唐诗','yuding','','[]','妖烽昨日靜，故里近嵩丘。楚月搖歸夢，江楓見早秋。',48,'御定全唐詩/json/819.json','["妖烽昨日靜，故里近嵩丘。楚月搖歸夢，江楓見早秋。", "鄉心無遠道，北信減離憂。禪子還無事，辭君買沃州。"]'),
('yuding-13','送楊遂初赴選','皎然','唐','御定全唐诗','yuding','','[]','秋風吹別袂，客思在長安。若得臨觴醉，何須減瑟彈。',48,'御定全唐詩/json/819.json','["秋風吹別袂，客思在長安。若得臨觴醉，何須減瑟彈。", "秉心淩竹柏，仗信越波瀾。春會文昌府，思君每北看。"]'),
('yuding-14','送贇上人還京','皎然','唐','御定全唐诗','yuding','','[]','久遊春草盡，還寄北船歸。沙鳥窺中食，江雲入淨衣。',48,'御定全唐詩/json/819.json','["久遊春草盡，還寄北船歸。沙鳥窺中食，江雲入淨衣。", "秦原山色近，楚寺磬聲微。見說翻經館，多聞似者稀。"]'),
('yuding-15','送廣通上人遊江西','皎然','唐','御定全唐诗','yuding','','[]','香爐七嶺秀，秋色九江清。自古多禪隱，吾常愛此行。',48,'御定全唐詩/json/819.json','["香爐七嶺秀，秋色九江清。自古多禪隱，吾常愛此行。", "尋師經鄂渚，受請到青城。離別人間事，何關道者情。"]'),
('yuding-16','送羅判官還壽州幕','皎然','唐','御定全唐诗','yuding','','[]','君章才五色，知爾得家風。故里旋歸駕，壽春思奉戎。',48,'御定全唐詩/json/819.json','["君章才五色，知爾得家風。故里旋歸駕，壽春思奉戎。", "天寒長蛇伏，飆烈文虎雄。定頌張征虜，桓桓戡難功。"]'),
('yuding-17','送李秀才赴婺州招','皎然','唐','御定全唐诗','yuding','','[]','山開江色上，孤賞去應遲。綠水迎吳榜，秋風入楚詞。',48,'御定全唐詩/json/819.json','["山開江色上，孤賞去應遲。綠水迎吳榜，秋風入楚詞。", "猿清獨宿處，木落遠行時。見說東陽守，登樓為爾期。"]'),
('yuding-18','送薛逢之宣州謁廢使','皎然','唐','御定全唐诗','yuding','','[]','六月鵬盡化，鴻飛獨冥冥。秋烽家不定，險路客頻經。',48,'御定全唐詩/json/819.json','["六月鵬盡化，鴻飛獨冥冥。秋烽家不定，險路客頻經。", "牛渚何時到，漁船幾處停。遙知詠史夜，謝守月中聽。"]'),
('yuding-19','送德守二叔侄上人還國清寺覲師','皎然','唐','御定全唐诗','yuding','','[]','道賢齊二阮，俱向竹林歸。古偈穿花線，春裝卷葉衣。',48,'御定全唐詩/json/819.json','["道賢齊二阮，俱向竹林歸。古偈穿花線，春裝卷葉衣。", "僧墟回水寺，佛隴啟山扉。愛別吾何有，人心強有違。"]'),
('yuding-20','同明府章送沈秀才還石門山讀書','皎然','唐','御定全唐诗','yuding','','[]','身為郢令客，心許楚山雲。文墨應經世，林泉漫誘君。',48,'御定全唐詩/json/819.json','["身為郢令客，心許楚山雲。文墨應經世，林泉漫誘君。", "欲隨樵子去，惜與道流分。肯謝申公輩，治詩事漢文。"]'),
('yuding-21','送吉判官還京赴崔尹幕','皎然','唐','御定全唐诗','yuding','','[]','江南梅雨天，別思極春前。長路飛鳴鶴，離帆聚散煙。',48,'御定全唐詩/json/819.json','["江南梅雨天，別思極春前。長路飛鳴鶴，離帆聚散煙。", "清晨趨九陌，秋色望三邊。見說王都尹，山陽辟一賢。"]'),
('yuding-22','送裴判官赴商幕','皎然','唐','御定全唐诗','yuding','','[]','商洛近京師，才難赴幕時。離歌紛白紵，候騎擁青絲。',48,'御定全唐詩/json/819.json','["商洛近京師，才難赴幕時。離歌紛白紵，候騎擁青絲。", "會喜疲人息，應逢猾虜衰。看君策高足，自此煙霄期。"]'),
('yuding-23','送李喻之處士洪州謁曹王','皎然','唐','御定全唐诗','yuding','','[]','獨思賢王府，遂作豫章行。雄鎮廬霍秀，高秋江漢清。',48,'御定全唐詩/json/819.json','["獨思賢王府，遂作豫章行。雄鎮廬霍秀，高秋江漢清。", "見聞驚苦節，艱故傷遠情。西邸延嘉士，遺才得正平。"]'),
('yuding-24','送唐贊善遊越','皎然','唐','御定全唐诗','yuding','','[]','田園臨漢水，離亂寄隨關。今日煙塵盡，東西又未還。',48,'御定全唐詩/json/819.json','["田園臨漢水，離亂寄隨關。今日煙塵盡，東西又未還。", "長亭百越外，孤棹五湖間。何處遊芳草，雲門千萬山。"]'),
('yuding-25','送韋秀才','皎然','唐','御定全唐诗','yuding','','[]','晨裝行墮葉，萬里望桑幹。舊說涇關險，猶聞易水寒。',48,'御定全唐詩/json/819.json','["晨裝行墮葉，萬里望桑幹。舊說涇關險，猶聞易水寒。", "黃雲戰後積，白草暮來看。近得君苗信，時教旅思寬。"]'),
('yuding-26','送陳秀才赴舉','皎然','唐','御定全唐诗','yuding','','[]','諸侯懼削地，選士皆不羈。休隱脫荷芰，將鳴矜羽儀。',48,'御定全唐詩/json/819.json','["諸侯懼削地，選士皆不羈。休隱脫荷芰，將鳴矜羽儀。", "甲科爭玉片，詩句擬花枝。君實三楚秀，承家有清規。"]'),
('yuding-27','烏程李明府水堂同盧使君幼平送奘上人遊五台','皎然','唐','御定全唐诗','yuding','','[]','身將劉令隱，經共謝公翻。有此宗師在，應知我法存。',48,'御定全唐詩/json/819.json','["身將劉令隱，經共謝公翻。有此宗師在，應知我法存。", "問心常寂樂，為別豈傷魂。獨訪華泉去，秋風入雁門。"]'),
('yuding-28','送李季良北歸','皎然','唐','御定全唐诗','yuding','','[]','風吹殘柳絲，孤客欲歸時。掩抑楚弦絕，離披湘葉衰。',48,'御定全唐詩/json/819.json','["風吹殘柳絲，孤客欲歸時。掩抑楚弦絕，離披湘葉衰。", "前軍猶轉戰，故國杳難期。北望雁門雪，空吟平子詩。"]'),
('yuding-29','送淳于秀才蘭陵覲省','皎然','唐','御定全唐诗','yuding','','[]','歡言欲忘別，風信忽相驚。柳浦歸人思，蘭陵春草生。',48,'御定全唐詩/json/819.json','["歡言欲忘別，風信忽相驚。柳浦歸人思，蘭陵春草生。", "擷芳心未及，視枕戀常盈。此去非長路，還如千里情。"]'),
('yuding-30','送至洪沙彌赴上元受戒','皎然','唐','御定全唐诗','yuding','','[]','不肯資章甫，勝衣被木蘭。今隨秣陵信，欲及蔡州壇。',48,'御定全唐詩/json/819.json','["不肯資章甫，勝衣被木蘭。今隨秣陵信，欲及蔡州壇。", "野寺鐘聲遠，春山戒足寒。歸來次第學，應見後心難。"]'),
('yuding-31','九日同盧使君幼平吳興郊外送李司倉赴選','皎然','唐','御定全唐诗','yuding','','[]','重陽千騎出，送客為踟躕。曠野多搖落，寒山滿路隅。',48,'御定全唐詩/json/819.json','["重陽千騎出，送客為踟躕。曠野多搖落，寒山滿路隅。", "晴空懸蒨旆，秋色起菱湖。幾日登司會，揚才盛五都。"]'),
('yuding-32','送盧孟明還上都','皎然','唐','御定全唐诗','yuding','','[]','江皋北風至，歸客獨傷魂。楚水逢鄉雁，平陵憶故園。',48,'御定全唐詩/json/819.json','["江皋北風至，歸客獨傷魂。楚水逢鄉雁，平陵憶故園。", "征驂嘶別館，落日隱寒原。應及秦川望，春華滿國門。"]'),
('yuding-33','送李少賓赴舉','皎然','唐','御定全唐诗','yuding','','[]','豈謂江南別，心如塞上行。苦雲搖陣色，亂木攪秋聲。',48,'御定全唐詩/json/819.json','["豈謂江南別，心如塞上行。苦雲搖陣色，亂木攪秋聲。", "周穀雨未散，漢河流尚橫。春司遲爾策，方用靜妖兵。"]'),
('yuding-34','留別閻士和','皎然','唐','御定全唐诗','yuding','','[]','不慣人間別，多應忘別時。逢山又逢水，只畏卻來遲。',24,'御定全唐詩/json/819.json','["不慣人間別，多應忘別時。逢山又逢水，只畏卻來遲。"]'),
('yuding-35','送李道士','皎然','唐','御定全唐诗','yuding','','[]','常隨山上下，忽限江南北。共是忘情人，何由肯相憶。',24,'御定全唐詩/json/819.json','["常隨山上下，忽限江南北。共是忘情人，何由肯相憶。"]'),
('yuding-36','送裴參軍還下邳舊居','皎然','唐','御定全唐诗','yuding','','[]','北望煙鋪驃騎營，虜烽無火楚天晴。',32,'御定全唐詩/json/819.json','["北望煙鋪驃騎營，虜烽無火楚天晴。", "此時千里西歸客，泗上春風得及耕。"]'),
('yuding-37','送文會上人還富陽','皎然','唐','御定全唐诗','yuding','','[]','悠悠渺渺屬寒波，故寺思歸意若何。',32,'御定全唐詩/json/819.json','["悠悠渺渺屬寒波，故寺思歸意若何。", "長憶孤洲二三月，春山偏愛富春多。"]'),
('yuding-38','送維諒上人歸洞庭','皎然','唐','御定全唐诗','yuding','','[]','從來湖上勝人間，遠愛浮雲獨自還。',32,'御定全唐詩/json/819.json','["從來湖上勝人間，遠愛浮雲獨自還。", "孤月空天見心地，寥寥一水鏡中山。"]'),
('yuding-39','九月八日送蕭少府歸洪州','皎然','唐','御定全唐诗','yuding','','[]','明日重陽今日歸，布帆絲雨望霏霏。',32,'御定全唐詩/json/819.json','["明日重陽今日歸，布帆絲雨望霏霏。", "行過鶴渚知堪住，家在龍沙意有違。"]'),
('yuding-40','同顏魯公泛舟送皇甫侍禦曾','皎然','唐','御定全唐诗','yuding','','[]','維舟若許暫從容，送過重江不厭重。',32,'御定全唐詩/json/819.json','["維舟若許暫從容，送過重江不厭重。", "霜簡別來今始見，雪山歸去又難逢。"]'),
('yuding-41','送孫侍禦游越','皎然','唐','御定全唐诗','yuding','','[]','不知持斧客，吟會是何情。丹陛恩猶在，滄洲賞暫行。',48,'御定全唐詩/json/819.json','["不知持斧客，吟會是何情。丹陛恩猶在，滄洲賞暫行。", "江橈隨月泛，山策逐雲行。佳句傳零雨，詩流許盛名。"]'),
('yuding-42','送顏處士還長沙覲省','皎然','唐','御定全唐诗','yuding','','[]','西候風信起，三湘孤客心。天寒漢水廣，鄉遠楚雲深。',48,'御定全唐詩/json/819.json','["西候風信起，三湘孤客心。天寒漢水廣，鄉遠楚雲深。", "服彩將侍膳，擷芳思滿襟。歸人忘艱阻，別恨獨何任。"]'),
('yuding-43','送還本上人遊江西','皎然','唐','御定全唐诗','yuding','','[]','欲廣分何教，心將江漢期。雲招望寺處，月待溯杯時。',48,'御定全唐詩/json/819.json','["欲廣分何教，心將江漢期。雲招望寺處，月待溯杯時。", "真侶誰傷別，降猿汝自悲。多應過廬阜，幽賞卻來遲。"]'),
('yuding-44','送路少府使京兼覲侍禦兄','皎然','唐','御定全唐诗','yuding','','[]','國賦推能吏，今朝發貢湖。佇瞻雙闕鳳，思見柏台烏。',48,'御定全唐詩/json/819.json','["國賦推能吏，今朝發貢湖。佇瞻雙闕鳳，思見柏台烏。", "樹向秦關遠，江分楚驛孤。榮君有兄弟，相繼騁長途。"]'),
('yuding-45','于武原從送盧士舉','皎然','唐','御定全唐诗','yuding','','[]','落日獨歸客，空山匹馬嘶。蕭條古關外，岐路更東西。',48,'御定全唐詩/json/819.json','["落日獨歸客，空山匹馬嘶。蕭條古關外，岐路更東西。", "大澤雲寂寂，長亭雨淒淒。君還到湘水，寒夜滿猿啼。"]'),
('yuding-46','送烏程李明府得陟狀赴京','皎然','唐','御定全唐诗','yuding','','[]','驛吏滿江城，深仁見此情。士林推玉振，公府薦冰清。',48,'御定全唐詩/json/819.json','["驛吏滿江城，深仁見此情。士林推玉振，公府薦冰清。", "為政移風久，承恩就日行。仲容綸綍貴，南巷有光榮。"]'),
('yuding-47','送裴秀才往會稽山讀書','皎然','唐','御定全唐诗','yuding','','[]','一身齎萬卷，編室寄煙蘿。硯滴穿池小，書衣種楮多。',48,'御定全唐詩/json/819.json','["一身齎萬卷，編室寄煙蘿。硯滴穿池小，書衣種楮多。", "吟詩山響答，泛瑟竹聲和。鶴板求儒術，深居意若何。"]'),
('yuding-48','送崔詹事論之上都','皎然','唐','御定全唐诗','yuding','','[]','金虎城池在，銅龍劍佩新。重看前浦柳，猶憶舊洲蘋。',48,'御定全唐詩/json/819.json','["金虎城池在，銅龍劍佩新。重看前浦柳，猶憶舊洲蘋。", "遠思秦雲暮，歸心臘月春。青園昔遊處，惆悵別離人。"]'),
('yuding-49','京口送盧孟明還揚州','皎然','唐','御定全唐诗','yuding','','[]','蕭蕭北風起，孤棹下江濆。暮客去來盡，春流南北分。',48,'御定全唐詩/json/819.json','["蕭蕭北風起，孤棹下江濆。暮客去來盡，春流南北分。", "萋萋禦亭草，渺渺蕪城雲。相送目千里，空山獨望君。"]'),
('yuding-50','送沙彌大智遊五台','皎然','唐','御定全唐诗','yuding','','[]','童年隨法侶，家世本儒流。章句三生學，清涼萬里遊。',48,'御定全唐詩/json/819.json','["童年隨法侶，家世本儒流。章句三生學，清涼萬里遊。", "雲歸龍沼暗，木落雁門秋。長老應相問，傳予向祖州。"]'),
('yuding-51','送稟上人遊越','皎然','唐','御定全唐诗','yuding','','[]','雲泉誰不賞，獨見爾情高。投石輕龍窟，臨流笑鷺濤。',48,'御定全唐詩/json/819.json','["雲泉誰不賞，獨見爾情高。投石輕龍窟，臨流笑鷺濤。", "折荷為片席，灑水淨方袍。剡路逢禪侶，多應問我曹。"]'),
('yuding-52','送潘秀才之舒州','皎然','唐','御定全唐诗','yuding','','[]','楚水清風生，揚舲泛月行。荻洲寒露彩，雷岸曙潮聲。',48,'御定全唐詩/json/819.json','["楚水清風生，揚舲泛月行。荻洲寒露彩，雷岸曙潮聲。", "東道思才子，西人望客卿。從來金穀集，相繼有詩名。"]'),
('yuding-53','送王山人遊廬山','皎然','唐','御定全唐诗','yuding','','[]','千里訪靈奇，山資亦相隨。葉舟過鶴市，花漏宿龍池。',48,'御定全唐詩/json/819.json','["千里訪靈奇，山資亦相隨。葉舟過鶴市，花漏宿龍池。", "峰頂應閒散，人間足別離。白雲將世事，吾見爾心知。"]'),
('yuding-54','送道契上人之越覲大夫叔','皎然','唐','御定全唐诗','yuding','','[]','楚僧推後輩，唐本學新經。外國傳香氎，何人施竹瓶。',48,'御定全唐詩/json/819.json','["楚僧推後輩，唐本學新經。外國傳香氎，何人施竹瓶。", "秋風別李寺，春日向柯亭。大阮今為郡，看君眼最青。"]'),
('yuding-55','送沙彌長文遊京','皎然','唐','御定全唐诗','yuding','','[]','白版年猶小，黃花褐已通。若為詩思逸，早欲似休公。',48,'御定全唐詩/json/819.json','["白版年猶小，黃花褐已通。若為詩思逸，早欲似休公。", "邁俗多真氣，傳家有素風。應須學心地，宗旨在關東。"]'),
('yuding-56','秋日送擇高上人往江西謁曹王','皎然','唐','御定全唐诗','yuding','','[]','超然獨遊趣，無限別山情。予病不同賞，雲閑應共行。',48,'御定全唐詩/json/819.json','["超然獨遊趣，無限別山情。予病不同賞，雲閑應共行。", "齋容秋水照，香氎早風輕。曾被陳王識，遙知江上迎。"]'),
('yuding-57','送如獻上人游長安','皎然','唐','御定全唐诗','yuding','','[]','關中四子教猶存，見說新經待爾翻。為法應過七祖寺，',40,'御定全唐詩/json/819.json','["關中四子教猶存，見說新經待爾翻。為法應過七祖寺，", "高逸詩情無別怨，春遊從遣落花繁。"]'),
('yuding-58','日曜上人還潤州','皎然','唐','御定全唐诗','yuding','','[]','送君何處最堪思，孤月停空欲別時。露茗猶芳邀重會，',40,'御定全唐詩/json/819.json','["送君何處最堪思，孤月停空欲別時。露茗猶芳邀重會，", "莫倚禪功放心定，蕭家陵樹誤人悲。"]'),
('yuding-59','寺院聽胡笳送李殷','皎然','唐','御定全唐诗','yuding','','[]','一奏胡笳客未停，野僧還欲廢禪聽。',32,'御定全唐詩/json/819.json','["一奏胡笳客未停，野僧還欲廢禪聽。", "難將此意臨江別，無限春風葭菼青。"]'),
('yuding-60','送僧繹','皎然','唐','御定全唐诗','yuding','','[]','斜日搖揚在柳絲，孤亭寂寂水逶迤。',32,'御定全唐詩/json/819.json','["斜日搖揚在柳絲，孤亭寂寂水逶迤。", "誰堪別後行人盡，唯有春風起路岐。"]'),
('yuding-61','答裴評事澄荻花間送梁肅拾遺','皎然','唐','御定全唐诗','yuding','','[]','波上荻花非雪花，風吹撩亂滿袈裟。',32,'御定全唐詩/json/819.json','["波上荻花非雪花，風吹撩亂滿袈裟。", "如今歲晏無芳草，獨對離樽作物華。"]'),
('yuding-62','送勝雲小師','皎然','唐','御定全唐诗','yuding','','[]','昨日雪山記爾名，吾今坐石已三生。',32,'御定全唐詩/json/819.json','["昨日雪山記爾名，吾今坐石已三生。", "少年道性易流動，莫遣秋風入別情。"]'),
('yuding-63','誚士和別','皎然','唐','御定全唐诗','yuding','','[]','今日同，明日隔，何事悠悠久為客。君憐溪上去來雲，',24,'御定全唐詩/json/819.json','["今日同，明日隔，何事悠悠久為客。君憐溪上去來雲，"]'),
('yuding-64','送吳馮遊京','皎然','唐','御定全唐诗','yuding','','[]','北期何意促，蕙草夜來繁。清月思淮水，春風望國門。',48,'御定全唐詩/json/819.json','["北期何意促，蕙草夜來繁。清月思淮水，春風望國門。", "此時休旋逸，萬里忽飛翻。若憶山陰會，孤琴為我援。"]'),
('yuding-65','送僧游宣州','皎然','唐','御定全唐诗','yuding','','[]','楚山千里一僧行，念爾初緣道未成。',32,'御定全唐詩/json/819.json','["楚山千里一僧行，念爾初緣道未成。", "莫向舒姑泉口泊，此中嗚咽為傷情。"]'),
('yuding-66','宿支硎寺上房','皎然','唐','御定全唐诗','yuding','','[]','上方精舍遠，共宿白雲端。寂寞千峰夜，蕭條萬木寒。',48,'御定全唐詩/json/819.json','["上方精舍遠，共宿白雲端。寂寞千峰夜，蕭條萬木寒。", "山光霜下見，松色月中看。卻與西林別，歸心即欲闌。"]'),
('yuding-67','答胡處士','皎然','唐','御定全唐诗','yuding','','[]','西山禪隱比來聞，長道唯應我與君。',32,'御定全唐詩/json/819.json','["西山禪隱比來聞，長道唯應我與君。", "書上無名心忘卻，人間聚散似浮雲。"]'),
('yuding-68','答張烏程','皎然','唐','御定全唐诗','yuding','','[]','莫道謫官無主人，秣陵才令日相親。',32,'御定全唐詩/json/819.json','["莫道謫官無主人，秣陵才令日相親。", "前溪更有忘憂處，荷葉田田間白蘋。"]'),
('yuding-69','酬張明府','皎然','唐','御定全唐诗','yuding','','[]','愛君詩思動禪心，使我休吟待鶴吟。',32,'御定全唐詩/json/819.json','["愛君詩思動禪心，使我休吟待鶴吟。", "更說郡中黃霸在，朝朝無事許招尋。"]'),
('yuding-70','勞山居寄呈吳處士','皎然','唐','御定全唐诗','yuding','','[]','官居鼎鼐古今無，名世才臣獨一餘。',32,'御定全唐詩/json/819.json','["官居鼎鼐古今無，名世才臣獨一餘。", "賢閣禦題龍墨燦，詔歸補袞在須臾。"]'),
('yuding-0','從軍行五首','皎然','唐','御定全唐诗','yuding','','[]','候騎出紛紛，元戎霍冠軍。漢鞞秋聒地，羌火晝燒雲。',240,'御定全唐詩/json/820.json','["候騎出紛紛，元戎霍冠軍。漢鞞秋聒地，羌火晝燒雲。", "萬里戈城合，三邊羽檄分。烏孫驅未盡，肯顧遼陽勳。", "韓旆拂丹霄，漢軍新破遼。紅塵驅鹵簿，白羽擁嫖姚。", "戰苦軍猶樂，功高將不驕。至今丁零塞，朔吹空蕭蕭。", "百萬逐呼韓，頻年不解鞍。兵屯絕漠暗，馬飲濁河幹。", "破虜功未錄，勞師力已殫。須防肘腋下，飛禍出無端。", "飛將下天來，奇謀閫外裁。水心龍劍動，地肺雁山開。", "望氣燕師銳，當鋒虜陣摧。從今射雕騎，不敢過雲堆。", "黃紙君王詔，青泥校尉書。誓師張虎落，選將擐犀渠。", "霧暗津蒲失，天寒塞柳疏。橫行十萬騎，欲掃虜塵餘。"]'),
('yuding-1','隴頭水二首','皎然','唐','御定全唐诗','yuding','','[]','隴頭水欲絕，隴水不堪聞。碎影搖槍壘，寒聲咽幔軍。',96,'御定全唐詩/json/820.json','["隴頭水欲絕，隴水不堪聞。碎影搖槍壘，寒聲咽幔軍。", "素從鹽海積，綠帶柳城分。日落天邊望，逶迤入塞雲。", "秦隴逼氐羌，征人去未央。如何幽咽水，並欲斷君腸。", "西注悲窮漠，東分憶故鄉。旅魂聲攪亂，無夢到咸陽。"]'),
('yuding-2','塞下曲二首','皎然','唐','御定全唐诗','yuding','','[]','寒塞無因見落梅，胡人吹入笛聲來。',64,'御定全唐詩/json/820.json','["寒塞無因見落梅，胡人吹入笛聲來。", "勞勞亭上春應度，夜夜城南戰未回。", "都護今年破武威，胡沙萬里鳥空飛。", "旄竿瀚海掃雲出，氈騎天山蹋雪歸。"]'),
('yuding-3','覽史','皎然','唐','御定全唐诗','yuding','','[]','黃綺皆皓發，秦時隱商山。嘉謀匡帝道，高步游天關。',48,'御定全唐詩/json/820.json','["黃綺皆皓發，秦時隱商山。嘉謀匡帝道，高步游天關。", "不愛珪組絏，卻思林壑還。放歌長松下，日與孤雲閑。"]'),
('yuding-4','詠史','皎然','唐','御定全唐诗','yuding','','[]','獨負高世資，冥冥寄浮俗。卞子去不歸，何人辯荊玉。',60,'御定全唐詩/json/820.json','["獨負高世資，冥冥寄浮俗。卞子去不歸，何人辯荊玉。", "鬻舂意不淺，汙跡身豈辱。鸞鎩樂迍邅，虯蟠甘窘束。", "五噫譎且正，可以見心曲。"]'),
('yuding-5','詠史','皎然','唐','御定全唐诗','yuding','','[]','田氏門下客，馮公眾中賤。一朝市義還，百代名獨擅。',48,'御定全唐詩/json/820.json','["田氏門下客，馮公眾中賤。一朝市義還，百代名獨擅。", "始知下客不可輕，能使主人功業成。借問高車與珠履，"]'),
('yuding-6','讀張曲江集','皎然','唐','御定全唐诗','yuding','','[]','相公乃天蓋，人文佐生成。立程正頹靡，繹思何縱橫。',180,'御定全唐詩/json/820.json','["相公乃天蓋，人文佐生成。立程正頹靡，繹思何縱橫。", "春杼弄緗綺，陽林敷玉英。飄然飛動姿，邈矣高簡情。", "後輩驚失步，前修敢爭衡。始欣耳目遠，再使機慮清。", "體正力已全，理精識何妙。昔年歌陽春，徒推郢中調。", "今朝聽鸞鳳，豈獨羨門嘯。帝命鎮雄州，待濟寄上流。", "才兼荊衡秀，氣助瀟湘秋。逸蕩子山匹，經奇文暢儔。", "沈吟未終卷，變態紛難數。曜耳代明璫，襲衣同芳杜。", "愔愔聞玉磬，寤寐在靈府。"]'),
('yuding-7','奉酬陸使君見過，各賦院中一物，得江蘺','皎然','唐','御定全唐诗','yuding','','[]','江蘺生古砌，花每落禪床。嘉客未采掇，空門自馨香。',48,'御定全唐詩/json/820.json','["江蘺生古砌，花每落禪床。嘉客未采掇，空門自馨香。", "名因詩目見，色對道心忘。不遇陸內史，誰知殊眾芳。"]'),
('yuding-8','賦得謝墅送王長史','皎然','唐','御定全唐诗','yuding','','[]','世業西山墅，移家長我身。蕭疏遺樹老，寂寞廢田春。',48,'御定全唐詩/json/820.json','["世業西山墅，移家長我身。蕭疏遺樹老，寂寞廢田春。", "車巷傷前轍，籬溝憶舊鄰。何堪再過日，更送北歸人。"]'),
('yuding-9','夏日同崔使君論登城樓賦得遠山','皎然','唐','御定全唐诗','yuding','','[]','遠山湖上小，青翠望依稀。才向窗中列，還從林表微。',48,'御定全唐詩/json/820.json','["遠山湖上小，青翠望依稀。才向窗中列，還從林表微。", "色濃春草在，峰起夏雲歸。不是蓬萊島，如何人去稀。"]'),
('yuding-10','詠數探得七','皎然','唐','御定全唐诗','yuding','','[]','鄒子譚天歲，黃童對日年。求真初作傳，煉魄已成仙。',48,'御定全唐詩/json/820.json','["鄒子譚天歲，黃童對日年。求真初作傳，煉魄已成仙。", "鶴駕迎緱嶺，星橋下蜀川。逢君竹林客，相對弄清弦。"]'),
('yuding-11','奉同顏使君真卿送李侍禦萼，賦得荻塘路','皎然','唐','御定全唐诗','yuding','','[]','落日車遙遙，客心在歸路。細草暗回塘，春泉縈古渡。',48,'御定全唐詩/json/820.json','["落日車遙遙，客心在歸路。細草暗回塘，春泉縈古渡。", "遺蹤歎蕪沒，遠道悲去住。寂寞荻花空，行人別無數。"]'),
('yuding-12','《賦顏氏古今一事，得晉仙傳》，送顏逸','皎然','唐','御定全唐诗','yuding','','[]','曾看顏氏傳，多記晉時仙。卻憶桐君老，俱還桂父年。',48,'御定全唐詩/json/820.json','["曾看顏氏傳，多記晉時仙。卻憶桐君老，俱還桂父年。", "青春留鬢髮，白日向雲煙。遠別齎遺簡，囊中有幾篇。"]'),
('yuding-13','賦得石樑泉送崔逵','皎然','唐','御定全唐诗','yuding','','[]','架石通霞壁，懸崖散碧沙。天晴虹影渡，風細練文斜。',48,'御定全唐詩/json/820.json','["架石通霞壁，懸崖散碧沙。天晴虹影渡，風細練文斜。", "舉陟幽期阻，沿洄客意賒。河梁非此路，別恨亦無涯。"]'),
('yuding-14','賦得夜雨滴空階，送陸羽歸龍山','皎然','唐','御定全唐诗','yuding','','[]','閑階夜雨滴，偏入別情中。斷續清猿應，淋漓候館空。',48,'御定全唐詩/json/820.json','["閑階夜雨滴，偏入別情中。斷續清猿應，淋漓候館空。", "氣令煩慮散，時與早秋同。歸客龍山道，東來雜好風。"]'),
('yuding-15','賦得燈心送李侍禦萼','皎然','唐','御定全唐诗','yuding','','[]','燈心生眾草，因有始知芳。彩妓窗偏麗，金桃動更香。',48,'御定全唐詩/json/820.json','["燈心生眾草，因有始知芳。彩妓窗偏麗，金桃動更香。", "花驚春未盡，焰喜夜初長。別後空離室，何人借末光。"]'),
('yuding-16','賦得竹如意送詳師赴講','皎然','唐','御定全唐诗','yuding','','[]','縹竹湘南美，吾師尚毀形。仍留負霜節，不變在林青。',48,'御定全唐詩/json/820.json','["縹竹湘南美，吾師尚毀形。仍留負霜節，不變在林青。", "每入楊枝手，因談貝葉經。誰期沃州講，持此別東亭。"]'),
('yuding-17','《聽素法師講法華經》','皎然','唐','御定全唐诗','yuding','','[]','法子出西秦，名齊漆道人。才敷藥草義，便見雪山春。',48,'御定全唐詩/json/820.json','["法子出西秦，名齊漆道人。才敷藥草義，便見雪山春。", "護講龍來遠，聞經鶴下頻。應機如一雨，誰不滌心塵。"]'),
('yuding-18','詠敡上人座右畫松','皎然','唐','御定全唐诗','yuding','','[]','寫得長松意，千尋數尺中。翠陰疑背日，寒色欲生風。',48,'御定全唐詩/json/820.json','["寫得長松意，千尋數尺中。翠陰疑背日，寒色欲生風。", "真樹孤標在，高人立操同。一枝遙可折，吾欲問生公。"]'),
('yuding-19','夏日登觀農樓和崔使君','皎然','唐','御定全唐诗','yuding','','[]','片雨拂簷楹，煩襟四坐清。霏微過麥隴，蕭散傍莎城。',48,'御定全唐詩/json/820.json','["片雨拂簷楹，煩襟四坐清。霏微過麥隴，蕭散傍莎城。", "靜愛和花落，幽聞入竹聲。朝觀趣無限，高詠寄深情。"]'),
('yuding-20','妙喜寺逵公院賦得夜磬送呂評事','皎然','唐','御定全唐诗','yuding','','[]','一磬寒山至，凝心轉清越。細和虛籟盡，疏繞懸泉發。',60,'御定全唐詩/json/820.json','["一磬寒山至，凝心轉清越。細和虛籟盡，疏繞懸泉發。", "在夜吟更長，停空韻難絕。幽僧悟深定，歸客忘遠別。", "寂曆無性中，真聲何起滅。"]'),
('yuding-21','詠小瀑布','皎然','唐','御定全唐诗','yuding','','[]','瀑布小更奇，潺湲二三尺。細脈穿亂沙，叢聲咽危石。',48,'御定全唐詩/json/820.json','["瀑布小更奇，潺湲二三尺。細脈穿亂沙，叢聲咽危石。", "初因智者賞，果會幽人跡。不向定中聞，那知我心寂。"]'),
('yuding-22','仙女台','皎然','唐','御定全唐诗','yuding','','[]','寂寂舊桑田，誰家女得仙。應無雞犬在，空有子孫傳。',48,'御定全唐詩/json/820.json','["寂寂舊桑田，誰家女得仙。應無雞犬在，空有子孫傳。", "古木花猶發，荒台路未遷。暮來雲一片，疑是欲歸年。"]'),
('yuding-23','靈澈上人何山寺七賢石詩','皎然','唐','御定全唐诗','yuding','','[]','七石配七賢，隱僧山上移。石性殊磊落，君子又高奇。',72,'御定全唐詩/json/820.json','["七石配七賢，隱僧山上移。石性殊磊落，君子又高奇。", "跂禪服宜壞，坐客冠可隳。夜倚月樹影，晝傾風竹枝。", "集質患追琢，表頑用磷緇。佚火玉亦害，塊然長在茲。"]'),
('yuding-24','潘丞孩子','皎然','唐','御定全唐诗','yuding','','[]','愛子性情奇，初生玉樹枝。人曾天上見，名向月中知。',36,'御定全唐詩/json/820.json','["愛子性情奇，初生玉樹枝。人曾天上見，名向月中知。", "我識嬰兒意，何須待佩觿。"]'),
('yuding-25','南池雜詠五首：水月','皎然','唐','御定全唐诗','yuding','','[]','夜夜池上觀，禪身坐月邊。虛無色可取，皎潔意難傳。',36,'御定全唐詩/json/820.json','["夜夜池上觀，禪身坐月邊。虛無色可取，皎潔意難傳。", "若向空心了，長如影正圓。"]'),
('yuding-26','南池雜詠五首：溪雲','皎然','唐','御定全唐诗','yuding','','[]','舒卷意何窮，縈流複帶空。有形不累物，無跡去隨風。',36,'御定全唐詩/json/820.json','["舒卷意何窮，縈流複帶空。有形不累物，無跡去隨風。", "莫怪長相逐，飄然與我同。"]'),
('yuding-27','南池雜詠五首：虛舟','皎然','唐','御定全唐诗','yuding','','[]','虛舟動又靜，忽似去逢時。觸物知無迕，為梁幸見遺。',36,'御定全唐詩/json/820.json','["虛舟動又靜，忽似去逢時。觸物知無迕，為梁幸見遺。", "因風到此岸，非有濟川期。"]'),
('yuding-28','南池雜詠五首：寒山','皎然','唐','御定全唐诗','yuding','','[]','侵空撩亂色，獨愛我中峰。無事負輕策，閑行躡幽蹤。',36,'御定全唐詩/json/820.json','["侵空撩亂色，獨愛我中峰。無事負輕策，閑行躡幽蹤。", "眾山搖落盡，寒翠更重重。"]'),
('yuding-29','南池雜詠五首：寒竹','皎然','唐','御定全唐诗','yuding','','[]','嫋嫋孤生竹，獨立山中雪。蒼翠搖動風，嬋娟帶寒月。',36,'御定全唐詩/json/820.json','["嫋嫋孤生竹，獨立山中雪。蒼翠搖動風，嬋娟帶寒月。", "狂花不相似，還共淩冬發。"]'),
('yuding-30','望遠村','皎然','唐','御定全唐诗','yuding','','[]','林杪不可分，水步遙難辨。一片山翠邊，依稀見村遠。',24,'御定全唐詩/json/820.json','["林杪不可分，水步遙難辨。一片山翠邊，依稀見村遠。"]'),
('yuding-31','惜暮景','皎然','唐','御定全唐诗','yuding','','[]','疏陰花不動，片景松梢度。夏日舊來長，佳游何易暮。',24,'御定全唐詩/json/820.json','["疏陰花不動，片景松梢度。夏日舊來長，佳游何易暮。"]'),
('yuding-32','效古','皎然','唐','御定全唐诗','yuding','','[]','日出天地正，煌煌辟晨曦。六龍驅群動，古今無盡時。',72,'御定全唐詩/json/820.json','["日出天地正，煌煌辟晨曦。六龍驅群動，古今無盡時。", "誇父亦何愚，競走先自疲。飲幹咸池水，折盡扶桑枝。", "渴死化爝火，嗟嗟徒爾為。空留鄧林在，折盡令人嗤。"]'),
('yuding-33','古別離','皎然','唐','御定全唐诗','yuding','','[]','太湖三山口，吳王在時道。寂寞千載心，無人見春草。',85,'御定全唐詩/json/820.json','["太湖三山口，吳王在時道。寂寞千載心，無人見春草。", "誰識緘怨者，持此傷懷抱。孤舟畏狂風，一點宿煙島。", "望所思兮若何，月蕩漾兮空波。雲離離兮北斷，", "春風胡為兮塞路，使我歸夢兮撩亂。"]'),
('yuding-34','擬長安春詞','皎然','唐','御定全唐诗','yuding','','[]','春信在河源，春風蕩妾魂。春歌雜鶗鴂，春夢繞轘轅。',48,'御定全唐詩/json/820.json','["春信在河源，春風蕩妾魂。春歌雜鶗鴂，春夢繞轘轅。", "春絮愁偏滿，春絲悶更繁。春期不可定，春曲懶新翻。"]'),
('yuding-35','效古','皎然','唐','御定全唐诗','yuding','','[]','思君轉戰度交河，強弄胡琴不成曲。日落應愁隴底難，',24,'御定全唐詩/json/820.json','["思君轉戰度交河，強弄胡琴不成曲。日落應愁隴底難，"]'),
('yuding-36','昭君怨','皎然','唐','御定全唐诗','yuding','','[]','自倚嬋娟望主恩，誰知美惡忽相翻。',32,'御定全唐詩/json/820.json','["自倚嬋娟望主恩，誰知美惡忽相翻。", "黃金不買漢宮貌，青塚空埋胡地魂。"]'),
('yuding-37','銅雀妓','皎然','唐','御定全唐诗','yuding','','[]','強開尊酒向陵看，憶得君王舊日歡。',32,'御定全唐詩/json/820.json','["強開尊酒向陵看，憶得君王舊日歡。", "不覺餘歌悲自斷，非關豔曲轉聲難。"]'),
('yuding-38','長門怨','皎然','唐','御定全唐诗','yuding','','[]','春風日日閉長門，搖盪春心似夢魂。',32,'御定全唐詩/json/820.json','["春風日日閉長門，搖盪春心似夢魂。", "誰遣花開只笑妾，不如桃李正無言。"]'),
('yuding-39','哭吳縣房聳明府','皎然','唐','御定全唐诗','yuding','','[]','仁人邁厚德，可謂名實全。撫跡若疏曠，會心極精研。',336,'御定全唐詩/json/820.json','["仁人邁厚德，可謂名實全。撫跡若疏曠，會心極精研。", "履危節詎屈，著論識不偏。恨以榮級淺，嘉猷未及宣。", "伊人期遠大，志業難比肩。昭世既合併，吾君藉陶甄。", "奈何明明理，與善徒空詮。征教或稽聖，窮源反問天。", "一官自吳邑，六翮委江壖。始是牽絲日，翻成撤瑟年。", "金膏果不就，玉佩長此捐。倚伏信冥昧，夭修驚後先。", "安知忘情子，愛網素已褰。為有深仁感，遂令真性遷。", "心悲空林下，淚灑秋景前。夫子寡兄弟，撫孤傷藐然。", "傾雲為慘結，吊鶴共聯翩。割念命歸駕，訣詞向空筵。", "樹桃陰始合，愛客位常懸。幡然遠行時，崇望歸朝旋。", "悟茲歡宴隔，哀被歲月延。書帶變芳草，履痕移綠錢。", "冥期儻可逢，生盡會無緣。幸願示因業，代君運精專。", "相思轉寂寞，獨往西林泉。欲見故人心，時閱所贈篇。", "素高陶靖節，今重楚先賢。芳躅將遺愛，可為終古傳。"]'),
('yuding-40','哭覺上人','皎然','唐','御定全唐诗','yuding','','[]','憶君南適越，不作買山期。昨得耶溪信，翻為逝水悲。',48,'御定全唐詩/json/820.json','["憶君南適越，不作買山期。昨得耶溪信，翻為逝水悲。", "神交如可見，生盡杳難思。白日東林下，空懷步影時。"]'),
('yuding-41','題餘不溪廢寺','皎然','唐','御定全唐诗','yuding','','[]','武原離亂後，真界積塵埃。殘月生秋水，悲風起故台。',48,'御定全唐詩/json/820.json','["武原離亂後，真界積塵埃。殘月生秋水，悲風起故台。", "居人今已盡，棲鴿暝還來。不到無生理，應堪賦七哀。"]'),
('yuding-42','同李洗馬入餘不溪經辛將軍故城','皎然','唐','御定全唐诗','yuding','','[]','慘慘寒城望，將軍下世時。高墉暮草遍，大樹野風悲。',48,'御定全唐詩/json/820.json','["慘慘寒城望，將軍下世時。高墉暮草遍，大樹野風悲。", "壁壘今惟在，勳庸近可思。蒼然古溪上，川逝共淒其。"]'),
('yuding-43','憶天臺','皎然','唐','御定全唐诗','yuding','','[]','箬溪朝雨散，雲色似天臺。應是東風便，吹從海上來。',48,'御定全唐詩/json/820.json','["箬溪朝雨散，雲色似天臺。應是東風便，吹從海上來。", "靈山遊汗漫，仙石過莓苔。誤到人間世，經年不早回。"]'),
('yuding-44','萬回寺','皎然','唐','御定全唐诗','yuding','','[]','萬里稱逆化，愚蠢性亦全。紫紱拖身上，妖姬安膝前。',48,'御定全唐詩/json/820.json','["萬里稱逆化，愚蠢性亦全。紫紱拖身上，妖姬安膝前。", "見他拘坐寂，故我是眠禪。吾知至人心，杳若青冥天。"]'),
('yuding-45','禪詩','皎然','唐','御定全唐诗','yuding','','[]','萬法出無門，紛紛使智昏。徒稱誰氏子，獨立天地元。',48,'御定全唐詩/json/820.json','["萬法出無門，紛紛使智昏。徒稱誰氏子，獨立天地元。", "實際且何有，物先安可存。須知不動念，照出萬重源。"]'),
('yuding-46','哀教','皎然','唐','御定全唐诗','yuding','','[]','本師不得已，強為我著書。知盡百慮遣，名存萬象拘。',48,'御定全唐詩/json/820.json','["本師不得已，強為我著書。知盡百慮遣，名存萬象拘。", "如何工言子，終日論虛無。伊人獨冥冥，時人以為愚。"]'),
('yuding-47','聞鐘','皎然','唐','御定全唐诗','yuding','','[]','古寺寒山上，遠鐘揚好風。聲餘月樹動，響盡霜天空。',36,'御定全唐詩/json/820.json','["古寺寒山上，遠鐘揚好風。聲餘月樹動，響盡霜天空。", "永夜一禪子，泠然心境中。"]'),
('yuding-48','溪上月','皎然','唐','御定全唐诗','yuding','','[]','秋水月娟娟，初生色界天。蟾光散浦漵，素影動淪漣。',36,'御定全唐詩/json/820.json','["秋水月娟娟，初生色界天。蟾光散浦漵，素影動淪漣。", "何事無心見，虧盈向夜禪。"]'),
('yuding-49','山雪','皎然','唐','御定全唐诗','yuding','','[]','夕陽在西峰，疊翠縈殘雪。狂風卷絮回，驚猿攀玉折。',36,'御定全唐詩/json/820.json','["夕陽在西峰，疊翠縈殘雪。狂風卷絮回，驚猿攀玉折。", "何意山中人，誤報山花發。"]'),
('yuding-50','江上風','皎然','唐','御定全唐诗','yuding','','[]','江風西複東，飄暴忽何窮。初生虛無際，稍起蕩漾中。',48,'御定全唐詩/json/820.json','["江風西複東，飄暴忽何窮。初生虛無際，稍起蕩漾中。", "應吹夏口檣竿折，定蹙湓城浪花咽。今朝莫怪沙岸明，"]'),
('yuding-51','山雨','皎然','唐','御定全唐诗','yuding','','[]','一片雨，山半晴。長風吹落西山上，滿樹蕭蕭心耳清。',44,'御定全唐詩/json/820.json','["一片雨，山半晴。長風吹落西山上，滿樹蕭蕭心耳清。", "雲鶴驚亂下，水香凝不然。風回雨定芭蕉濕，"]'),
('yuding-52','問遙山禪老','皎然','唐','御定全唐诗','yuding','','[]','天與松子壽，獨飲日月精。複令顏子賢，胡為夭其生。',60,'御定全唐詩/json/820.json','["天與松子壽，獨飲日月精。複令顏子賢，胡為夭其生。", "吾將尋河源，上天問天何不平？吾將詰仙老，", "明朝欲向翅頭山，問取禪公此義還。"]'),
('yuding-53','禪思','皎然','唐','御定全唐诗','yuding','','[]','真我性無主，誰為塵識昏。奈何求其本，若拔大木根。',96,'御定全唐詩/json/820.json','["真我性無主，誰為塵識昏。奈何求其本，若拔大木根。", "妄以一念動，勢如千波翻。傷哉子桑扈，蟲臂徒虛言。", "神威興外論，宗邪生異源。空何妨色在，妙豈廢身存。", "寂滅本非寂，喧嘩曾未喧。嗟嗟世上禪，不共智者論。"]'),
('yuding-54','支公詩','皎然','唐','御定全唐诗','yuding','','[]','支公養馬複養鶴，率性無機多脫略。天生支公與凡異，',24,'御定全唐詩/json/820.json','["支公養馬複養鶴，率性無機多脫略。天生支公與凡異，"]'),
('yuding-55','述夢','皎然','唐','御定全唐诗','yuding','','[]','夢中歸見西陵雪，渺渺茫茫行路絕。覺來還在剡東峰，',24,'御定全唐詩/json/820.json','["夢中歸見西陵雪，渺渺茫茫行路絕。覺來還在剡東峰，"]'),
('yuding-56','赤松','皎然','唐','御定全唐诗','yuding','','[]','緣岸蒙籠出見天，晴沙瀝瀝水濺濺。',32,'御定全唐詩/json/820.json','["緣岸蒙籠出見天，晴沙瀝瀝水濺濺。", "何處羽人長洗藥，殘花無數逐流泉。"]'),
('yuding-57','戲題松樹','皎然','唐','御定全唐诗','yuding','','[]','為愛松聲聽不足，每逢松樹遂忘還。',32,'御定全唐詩/json/820.json','["為愛松聲聽不足，每逢松樹遂忘還。", "翛然此外更何事，笑向閑雲似我閑。"]'),
('yuding-58','戲題二首','皎然','唐','御定全唐诗','yuding','','[]','看飲逢歌日屢曛，我身何似系浮雲。',64,'御定全唐詩/json/820.json','["看飲逢歌日屢曛，我身何似系浮雲。", "時人不解野僧意，歸去溪頭作鳥群。", "喧喧共在是非間，終日誰知我自閑。", "偶客狂歌何所為，欲于人事強相關。"]'),
('yuding-59','雜寓興','皎然','唐','御定全唐诗','yuding','','[]','嗟嗟號呶子，世稱謫仙儔。媚俗被鮫綃，欺天薦昫修。',120,'御定全唐詩/json/820.json','["嗟嗟號呶子，世稱謫仙儔。媚俗被鮫綃，欺天薦昫修。", "奔景謂可致，馳齡言易流。燕昭昧往事，嬴政亡前籌。", "三山果不見，九仙忽悠悠。君看牛山樂，君見麋浦遊。", "昨日千金子，聯綿成古丘。吾將攬明月，照爾生死流。", "至樂享爰居，慚貽達者尤。冥冥光塵內，機喪成海漚。"]'),
('yuding-60','雜興六首','皎然','唐','御定全唐诗','yuding','','[]','吾觀談天客，工言喪其精。萬物資廣庇，此中何有情。',236,'御定全唐詩/json/820.json','["吾觀談天客，工言喪其精。萬物資廣庇，此中何有情。", "若為昧顏蹠，修短怨太清。高論讓鄒子，放詞征屈生。", "請從象外推，至論尤明明。", "短齡役長世，擾擾悟不早。嬪女身後空，歡娛夢中好。", "從教西陵樹，千載傷懷抱。鶴駕何冥冥，鼇洲去浩浩。", "柔顏感三花，凋發悲蔓草。月中伐桂人是誰，", "誰高齊公子，泣聽雍門琴。死且何足傷，殊非達人心。", "獨高庭中鶴，意遠貴氛埃。有時青冥游，顧我還下來。", "白雲琅玕色，一片生虛無。此物若無心，若何卷還舒。", "疏散遂吾性，棲山更無機。寥寥高松下，獨有閑雲歸。", "精意不可道，冥然還掩扉。"]'),
('yuding-61','偶然五首','皎然','唐','御定全唐诗','yuding','','[]','樂禪心似蕩，吾道不相妨。獨悟歌還笑，誰言老更狂。',132,'御定全唐詩/json/820.json','["樂禪心似蕩，吾道不相妨。獨悟歌還笑，誰言老更狂。", "偶然寂無喧，吾了心性源。可嫌蟲食木，不笑鳥能言。", "隱心不隱跡，卻欲住人寰。欠樹移春樹，無山看畫山。", "居喧我未錯，真意在其間。", "虜語嫌不學，胡音從不翻。說禪顛倒是，樂殺金王孫。", "真隱須無矯，忘名要似愚。只將兩條事，空卻漢潛夫。"]'),
('yuding-62','問天','皎然','唐','御定全唐诗','yuding','','[]','天公何時有，談者皆不經。誰道賢人死，今為傅說星。',24,'御定全唐詩/json/820.json','["天公何時有，談者皆不經。誰道賢人死，今為傅說星。"]'),
('yuding-63','寓言','皎然','唐','御定全唐诗','yuding','','[]','吾道本無我，未曾嫌世人。如今到城市，彌覺此心真。',24,'御定全唐詩/json/820.json','["吾道本無我，未曾嫌世人。如今到城市，彌覺此心真。"]'),
('yuding-64','前溪作','皎然','唐','御定全唐诗','yuding','','[]','春歌已寂寂，古水自涓涓。徒誤時人輩，傷心作逝川。',24,'御定全唐詩/json/820.json','["春歌已寂寂，古水自涓涓。徒誤時人輩，傷心作逝川。"]'),
('yuding-65','戲作','皎然','唐','御定全唐诗','yuding','','[]','乞我百萬金，封我異姓王。不如獨悟時，大笑放清狂。',24,'御定全唐詩/json/820.json','["乞我百萬金，封我異姓王。不如獨悟時，大笑放清狂。"]'),
('yuding-66','浮雲三章','皎然','唐','御定全唐诗','yuding','','[]','浮雲浮雲，集於扶桑。扶桑茫茫，日暮之光。',120,'御定全唐詩/json/820.json','["浮雲浮雲，集於扶桑。扶桑茫茫，日暮之光。", "匪日之暮，浮雲之汙。嗟我懷人，猶心如蠹。", "浮雲浮雲，集于咸池。咸池微微，日昃之時。", "匪日之昃，浮雲之惑。嗟我懷人，憂心如織。", "浮雲浮雲，集于高舂。高舂濛濛，日夕之容。", "匪日之夕，浮雲之積。嗟我懷人，憂心如惄。"]'),
('yuding-67','寓言','皎然','唐','御定全唐诗','yuding','','[]','人生百年我過半，天生才定不可換。',32,'御定全唐詩/json/820.json','["人生百年我過半，天生才定不可換。", "東海釣鼇鼇不食，南山坐石石欲爛。"]'),
('yuding-68','若邪春興','皎然','唐','御定全唐诗','yuding','','[]','春生若邪水，雨後漫流通。芳草行無盡，清源去不窮。',48,'御定全唐詩/json/820.json','["春生若邪水，雨後漫流通。芳草行無盡，清源去不窮。", "野煙迷極浦，斜日起微風。數處乘流望，依稀似剡中。"]'),
('yuding-69','晨登樂游原，望終南積雪','皎然','唐','御定全唐诗','yuding','','[]','淩晨擁弊裘，徑上古原頭。雪霽山疑近，天高思若浮。',72,'御定全唐詩/json/820.json','["淩晨擁弊裘，徑上古原頭。雪霽山疑近，天高思若浮。", "瓊峰埋積翠，玉嶂掩飛流。曜彩含朝日，搖光奪寸眸。", "寒空標瑞色，爽氣襲皇州。清眺何人得，終當獨再遊。"]'),
('yuding-70','送商季皋','皎然','唐','御定全唐诗','yuding','','[]','比來知爾有詩名，莫恨東歸學未成。',32,'御定全唐詩/json/820.json','["比來知爾有詩名，莫恨東歸學未成。", "新豐有酒為我飲，消取故園傷別情。"]'),
('yuding-0','吊靈均詞','皎然','唐','御定全唐诗','yuding','','[]','昧天道兮有無，聽汨渚兮躊躇。期靈均兮若存，',67,'御定全唐詩/json/821.json','["昧天道兮有無，聽汨渚兮躊躇。期靈均兮若存，", "天獨何兮有君，君在萬兮不群。既冰心兮皎潔，", "風激烈兮楚竹死，國殤人悲兮雨颸颸。雨颸颸兮望君時，"]'),
('yuding-1','步虛詞','皎然','唐','御定全唐诗','yuding','','[]','予因覽真訣，遂感西城君。玉笙下青冥，人間未曾聞。',72,'御定全唐詩/json/821.json','["予因覽真訣，遂感西城君。玉笙下青冥，人間未曾聞。", "日華煉精魄，皎皎無垢氛。謂我有仙骨，且令餌氤氳。", "俯仰愧靈顏，願隨鸞鵠群。俄然動風馭，縹渺歸青雲。"]'),
('yuding-2','奉應顏尚書真卿觀玄真子置酒張樂舞破陣畫洞庭三山歌','皎然','唐','御定全唐诗','yuding','','[]','道流跡異人共驚，寄向畫中觀道情。如何萬象自心出，',96,'御定全唐詩/json/821.json','["道流跡異人共驚，寄向畫中觀道情。如何萬象自心出，", "石文亂點急管催，雲態徐揮慢歌發。樂縱酒酣狂更好，", "盻睞方知造境難，象忘神遇非筆端。昨日幽奇湖上見，", "秋空暮景颯颯容，翻疑是真畫不得。顏公素高山水意，"]'),
('yuding-3','答韋山人隱起龍文藥瓢歌','皎然','唐','御定全唐诗','yuding','','[]','野人藥瓢天下絕，全如渾金割如月。彪炳文章智使然，',96,'御定全唐詩/json/821.json','["野人藥瓢天下絕，全如渾金割如月。彪炳文章智使然，", "韋生能詩兼好異，獲此靈瓢遠相遺。仙侯玉帖人漫傳，", "背上驪龍蟠不睡，張鱗擺頷生風雲。世人強知金丹道，", "聊將系肘步何輕，便有三山孤鶴情。東方小兒乏此物，"]'),
('yuding-4','桃花石枕歌贈康從事','皎然','唐','御定全唐诗','yuding','','[]','卞山幽石產奇璞，荊人至死采不著。何人琢枕持贈君，',96,'御定全唐詩/json/821.json','["卞山幽石產奇璞，荊人至死采不著。何人琢枕持贈君，", "至寶由來覽者稀，今君獨鑒應欲惜。何辭售與章天真，", "四座喧喧爭目悅，巧過造化稱一絕。莫言昨日因錯磨，", "高窗正午風颯變，室中不減春天寒。主人所重重枕德，"]'),
('yuding-5','張伯英草書歌','皎然','唐','御定全唐诗','yuding','','[]','伯英死後生伯高，朝看手把山中毫。先賢草律我草狂，',96,'御定全唐詩/json/821.json','["伯英死後生伯高，朝看手把山中毫。先賢草律我草狂，", "閬風遊雲千萬朵，驚龍蹴踏飛欲墮。更睹鄧林花落朝，", "有時取勢氣更高，憶得春江千里濤。張生奇絕難再遇，", "黃公酒壚興偏入，阮籍不嗔嵇亦顧。長安酒榜醉後書，"]'),
('yuding-6','寒棲子歌','皎然','唐','御定全唐诗','yuding','','[]','君在廬山知不群，有疑是鶴又是雲。生死塵埃汙不得，',112,'御定全唐詩/json/821.json','["君在廬山知不群，有疑是鶴又是雲。生死塵埃汙不得，", "拂除衣上餌煙霞，昨夜胥門宿蔡家。天然不飲亦不食，", "停形為餌天地根，世人皆死我獨存。洗慮因吞清明籙，", "能令鬼哭神效靈，身如飄風不可絆。朝遊崆峒夕汗漫，", "海上仙遊不可見，人間日落空桑枝。"]'),
('yuding-7','翔隼歌送王端公','皎然','唐','御定全唐诗','yuding','','[]','古人賞神駿，何如秋隼擊。獨立高標望霜翮，',68,'御定全唐詩/json/821.json','["古人賞神駿，何如秋隼擊。獨立高標望霜翮，", "晴空四顧忽不見，有時獨出青霞傍。窮陰萬里落寒日，", "見君高情有所屬，贈別因歌翔隼曲。離亭慘慘客散時，"]'),
('yuding-8','白雲歌寄陸中丞使君長源','皎然','唐','御定全唐诗','yuding','','[]','一見西山雲，使人情意遠。憑高發詠何超遙，',112,'御定全唐詩/json/821.json','["一見西山雲，使人情意遠。憑高發詠何超遙，", "潔白不由陰雨積，高明肯共雜煙重。萬物有形皆有著，", "或逢天上或人間，人自營營雲自閑。忽爾飛來暫為侶，", "白雲遇物無偏頗，自是人心見同異。閶闔天門宜曙看，", "誰憐西山雲，亭亭處幽絕。坐石長看非我羈，"]'),
('yuding-9','裴端公使君清席，賦得青桂歌送徐長史','皎然','唐','御定全唐诗','yuding','','[]','昔年攀桂為留人，今朝攀桂送歸客。秋風桃李搖落盡，',48,'御定全唐詩/json/821.json','["昔年攀桂為留人，今朝攀桂送歸客。秋風桃李搖落盡，", "應憐獨秀空林上，空賞敷華積雪間。昨夜一枝生在月，"]'),
('yuding-10','周長史昉畫毗沙門天王歌','皎然','唐','御定全唐诗','yuding','','[]','長史畫神獨感神，高步區中無兩人。雅而逸，高且真，',88,'御定全唐詩/json/821.json','["長史畫神獨感神，高步區中無兩人。雅而逸，高且真，", "慈威示物雖凜凜，在德無秋唯有春。吾知真象本非色，", "寫出霜縑可舒卷，何人應識此情遠。秋齋清寂無外物，", "至今雲旗圖我形，為君一顧煙塵清。"]'),
('yuding-11','奉和顏魯公真卿落玄真子舴艋舟歌','皎然','唐','御定全唐诗','yuding','','[]','滄浪子後玄真子，冥冥釣隱江之汜。刳木新成舴艋舟，',73,'御定全唐詩/json/821.json','["滄浪子後玄真子，冥冥釣隱江之汜。刳木新成舴艋舟，", "從水遠逝兮任風還，朝五湖兮夕三山。停綸乍入芙蓉浦，", "竹竿嫋嫋魚簁簁，此中自得還自笑。汗漫一游何可期，"]'),
('yuding-12','鄭容全成蛟形木機歌','皎然','唐','御定全唐诗','yuding','','[]','萬物貴天然，天然不可得。渾樸無勞剞劂工，',92,'御定全唐詩/json/821.json','["萬物貴天然，天然不可得。渾樸無勞剞劂工，", "可中風雨一朝至，還應不是池中物。蒼山萬重采一枝，", "高人心，多越格。有時就月吟春風，持來座右驚神客。", "愛君開合江之濱，白雲黃鶴長相親。南郭子綦我不識，"]'),
('yuding-13','奉同顏使君真卿清風樓賦得洞庭歌送吳煉師歸林屋洞','皎然','唐','御定全唐诗','yuding','','[]','名山洞府到金庭，三十六洞稱最靈。不有古仙啟其秘，',96,'御定全唐詩/json/821.json','["名山洞府到金庭，三十六洞稱最靈。不有古仙啟其秘，", "三千甲子朝玉帝，世上如今名始聞。吐納青牙養肌發，", "吳興太守道家流，仙師遠放清風樓。應將內景還飛去，", "世人不到君自到，縹緲仙都誰與儔。黃鶴孤雲天上物，"]'),
('yuding-14','戛銅碗為龍吟歌','皎然','唐','御定全唐诗','yuding','','[]','逸僧戛碗為龍吟，世上未曾聞此音。一從太尉房公賞，',112,'御定全唐詩/json/821.json','["逸僧戛碗為龍吟，世上未曾聞此音。一從太尉房公賞，", "似出龍泉萬丈底，乍怪聲來近而遠。未必全由戛者功，", "遙聞不斷在煙杪，萬籟無聲天境空。乍向天臺宿華頂，", "今日鏗鍠江上聞，蛟螭奔飛如得群。聲過陰嶺恐成雨，", "人生萬事將此同，暮賤朝榮動還寂。"]'),
('yuding-15','飲茶歌誚崔石使君','皎然','唐','御定全唐诗','yuding','','[]','越人遺我剡溪茗，采得金牙爨金鼎。素瓷雪色縹沫香，',68,'御定全唐詩/json/821.json','["越人遺我剡溪茗，采得金牙爨金鼎。素瓷雪色縹沫香，", "再飲清我神，忽如飛雨灑輕塵。三飲便得道，", "愁看畢卓甕間夜，笑向陶潛籬下時。崔侯啜之意不已，"]'),
('yuding-16','買藥歌送楊山人','皎然','唐','御定全唐诗','yuding','','[]','華陰少年何所希，欲餌丹砂化骨飛。江南藥少淮南有，',72,'御定全唐詩/json/821.json','["華陰少年何所希，欲餌丹砂化骨飛。江南藥少淮南有，", "夜驚潮沒鸕鷀堰，朝看日出芙蓉樓。搖盪春風亂帆影，", "河間姹女直千金，紫陽夫人服不死。吾於此道複何如，"]'),
('yuding-17','薛卿教長行歌','皎然','唐','御定全唐诗','yuding','','[]','桂陽仙柳道家說，昔傳蘇君今是薛。聊將握槊偶時人，',96,'御定全唐詩/json/821.json','["桂陽仙柳道家說，昔傳蘇君今是薛。聊將握槊偶時人，", "初疑月破雲中墮，複怪星移指下攢。誰識兵奇勢可保，", "鳧驚隼擊疾若飛，左顧右盻生光輝。家本聯姻漢戚裏，", "扈游長樂與祈年，人望青雲白日邊。謫宦江南歲陰晚，"]'),
('yuding-18','桃花石枕歌送安吉康丞','皎然','唐','御定全唐诗','yuding','','[]','君吏桃州尚奇跡，桃州采得桃花石。爛疑朝日照已舒，',72,'御定全唐詩/json/821.json','["君吏桃州尚奇跡，桃州采得桃花石。爛疑朝日照已舒，", "應羨花開不凋悴，應嘉玉片無緇磷。立性堅剛平若砥，", "君心所好我獨知，別多見少長相思。從來賞玩安左右，"]'),
('yuding-19','賦得吳王送女潮歌，送李判官之河中府','皎然','唐','御定全唐诗','yuding','','[]','見說吳王送女時，行宮直到荊溪口。溪上千年送女潮，',88,'御定全唐詩/json/821.json','["見說吳王送女時，行宮直到荊溪口。溪上千年送女潮，", "平波忽起二三尺，此上疑與神仙宅。今人猶望荊之湄，", "溪草何草號帝女，溪竹何竹號湘妃。靈濤旦暮自堪傷，", "不知別後相見期，君意何如此潮水。"]'),
('yuding-20','觀李中丞洪二美人唱歌軋箏歌','皎然','唐','御定全唐诗','yuding','','[]','君家雙美姬，善歌工箏人莫知。軋用蜀竹弦楚絲，',140,'御定全唐詩/json/821.json','["君家雙美姬，善歌工箏人莫知。軋用蜀竹弦楚絲，", "美人矜名曲不誤，蹙響時時如迸泉。趙琴素所嘉，", "淫聲已闋雅聲來，遊魚噞喁鶴裴回。主人高情始為開，", "文章已冠諸人籍。每笑石崇無道情，輕身重色禍亦成。", "君有佳人當禪伴，於中不廢學無生。愛君天然性寡欲，", "不意全家萬里來，湖中再見春山綠。吳興公舍幽且閑，"]'),
('yuding-21','陳氏童子草書歌','皎然','唐','御定全唐诗','yuding','','[]','書家孺子有奇名，天然大草令人驚。僧虔老時把筆法，',88,'御定全唐詩/json/821.json','["書家孺子有奇名，天然大草令人驚。僧虔老時把筆法，", "有時作點險且能，太行片石看欲崩。偶然長掣濃入燥，", "桐花飛盡子規思，主人高歌興不至。濁醪不飲嫌昏沈，", "王家小令草最狂，為予灑出驚騰勢。"]'),
('yuding-22','飲茶歌送鄭容','皎然','唐','御定全唐诗','yuding','','[]','丹丘羽人輕玉食，採茶飲之生羽翼。名藏仙府世空知，',48,'御定全唐詩/json/821.json','["丹丘羽人輕玉食，採茶飲之生羽翼。名藏仙府世空知，", "霜天半夜芳草折，爛漫緗花啜又生。賞君此茶祛我疾，"]'),
('yuding-23','花石長枕歌答章居士贈','皎然','唐','御定全唐诗','yuding','','[]','楚山有石郢人琢，琢成長枕知是玉。全疑冰片坐恐銷，',72,'御定全唐詩/json/821.json','["楚山有石郢人琢，琢成長枕知是玉。全疑冰片坐恐銷，", "吾師道吾不執寶，今日感君因執看。試叩鏗然應清律，", "南山有雲鵠在空，長松為我生涼風。高友朗詠樂其中，"]'),
('yuding-24','觀王右丞維滄洲圖歌','皎然','唐','御定全唐诗','yuding','','[]','滄洲誤是真，萋萋忽盈視。便有春渚情，褰裳掇芳芷。',72,'御定全唐詩/json/821.json','["滄洲誤是真，萋萋忽盈視。便有春渚情，褰裳掇芳芷。", "颯然風至草不動，始悟丹青得如此。丹青變化不可尋，", "滄洲說近三湘口，誰知卷得在君手。披圖擁褐臨水時，"]'),
('yuding-25','洞庭山維諒上人院階前孤生橘樹歌','皎然','唐','御定全唐诗','yuding','','[]','洞庭仙山但生橘，不生凡木與梨栗。真子無私自不栽，',96,'御定全唐詩/json/821.json','["洞庭仙山但生橘，不生凡木與梨栗。真子無私自不栽，", "若言此物無道性，何意孤生來就人。二月三月山初暖，", "九月十月爭破顏，金實離離色殷殷，一夜天晴香滿山。", "天生珍木異於俗，俗士來逢不敢觸。清陰獨步禪起時，"]'),
('yuding-26','春夜賦得漉水囊歌，送鄭明府','皎然','唐','御定全唐诗','yuding','','[]','吳縑楚練何白皙，居士持來遺禪客。禪客能裁漉水囊，',72,'御定全唐詩/json/821.json','["吳縑楚練何白皙，居士持來遺禪客。禪客能裁漉水囊，", "夕望東峰思漱盥，曨曨斜月懸燈紗。徙倚花前漏初斷，", "因識仁人為宦情，還如漉水愛蒼生。聊歌一曲與君別，"]'),
('yuding-27','湛處士枸杞架歌','皎然','唐','御定全唐诗','yuding','','[]','天生靈草生靈地，誤生人間人不貴。獨君井上有一根，',88,'御定全唐詩/json/821.json','["天生靈草生靈地，誤生人間人不貴。獨君井上有一根，", "春風亦解愛此物，嫋嫋時來傍香實。濕雲綴葉擺不去，", "我獨全生異此輩，順時榮落不相背。孤松自被斧斤傷，", "擷芳生影風灑懷，其致翛然此中足。"]'),
('yuding-28','觀裴秀才松石障歌','皎然','唐','御定全唐诗','yuding','','[]','誰工此松唯拂墨，巧思丹青營不得。初寫松梢風正生，',72,'御定全唐詩/json/821.json','["誰工此松唯拂墨，巧思丹青營不得。初寫松梢風正生，", "左右雙松更奇絕，龍鱗麈尾仍半折。經春寒色聚不散，", "何年蒨蒨苔黏跡，幾夜潺潺水擊痕。裴生詩家後來客，"]'),
('yuding-29','送顧處士歌','皎然','唐','御定全唐诗','yuding','','[]','吳門顧子予早聞，風貌真古誰似君。人中黃憲與顏子，',88,'御定全唐詩/json/821.json','["吳門顧子予早聞，風貌真古誰似君。人中黃憲與顏子，", "醉書在篋稱絕倫，神畫開廚怕飛出。謝氏檀郎亦可儔，", "知君別業長洲外，欲行秋田循畎澮。門前便取觳觫乘，", "滿道喧喧遇君別，爭窺玉潤與冰清。"]'),
('yuding-30','水精數珠歌','皎然','唐','御定全唐诗','yuding','','[]','西方真人為行密，臂上記珠皎如日。佛名無著心亦空，',24,'御定全唐詩/json/821.json','["西方真人為行密，臂上記珠皎如日。佛名無著心亦空，"]'),
('yuding-31','兵後西日溪行','皎然','唐','御定全唐诗','yuding','','[]','一從清氣上為天，仙叟何年見幹海。黃河幾度濁複清，',88,'御定全唐詩/json/821.json','["一從清氣上為天，仙叟何年見幹海。黃河幾度濁複清，", "風吹花片使我迷，時時問山驚踏雪。石樑丹灶意更奇，", "路是武陵路，人非秦代人。飯松得高侶，濯足偶清津。", "數片昔賢磐石在，幾回並坐戴綸巾。"]'),
('yuding-32','姑蘇行','皎然','唐','御定全唐诗','yuding','','[]','古台不見秋草衰，卻憶吳王全盛時。千年月照秋草上，',48,'御定全唐詩/json/821.json','["古台不見秋草衰，卻憶吳王全盛時。千年月照秋草上，", "山中精靈安可睹，轍跡人蹤麋鹿聚。嬋娟西子傾國容，"]'),
('yuding-33','短歌行','皎然','唐','御定全唐诗','yuding','','[]','古人若不死，吾亦何所悲。蕭蕭煙雨九原上，',56,'御定全唐詩/json/821.json','["古人若不死，吾亦何所悲。蕭蕭煙雨九原上，", "人生在世共如此，何異浮雲與流水。短歌行，", "何為不學金仙侶，一悟空王無死生。"]'),
('yuding-34','山月行','皎然','唐','御定全唐诗','yuding','','[]','家家望秋月，不及秋山望。山中萬境長寂寥，',44,'御定全唐詩/json/821.json','["家家望秋月，不及秋山望。山中萬境長寂寥，", "憂虞歡樂皆占月，月本無心同不同。自從有月山不改，"]'),
('yuding-35','顧渚行寄裴方舟','皎然','唐','御定全唐诗','yuding','','[]','我有雲泉鄰渚山，山中茶事頗相關。鶗鴂鳴時芳草死，',112,'御定全唐詩/json/821.json','["我有雲泉鄰渚山，山中茶事頗相關。鶗鴂鳴時芳草死，", "由來慣采無近遠，陰嶺長兮陽崖淺。大寒山下葉未生，", "迷山乍被落花亂，度水時驚啼鳥飛。家園不遠乘露摘，", "昨夜西峰雨色過，朝尋新茗複如何。女宮露澀青芽老，", "清泠真人待子元，貯此芳香思何極。"]'),
('yuding-36','武源行贈丘卿岑','皎然','唐','御定全唐诗','yuding','','[]','昔年群盜阻江東，吳山動搖楚澤空。齊人亦戴蜂蠆毒，',136,'御定全唐詩/json/821.json','["昔年群盜阻江東，吳山動搖楚澤空。齊人亦戴蜂蠆毒，", "萬人死地當虎口，一旦生涯懸彀中。昨日將軍殉死節，", "長洲南去接孤城，居人散盡鼓噪驚。三春不見芳草色，", "縱橫計出皆獲全，士卒身先每輕死。掃平氛祲望吳門，", "如何棄置功不錄，通籍無名滯江曲。灞亭不重李將軍，", "野戰攻城盡如此，即今誰是霍嫖姚。"]'),
('yuding-37','長安少年行','皎然','唐','御定全唐诗','yuding','','[]','翠樓春酒蝦蟆陵，長安少年皆共矜。',32,'御定全唐詩/json/821.json','["翠樓春酒蝦蟆陵，長安少年皆共矜。", "紛紛半醉綠槐道，躞蹀花驄驕不勝。"]'),
('yuding-38','風入松','皎然','唐','御定全唐诗','yuding','','[]','西嶺松聲落日秋，千枝萬葉風飀飀。美人援琴弄成曲，',64,'御定全唐詩/json/821.json','["西嶺松聲落日秋，千枝萬葉風飀飀。美人援琴弄成曲，", "攪寒松兮又夜起。夜未央，曲何長，金徽更促聲泱泱。", "何人此時不得意，意苦弦悲聞客堂。"]'),
('yuding-39','陪盧中丞閒遊山寺','皎然','唐','御定全唐诗','yuding','','[]','野寺出人境，舍舟登遠峰。林開明見月，萬壑靜聞鐘。',48,'御定全唐詩/json/821.json','["野寺出人境，舍舟登遠峰。林開明見月，萬壑靜聞鐘。", "擁燭明山翠，交麾動水容。如何股肱守，塵外得相逢。"]'),
('yuding-40','湖南草堂讀書招李少府','皎然','唐','御定全唐诗','yuding','','[]','削去僧家事，南池便隱居。為憐松子壽，還蔔道家書。',48,'御定全唐詩/json/821.json','["削去僧家事，南池便隱居。為憐松子壽，還蔔道家書。", "藥院常無客，茶樽獨對餘。有時招逸史，來飯野中蔬。"]'),
('yuding-41','答李季蘭','皎然','唐','御定全唐诗','yuding','','[]','天女來相試，將花欲染衣。禪心竟不起，還捧舊花歸。',24,'御定全唐詩/json/821.json','["天女來相試，將花欲染衣。禪心竟不起，還捧舊花歸。"]'),
('yuding-42','酬鄭判官湖上見贈','皎然','唐','御定全唐诗','yuding','','[]','歲歲湖南隱已成，如何星使忽知名。',32,'御定全唐詩/json/821.json','["歲歲湖南隱已成，如何星使忽知名。", "沙鷗慣識無心客，今日逢君不解驚。"]'),
('yuding-43','送旻上人遊天臺','皎然','唐','御定全唐诗','yuding','','[]','真心不廢別，試看越溪清。知汝機忘盡，春山自有情。',48,'御定全唐詩/json/821.json','["真心不廢別，試看越溪清。知汝機忘盡，春山自有情。", "月思華頂宿，雲愛石門行。海近應須泛，無令鷗鷺驚。"]'),
('yuding-44','送別','皎然','唐','御定全唐诗','yuding','','[]','聞說情人怨別情，霜天淅瀝在寒城。',32,'御定全唐詩/json/821.json','["聞說情人怨別情，霜天淅瀝在寒城。", "長宵漫漫角聲發，禪子無心恨亦生。"]'),
('yuding-45','與昂上人兩字繼合四句初字日','皎然','唐','御定全唐诗','yuding','','[]','有一鳥雛，淩寒獨宿。若逢雲雨，兩兩相逐。',20,'御定全唐詩/json/821.json','["有一鳥雛，淩寒獨宿。若逢雲雨，兩兩相逐。"]'),
('yuding-46','次日','皎然','唐','御定全唐诗','yuding','','[]','野外有一人，獨立無四鄰。彼見是我身，我見是彼身。',24,'御定全唐詩/json/821.json','["野外有一人，獨立無四鄰。彼見是我身，我見是彼身。"]'),
('yuding-0','皇太子頻賜存問，並索唱和新詩，因有陳謝','廣宣','唐','御定全唐诗','yuding','','[]','望苑招延後，禪扉訪道餘。祗言俟文雅，何意及庸虛。',96,'御定全唐詩/json/822.json','["望苑招延後，禪扉訪道餘。祗言俟文雅，何意及庸虛。", "率性多非學，緣情偶自書。清風聞寺響，白日見心初。", "重道逢軒後，崇儒過魏儲。青宮列芳梓，玄圃積瓊琚。", "鄭鼠甯容者，齊竽久舍諸。空懷受恩感，含思幾躊躇。"]'),
('yuding-1','禁中法會應制','廣宣','唐','御定全唐诗','yuding','','[]','天上萬年枝，人間不可窺。道場三教會，心地百王期。',72,'御定全唐詩/json/822.json','["天上萬年枝，人間不可窺。道場三教會，心地百王期。", "侍讀沾恩早，傳香駐日遲。在筵還向道，通籍許言詩。", "空愧陪仙列，何階答聖慈。從今精至理，長願契無為。"]'),
('yuding-2','降誕日內庭獻壽應制','廣宣','唐','御定全唐诗','yuding','','[]','慶壽千齡遠，敷仁萬國通。登霄欣有路，捧日愧無功。',72,'御定全唐詩/json/822.json','["慶壽千齡遠，敷仁萬國通。登霄欣有路，捧日愧無功。", "仙駕三山上，龍生二月中。修齋長樂殿，講道大明宮。", "此地人難到，諸天事不同。法筵花散後，空界滿香風。"]'),
('yuding-3','寺中柿樹一蒂四顆詠應制','廣宣','唐','御定全唐诗','yuding','','[]','珍木生奇畝，低枝拂梵宮。因開四界分，本自百花中。',48,'御定全唐詩/json/822.json','["珍木生奇畝，低枝拂梵宮。因開四界分，本自百花中。", "當夏陰涵綠，臨秋色變紅。君看藥草喻，何減太陽功。"]'),
('yuding-4','早秋降誕日獻壽二首應制','廣宣','唐','御定全唐诗','yuding','','[]','秋蓂開六葉，元聖誕千年。繞殿祥風起，當空瑞日懸。',96,'御定全唐詩/json/822.json','["秋蓂開六葉，元聖誕千年。繞殿祥風起，當空瑞日懸。", "道光中國主，人識大羅仙。敢贊無疆壽，香花上法筵。", "萬方瞻聖日，九土仰清光。磬地山河壯，彌天福壽長。", "瑞煙熏法界，真偈啟仁王。看獻千秋樂，千秋樂未央。"]'),
('yuding-5','駕幸天長寺應制','廣宣','唐','御定全唐诗','yuding','','[]','天界宜春賞，禪門不掩關。宸游雙闕外，僧引百花間。',48,'御定全唐詩/json/822.json','["天界宜春賞，禪門不掩關。宸游雙闕外，僧引百花間。", "車馬喧長路，煙雲淨遠山。觀空複觀俗，皇鑒此中閑。"]'),
('yuding-6','九月菊花詠應制','廣宣','唐','御定全唐诗','yuding','','[]','可訝東籬菊，能知節候芳。細枝青玉潤，繁蕊碎金香。',48,'御定全唐詩/json/822.json','["可訝東籬菊，能知節候芳。細枝青玉潤，繁蕊碎金香。", "爽氣浮朝露，濃姿帶夜霜。泛杯傳壽酒，應共樂時康。"]'),
('yuding-7','駕幸聖容院應制','廣宣','唐','御定全唐诗','yuding','','[]','大唐國裏千年聖，王舍城中百億身。卻指容顏非我相，',40,'御定全唐詩/json/822.json','["大唐國裏千年聖，王舍城中百億身。卻指容顏非我相，", "古來貴重緣親近，狂客慚為侍從臣。"]'),
('yuding-8','聖恩顧問，獨游月磴閣，直書其事應制','廣宣','唐','御定全唐诗','yuding','','[]','禪居河畔無多地，來往尋春物正華。磴道上盤千畝竹，',40,'御定全唐詩/json/822.json','["禪居河畔無多地，來往尋春物正華。磴道上盤千畝竹，", "自解刹那知佛性，不勞更喻幾塵沙。"]'),
('yuding-9','安國寺隨駕幸興唐觀應制','廣宣','唐','御定全唐诗','yuding','','[]','東林何殿是西鄰，禪客垣牆接羽人。萬乘游仙宗有道，',40,'御定全唐詩/json/822.json','["東林何殿是西鄰，禪客垣牆接羽人。萬乘游仙宗有道，", "兩地盡修天上事，共瞻鑾駕重來巡。"]'),
('yuding-10','賀王起','廣宣','唐','御定全唐诗','yuding','','[]','從辭鳳閣掌絲綸，便向青雲領貢賓。再辟文場無枉路，',40,'御定全唐詩/json/822.json','["從辭鳳閣掌絲綸，便向青雲領貢賓。再辟文場無枉路，", "明日定歸台席去，鶺鴒原上共陶鈞。"]'),
('yuding-11','賀幸普濟寺應制','廣宣','唐','御定全唐诗','yuding','','[]','南方寶界幾由旬，八部同瞻一佛身。寺壓山河天宇靜，',40,'御定全唐詩/json/822.json','["南方寶界幾由旬，八部同瞻一佛身。寺壓山河天宇靜，", "向晚鑾輿歸鳳闕，曲江池上動青蘋。"]'),
('yuding-12','紅樓院應制','廣宣','唐','御定全唐诗','yuding','','[]','紅樓疑見白毫光，寺逼宸居福盛唐。支遁愛山情謾切，',40,'御定全唐詩/json/822.json','["紅樓疑見白毫光，寺逼宸居福盛唐。支遁愛山情謾切，", "誰道此中難可到，自憐深院得徊翔。"]'),
('yuding-13','再入道場紀事應制','廣宣','唐','御定全唐诗','yuding','','[]','南方歸去再生天，內殿今年異昔年。見辟乾坤新定位，',40,'御定全唐詩/json/822.json','["南方歸去再生天，內殿今年異昔年。見辟乾坤新定位，", "自喜恩深陪侍從，兩朝長在聖人前。"]'),
('yuding-14','寺中賞花應制','廣宣','唐','御定全唐诗','yuding','','[]','東風萬里送香來，上界千花向日開。',32,'御定全唐詩/json/822.json','["東風萬里送香來，上界千花向日開。", "卻笑霞樓紫芝侶，桃源深洞訪仙才。"]'),
('yuding-15','九月十五日夜宿鄭尚書絪東亭，望月寄杜給事','廣宣','唐','御定全唐诗','yuding','','[]','霜天晴夜宿東齋，松竹交陰愜素懷。迥出風塵心得地，',40,'御定全唐詩/json/822.json','["霜天晴夜宿東齋，松竹交陰愜素懷。迥出風塵心得地，", "霄漢路殊從道合，往來人事不相乖。"]'),
('yuding-0','酬盧仝見訪不遇題壁','含曦','唐','御定全唐诗','yuding','','[]','長壽寺石壁，盧公一首詩。渴讀即不渴，饑讀即不饑。',44,'御定全唐詩/json/823.json','["長壽寺石壁，盧公一首詩。渴讀即不渴，饑讀即不饑。", "鯨吞海水盡，露出珊瑚枝。海神知貴不知價，"]'),
('yuding-1','旅中答喻軍事問客情','善生','唐','御定全唐诗','yuding','','[]','一自遊他國，相逢少故人。縱然為客樂，爭似在家貧。',48,'御定全唐詩/json/823.json','["一自遊他國，相逢少故人。縱然為客樂，爭似在家貧。", "畜恨霜侵鬢，搜詩病入神。若非憐片善，誰肯問風塵。"]'),
('yuding-2','贈盧逸人','善生','唐','御定全唐诗','yuding','','[]','高眠岩野間，至藝敵應難。詩苦無多首，藥靈惟一丸。',48,'御定全唐詩/json/823.json','["高眠岩野間，至藝敵應難。詩苦無多首，藥靈惟一丸。", "引泉魚落釜，攀果露沾冠。已得嵇康趣，逢迎事每闌。"]'),
('yuding-3','送玉禪師','善生','唐','御定全唐诗','yuding','','[]','飄然無定跡，迥與律乘違。入郭隨緣住，思山破夏歸。',48,'御定全唐詩/json/823.json','["飄然無定跡，迥與律乘違。入郭隨緣住，思山破夏歸。", "盂擎數家飯，衲乞幾人衣。洞了曹溪旨，寧輸俗者機。"]'),
('yuding-4','送智光之南值雨','善生','唐','御定全唐诗','yuding','','[]','結束衣囊了，炎州定去遊。草堂方惜別，山雨為相留。',48,'御定全唐詩/json/823.json','["結束衣囊了，炎州定去遊。草堂方惜別，山雨為相留。", "又得一宵話，免生千里愁。莫辭重蔔日，後會必經秋。"]'),
('yuding-5','謝白樂天招','韜光','唐','御定全唐诗','yuding','','[]','山僧野性好林泉，每向岩阿倚石眠。不解栽松陪玉勒，',40,'御定全唐詩/json/823.json','["山僧野性好林泉，每向岩阿倚石眠。不解栽松陪玉勒，", "城市不能飛錫去，恐妨鶯囀翠樓前。"]'),
('yuding-6','五歲詠花','知玄','唐','御定全唐诗','yuding','','[]','花開滿樹紅，花落萬枝空。唯餘一孕在，明日定隨風。',24,'御定全唐詩/json/823.json','["花開滿樹紅，花落萬枝空。唯餘一孕在，明日定隨風。"]'),
('yuding-7','祝堯詩','知玄','唐','御定全唐诗','yuding','','[]','生天本自生天業，未必求仙便得仙。',32,'御定全唐詩/json/823.json','["生天本自生天業，未必求仙便得仙。", "鶴背傾危龍背滑，君王且住一千年。"]'),
('yuding-8','答僧澈','知玄','唐','御定全唐诗','yuding','','[]','觀君法苑思沖虛，使我真乘刃有餘。若使龍光時可待，',48,'御定全唐詩/json/823.json','["觀君法苑思沖虛，使我真乘刃有餘。若使龍光時可待，", "蕭寺講軒橫淡蕩，帝鄉雲樹正扶疏。幾生曾得闍瑜意，"]'),
('yuding-9','月夜懷劉秀才','元孚','唐','御定全唐诗','yuding','','[]','獨夜相思但自勞，阮生吟罷夢雲濤。',32,'御定全唐詩/json/823.json','["獨夜相思但自勞，阮生吟罷夢雲濤。", "此時小定未禪寂，古塔月中松磬高。"]'),
('yuding-10','送李四校書','元孚','唐','御定全唐诗','yuding','','[]','朱絲寫別鶴泠泠，詩滿紅箋月滿庭。',32,'御定全唐詩/json/823.json','["朱絲寫別鶴泠泠，詩滿紅箋月滿庭。", "莫學楚狂隳姓字，知音還有子期聽。"]'),
('yuding-11','邊思','棲白','唐','御定全唐诗','yuding','','[]','西北黃雲暮，聲聲畫角愁。陰山一夜雨，白草四郊秋。',48,'御定全唐詩/json/823.json','["西北黃雲暮，聲聲畫角愁。陰山一夜雨，白草四郊秋。", "亂雁鳴寒渡，飛沙入廢樓。何時番色盡，此地見芳洲。"]'),
('yuding-12','八月十五夜玩月','棲白','唐','御定全唐诗','yuding','','[]','尋常三五夜，不是不嬋娟。及至中秋滿，還勝別夜圓。',48,'御定全唐詩/json/823.json','["尋常三五夜，不是不嬋娟。及至中秋滿，還勝別夜圓。", "清光凝有露，皓魄爽無煙。自古人皆望，年來又一年。"]'),
('yuding-13','尋山僧真勝上人不遇','棲白','唐','御定全唐诗','yuding','','[]','松下禪棲所，苔滋徑莫分。青山春暮見，流水夜深聞。',48,'御定全唐詩/json/823.json','["松下禪棲所，苔滋徑莫分。青山春暮見，流水夜深聞。", "不坐看心石，應隨出定雲。猿猱非可問，岩穀自空曛。"]'),
('yuding-14','贈李溟秀才','棲白','唐','御定全唐诗','yuding','','[]','南居古廟深，高樹宿山禽。明月上清漢，騷人動楚吟。',48,'御定全唐詩/json/823.json','["南居古廟深，高樹宿山禽。明月上清漢，騷人動楚吟。", "數篇正始韻，一片補亡心。孤悄欺何謝，雲波不可尋。"]'),
('yuding-15','送石秀才','棲白','唐','御定全唐诗','yuding','','[]','正是歎羈游，知音拜楚侯。何須辭遠道，自可樂扁舟。',48,'御定全唐詩/json/823.json','["正是歎羈游，知音拜楚侯。何須辭遠道，自可樂扁舟。", "倚棹江洲雨，聞猿島岫秋。謝家山水興，終日待詩流。"]'),
('yuding-16','送造微上人遊五台及禮本師','棲白','唐','御定全唐诗','yuding','','[]','寒空金錫響，欲過渭陽津。極目多來雁，孤城少故人。',48,'御定全唐詩/json/823.json','["寒空金錫響，欲過渭陽津。極目多來雁，孤城少故人。", "與師雖別久，於法本相親。又對清涼月，中宵語宿因。"]'),
('yuding-17','送禪師宗極歸玉峰','棲白','唐','御定全唐诗','yuding','','[]','背郭去歸宿，頭陀意頗濃。鶴爭棲遠樹，猿鬥上孤峰。',48,'御定全唐詩/json/823.json','["背郭去歸宿，頭陀意頗濃。鶴爭棲遠樹，猿鬥上孤峰。", "夜戍經霜月，秋城過雨鐘。由來無定止，何處訪高蹤。"]'),
('yuding-18','送僧歸舊山','棲白','唐','御定全唐诗','yuding','','[]','談空與破邪，獻壽複榮家。白日得何偈，青天落幾花。',48,'御定全唐詩/json/823.json','["談空與破邪，獻壽複榮家。白日得何偈，青天落幾花。", "傳燈皆有分，化俗獨無涯。卻入中峰寺，還知有聚沙。"]'),
('yuding-19','送圓仁三藏歸本國','棲白','唐','御定全唐诗','yuding','','[]','家山臨晚日，海路信歸橈。樹滅渾無岸，風生只有潮。',48,'御定全唐詩/json/823.json','["家山臨晚日，海路信歸橈。樹滅渾無岸，風生只有潮。", "歲窮程未盡，天末國仍遙。已入閩王夢，香花境外邀。"]'),
('yuding-20','送王煉師歸嵩岳','棲白','唐','御定全唐诗','yuding','','[]','飄然綠毛節，杳去洛城端。隔水見秋嶽，兼霜掃石壇。',48,'御定全唐詩/json/823.json','["飄然綠毛節，杳去洛城端。隔水見秋嶽，兼霜掃石壇。", "一溪松色古，半夜鶴聲寒。迥與人寰別，勞生不可觀。"]'),
('yuding-21','壽昌節賦得紅雲表夏日','棲白','唐','御定全唐诗','yuding','','[]','景候融融陰氣潛，如峰雲共火相兼。霞光捧日登天上，',40,'御定全唐詩/json/823.json','["景候融融陰氣潛，如峰雲共火相兼。霞光捧日登天上，", "微臣多幸逢佳節，得賦殊祥近禦簾。"]'),
('yuding-22','經廢宮','棲白','唐','御定全唐诗','yuding','','[]','終日河聲咽暮空，煙愁此地晝濛濛。錦帆東去沙侵苑，',40,'御定全唐詩/json/823.json','["終日河聲咽暮空，煙愁此地晝濛濛。錦帆東去沙侵苑，", "那堪獨立思前事，回首殘陽雉堞紅。"]'),
('yuding-23','贈識古法師','棲白','唐','御定全唐诗','yuding','','[]','重城深寺講初休，卻憶家山訪舊遊。對月與君相送夜，',40,'御定全唐詩/json/823.json','["重城深寺講初休，卻憶家山訪舊遊。對月與君相送夜，", "遙想孤舟清渭上，飄然帆影起離愁。"]'),
('yuding-24','月夜懷劉秀才','棲白','唐','御定全唐诗','yuding','','[]','獨夜相思但自勞，阮生吟罷夢雲濤。',32,'御定全唐詩/json/823.json','["獨夜相思但自勞，阮生吟罷夢雲濤。", "此時小定未禪寂，古塔月中松磬高。"]'),
('yuding-25','寄南山景禪師','棲白','唐','御定全唐诗','yuding','','[]','一度林前見遠公，靜聞真語世情空。',32,'御定全唐詩/json/823.json','["一度林前見遠公，靜聞真語世情空。", "至今寂寞禪心在，任起桃花柳絮風。"]'),
('yuding-26','哭劉得仁','棲白','唐','御定全唐诗','yuding','','[]','為愛詩名吟至死，風魂雪魄去難招。',32,'御定全唐詩/json/823.json','["為愛詩名吟至死，風魂雪魄去難招。", "直須桂子落墳上，生得一枝冤始消。"]'),
('yuding-27','龍潭','應物','唐','御定全唐诗','yuding','','[]','石激懸流雪滿灣，五龍潛處野雲閑。暫收雷電九峰下，',40,'御定全唐詩/json/823.json','["石激懸流雪滿灣，五龍潛處野雲閑。暫收雷電九峰下，", "回瞻四面如看畫，須信遊人不欲還。"]'),
('yuding-28','題化城寺','應物','唐','御定全唐诗','yuding','','[]','平高選處創蓮宮，一水縈流處處通。畫閣晝開遲日畔，',40,'御定全唐詩/json/823.json','["平高選處創蓮宮，一水縈流處處通。畫閣晝開遲日畔，", "偶與遊人論法要，真元浩浩理無窮。"]'),
('yuding-29','戴雲山吟','智亮','唐','御定全唐诗','yuding','','[]','人間謾說上天梯，上萬千回總是迷。',64,'御定全唐詩/json/823.json','["人間謾說上天梯，上萬千回總是迷。", "曾似老人岩上坐，清風明月與心齊。", "戴雲山頂白雲齊，登頂方知世界低。", "異草奇花人不識，一池分作九條溪。"]'),
('yuding-30','答盧鄴','良乂','唐','御定全唐诗','yuding','','[]','風泉只向夢中聞，身外無餘可寄君。',32,'御定全唐詩/json/823.json','["風泉只向夢中聞，身外無餘可寄君。", "當戶一輪惟曉月，掛簷數片是秋雲。"]'),
('yuding-31','山居八詠','常達','唐','御定全唐诗','yuding','','[]','身閑依祖寺，志僻性多慵。少室遺真旨，層樓起暮鐘。',384,'御定全唐詩/json/823.json','["身閑依祖寺，志僻性多慵。少室遺真旨，層樓起暮鐘。", "啜茶思好水，對月數諸峰。有問山中趣，庭前是古松。", "晚望虛庭物，心心見祖情。煙開分嶽色，雨霧減泉聲。", "遠樹猿長嘯，層岩日乍明。更堪論的意，林下筍新生。", "一室塵埃外，翛然祗麼常。睡來開寢帳，鐘動下禪床。", "溪浸山光冷，秋凋木葉黃。時提祖師意，欹石看斜陽。", "西來真祖意，只在見聞中。寒雁一聲過，疏林幾葉空。", "心閑憐水石，身老怯霜風。為報參玄者，山山月色同。", "真性寂無機，塵塵祖佛師。日明庭砌暖，霜苦藥苗衰。", "汲水和煙酌，栽松帶雪移。好聽玄旨處，猿嘯嶺南枝。", "古寺憑欄危，時聞舉妙機。庭空月色淨，夜迥磬聲移。", "漏轉寒更急，燈殘冷焰微。太虛同萬象，相謂話玄微。", "胡僧論的旨，物物唱圓成。疏柳春來翠，幽窗日漸明。", "禪心清石室，蝶翅覆花英。好聽談玄處，喬松鶴數聲。", "祖祖唯心旨，春融日正長。霜輕莎草綠，風細藥苗香。", "月滿真如淨，花開覺樹芳。庭前鶯囀處，時聽語圓常。"]'),
('yuding-32','苦熱行','僧鸞','唐','御定全唐诗','yuding','','[]','燭龍銜火飛天地，平陸無風海波沸。彤雲疊疊聳奇峰，',120,'御定全唐詩/json/823.json','["燭龍銜火飛天地，平陸無風海波沸。彤雲疊疊聳奇峰，", "飲流誇父斃長途，如見當中印王字。明明夜西朝又東，", "行人揮汗翻成雨，口燥喉幹嗌塵土。西郊雲色晝冥冥，", "不發滂澤注天下，欲使風雷何所從。旱苗原上枯成焰，", "玉扇畫堂凝夜秋，歌豔繞梁催莫愁。陽烏落盡酒不醒，"]'),
('yuding-33','贈李粲秀才','僧鸞','唐','御定全唐诗','yuding','','[]','隴西輝用真才子，搜奇探險無倫比。筆下銛磨巨闕鋒，',216,'御定全唐詩/json/823.json','["隴西輝用真才子，搜奇探險無倫比。筆下銛磨巨闕鋒，", "苔地無塵到曉吟，杉松老葉風乾起。十軸示餘三百篇，", "大郊遠闊空無邊，凝明淡綠收餘煙。曠懷相對景何限，", "回首瞥見五千仞，撲下香爐瀑布泉。何事古人誇八鬥，", "駿如健鶻鶚與雕，拏雲獵野翻重霄。狐狸竄伏不敢動，", "九嶷深翠轉巍峨，仙骨寒消不知處。清同野客敲越甌，", "高若太空露雲物，片白激青皆仿佛。仙鶴閑從淨碧飛，", "鞭馳造化繞筆轉，燦爛不為酸苦吟。夢乘明月清沉沉，", "此日多君可儔侶，堆珠疊璣滿玄圃。終日並轡遊昆侖，"]'),
('yuding-34','和王季文題九華山','神穎','唐','御定全唐诗','yuding','','[]','眾嶽雄分野，九華鎮南朝。彩筆凝空遠，崔嵬寄青霄。',120,'御定全唐詩/json/823.json','["眾嶽雄分野，九華鎮南朝。彩筆凝空遠，崔嵬寄青霄。", "龍潭古仙府，靈藥今不凋。瑩為滄海鏡，煙霞作荒標。", "造化心數奇，性狀精氣饒。玉樹郁玲瓏，天籟韻蕭寥。", "寂寂尋乳竇，兢兢行石橋。通泉漱雲母，藉草縈香苕。", "我住幽且深，君賞昏複朝。稀逢發清唱，片片霜淩飆。"]'),
('yuding-35','宿嚴陵釣台','神穎','唐','御定全唐诗','yuding','','[]','寒穀荒台七裏洲，賢人永逐水東流。',32,'御定全唐詩/json/823.json','["寒穀荒台七裏洲，賢人永逐水東流。", "獨猿叫斷青天月，千古冥冥潭樹秋。"]'),
('yuding-36','效古','澹交','唐','御定全唐诗','yuding','','[]','榮辱又榮辱，一何翻與覆。人生百歲中，孰肯死前足。',48,'御定全唐詩/json/823.json','["榮辱又榮辱，一何翻與覆。人生百歲中，孰肯死前足。", "玄鬢忽如絲，青叢不再綠。自古爭名徒，黃金是誰祿。"]'),
('yuding-37','病後作','澹交','唐','御定全唐诗','yuding','','[]','未得忘身法，此身終未安。病腸猶可洗，瘦骨不禁寒。',48,'御定全唐詩/json/823.json','["未得忘身法，此身終未安。病腸猶可洗，瘦骨不禁寒。", "藥少心情餌，經無氣力看。悠悠片雲質，獨對夕陽殘。"]'),
('yuding-38','寫真','澹交','唐','御定全唐诗','yuding','','[]','圖形期自見，自見卻傷神。已是夢中夢，更逢身外身。',48,'御定全唐詩/json/823.json','["圖形期自見，自見卻傷神。已是夢中夢，更逢身外身。", "水花凝幻質，墨彩染空塵。堪笑予兼爾，俱為未了人。"]'),
('yuding-39','端午','文秀','唐','御定全唐诗','yuding','','[]','節分端午自誰言，萬古傳聞為屈原。',32,'御定全唐詩/json/823.json','["節分端午自誰言，萬古傳聞為屈原。", "堪笑楚江空渺渺，不能洗得直臣冤。"]'),
('yuding-40','謝友人見訪留詩','懷楚','唐','御定全唐诗','yuding','','[]','軒車誰肯到，泉石自相親。暮雨凋殘寺，秋風悵望人。',48,'御定全唐詩/json/823.json','["軒車誰肯到，泉石自相親。暮雨凋殘寺，秋風悵望人。", "庭新一片葉，衣故十年塵。賴有瑤華贈，清吟愈病身。"]'),
('yuding-41','送新平故人','懷楚','唐','御定全唐诗','yuding','','[]','常聽倉庚思舊友，又因蝴蝶夢生涯。一千餘裏河連郭，',40,'御定全唐詩/json/823.json','["常聽倉庚思舊友，又因蝴蝶夢生涯。一千餘裏河連郭，", "薑嫄廟北與君別，應笑薄寒悲落花。"]'),
('yuding-42','辭南平鐘王召','耽章','唐','御定全唐诗','yuding','','[]','摧殘枯木倚寒林，幾度逢春不變心。',32,'御定全唐詩/json/823.json','["摧殘枯木倚寒林，幾度逢春不變心。", "樵客見之猶不采，郢人何事苦搜尋。"]'),
('yuding-0','短歌行','子蘭','唐','御定全唐诗','yuding','','[]','日月何忙忙，出沒住不得。使我勇壯心，少年如頃刻。',60,'御定全唐詩/json/824.json','["日月何忙忙，出沒住不得。使我勇壯心，少年如頃刻。", "人生石火光，通時少於塞。四季倏往來，寒暑變為賊。", "偷人面上花，奪人頭上黑。"]'),
('yuding-1','飲馬長城窟','子蘭','唐','御定全唐诗','yuding','','[]','遊客長城下，飲馬長城窟。馬嘶聞水腥，為浸征人骨。',72,'御定全唐詩/json/824.json','["遊客長城下，飲馬長城窟。馬嘶聞水腥，為浸征人骨。", "豈不是流泉，終不成潺湲。洗盡骨上土，不洗骨中冤。", "骨若比流水，四海有還魂。空流嗚咽聲，聲中疑是言。"]'),
('yuding-2','夜直','子蘭','唐','御定全唐诗','yuding','','[]','大內隔重牆，多聞樂未央。燈明宮樹色，茶煮禁泉香。',96,'御定全唐詩/json/824.json','["大內隔重牆，多聞樂未央。燈明宮樹色，茶煮禁泉香。", "鳳輦通門靜，雞歌入漏長。宴榮陪禦席，話密近龍章。", "吟步彤庭月，眠分玉署涼。欲黏朱紱重，頻草白麻忙。", "筆力將群吏，人情在致唐。萬方瞻仰處，晨夕面吾皇。"]'),
('yuding-3','贈行腳僧','子蘭','唐','御定全唐诗','yuding','','[]','世界曾行遍，全無行可修。炎涼三衲共，生死一身休。',48,'御定全唐詩/json/824.json','["世界曾行遍，全無行可修。炎涼三衲共，生死一身休。", "片斷雲隨體，稀疏雪滿頭。此門無所著，不肯暫淹留。"]'),
('yuding-4','秋日思舊山','子蘭','唐','御定全唐诗','yuding','','[]','咸言上國繁華，豈謂帝城羈旅。十點五點殘螢，',35,'御定全唐詩/json/824.json','["咸言上國繁華，豈謂帝城羈旅。十點五點殘螢，", "欲去不去遲遲，未展平生所佇。"]'),
('yuding-5','寄幹陵楊侍郎','子蘭','唐','御定全唐诗','yuding','','[]','冷落官資不畏貧，司曹且共內官分。步量野色成公案，',40,'御定全唐詩/json/824.json','["冷落官資不畏貧，司曹且共內官分。步量野色成公案，", "碑寒樹古神門上，管得無窮空白雲。"]'),
('yuding-6','登樓憶友','子蘭','唐','御定全唐诗','yuding','','[]','物象遠濛濛，周回極望中。帶煙千井樹，和磬一樓風。',48,'御定全唐詩/json/824.json','["物象遠濛濛，周回極望中。帶煙千井樹，和磬一樓風。", "月色寒沈地，波聲夜颺空。登臨無限趣，恨不與君同。"]'),
('yuding-7','華嚴寺望樊川','子蘭','唐','御定全唐诗','yuding','','[]','萬木葉初紅，人家樹色中。疏鐘搖雨腳，秋水浸雲容。',48,'御定全唐詩/json/824.json','["萬木葉初紅，人家樹色中。疏鐘搖雨腳，秋水浸雲容。", "雪磧回寒雁，村燈促夜舂。舊山歸未得，生計欲何從。"]'),
('yuding-8','與道侶同於水陸寺會宿','子蘭','唐','御定全唐诗','yuding','','[]','論道窮心少有朋，此時清話昔年曾。柿凋紅葉鋪寒井，',40,'御定全唐詩/json/824.json','["論道窮心少有朋，此時清話昔年曾。柿凋紅葉鋪寒井，", "出門儘是勞生者，只此長閑幾個能。"]'),
('yuding-9','城上吟','子蘭','唐','御定全唐诗','yuding','','[]','古塚密於草，新墳侵官道。城外無閑地，城中人又老。',24,'御定全唐詩/json/824.json','["古塚密於草，新墳侵官道。城外無閑地，城中人又老。"]'),
('yuding-10','襄陽曲','子蘭','唐','御定全唐诗','yuding','','[]','為憶南遊人，移家大堤住。千帆萬帆來，盡過門前去。',24,'御定全唐詩/json/824.json','["為憶南遊人，移家大堤住。千帆萬帆來，盡過門前去。"]'),
('yuding-11','誡貪','子蘭','唐','御定全唐诗','yuding','','[]','多求待心足，未足旋傾覆。明知貪者心，求榮不求辱。',24,'御定全唐詩/json/824.json','["多求待心足，未足旋傾覆。明知貪者心，求榮不求辱。"]'),
('yuding-12','蟬二首','子蘭','唐','御定全唐诗','yuding','','[]','獨蟬初唱古槐枝，委曲悲涼斷續遲。',64,'御定全唐詩/json/824.json','["獨蟬初唱古槐枝，委曲悲涼斷續遲。", "雨後忽聞誰最苦，異鄉孤館憶家時。", "衰柳蟬吟旁濁河，正當殘日角聲和。", "尋常不足少愁思，此際聞時愁更多。"]'),
('yuding-13','太平坊尋裴郎中故宅','子蘭','唐','御定全唐诗','yuding','','[]','不語淒涼無限情，荒階行盡又重行。',32,'御定全唐詩/json/824.json','["不語淒涼無限情，荒階行盡又重行。", "昔年住此何人在，滿地槐花秋草生。"]'),
('yuding-14','登樓','子蘭','唐','御定全唐诗','yuding','','[]','邊邑鴻聲一例秋，大波平日繞山流。',32,'御定全唐詩/json/824.json','["邊邑鴻聲一例秋，大波平日繞山流。", "故人千里同明月，盡夕無言空倚樓。"]'),
('yuding-15','長安早秋','子蘭','唐','御定全唐诗','yuding','','[]','風舞槐花落禦溝，終南山色入城秋。',32,'御定全唐詩/json/824.json','["風舞槐花落禦溝，終南山色入城秋。", "門門走馬徵兵急，公子笙歌醉玉樓。"]'),
('yuding-16','對雪','子蘭','唐','御定全唐诗','yuding','','[]','密密無聲墜碧空，霏霏有韻舞微風。',32,'御定全唐詩/json/824.json','["密密無聲墜碧空，霏霏有韻舞微風。", "幽人吟望搜辭處，飄入窗來落硯中。"]'),
('yuding-17','鸚鵡','子蘭','唐','御定全唐诗','yuding','','[]','翠毛丹觜乍教時，終日無寥似憶歸。',32,'御定全唐詩/json/824.json','["翠毛丹觜乍教時，終日無寥似憶歸。", "近來偷解人言語，亂向金籠說是非。"]'),
('yuding-18','晚景','子蘭','唐','御定全唐诗','yuding','','[]','池荷衰颯菊芬芳，策杖吟詩上草堂。',32,'御定全唐詩/json/824.json','["池荷衰颯菊芬芳，策杖吟詩上草堂。", "滿目暮雲風卷盡，郡樓寒角數聲長。"]'),
('yuding-19','長安傷春','子蘭','唐','御定全唐诗','yuding','','[]','霜隕中春花半無，狂遊恣飲盡凶徒。',32,'御定全唐詩/json/824.json','["霜隕中春花半無，狂遊恣飲盡凶徒。", "年年賞玩公卿輩，今委溝塍骨漸枯。"]'),
('yuding-20','河梁晚望二首','子蘭','唐','御定全唐诗','yuding','','[]','水勢滔滔不可量，漁舟容易泛滄浪。',64,'御定全唐詩/json/824.json','["水勢滔滔不可量，漁舟容易泛滄浪。", "連山翠靄籠沙漵，白鳥翩翩下夕陽。", "雨添一夜秋濤闊，極目茫茫似接天。", "不知龍物潛何處，魚躍蛙鳴滿檻前。"]'),
('yuding-21','悲長安','子蘭','唐','御定全唐诗','yuding','','[]','何事天時禍未回，生靈愁悴苦寒灰。',32,'御定全唐詩/json/824.json','["何事天時禍未回，生靈愁悴苦寒灰。", "豈知萬頃繁華地，強半今為瓦礫堆。"]'),
('yuding-22','千葉石榴花','子蘭','唐','御定全唐诗','yuding','','[]','一朵花開千葉紅，開時又不藉春風。',32,'御定全唐詩/json/824.json','["一朵花開千葉紅，開時又不藉春風。", "若教移在香閨畔，定與佳人豔態同。"]'),
('yuding-23','觀棋','子蘭','唐','御定全唐诗','yuding','','[]','拂局盡消時，能因長路遲。點頭初得計，格手待無疑。',48,'御定全唐詩/json/824.json','["拂局盡消時，能因長路遲。點頭初得計，格手待無疑。", "寂默親遺景，凝神入過思。共藏多少意，不語兩相知。"]'),
('yuding-0','山居','可止','唐','御定全唐诗','yuding','','[]','雪消春力展，花漫洞門垂。果長纖枝曲，岩崩直道移。',48,'御定全唐詩/json/825.json','["雪消春力展，花漫洞門垂。果長纖枝曲，岩崩直道移。", "重猿圍淺井，鬥鼠下疏籬。寒食微燈在，高風勢徹陂。"]'),
('yuding-1','贈樊川長老','可止','唐','御定全唐诗','yuding','','[]','瘦顏顴骨見，滿面雪毫垂。坐石鳥疑死，出門人謂癡。',48,'御定全唐詩/json/825.json','["瘦顏顴骨見，滿面雪毫垂。坐石鳥疑死，出門人謂癡。", "照身潭入楚，浸影檜生隋。太白曾經夏，清風涼四肢。"]'),
('yuding-2','寄積麥山會如長老','可止','唐','御定全唐诗','yuding','','[]','默然如大道，塵世不相關。青檜行時靜，白雲禪處閑。',48,'御定全唐詩/json/825.json','["默然如大道，塵世不相關。青檜行時靜，白雲禪處閑。", "貧高一生行，病長十年顏。夏滿期遊寺，尋山又下山。"]'),
('yuding-3','送僧','可止','唐','御定全唐诗','yuding','','[]','四海無拘系，行心興自濃。百年三事衲，萬里一枝筇。',48,'御定全唐詩/json/825.json','["四海無拘系，行心興自濃。百年三事衲，萬里一枝筇。", "夜減當晴影，春消過雪蹤。白雲深處去，知宿在何峰。"]'),
('yuding-4','哭賈島','可止','唐','御定全唐诗','yuding','','[]','燕生松雪地，蜀死葬山根。詩僻降今古，官卑誤子孫。',48,'御定全唐詩/json/825.json','["燕生松雪地，蜀死葬山根。詩僻降今古，官卑誤子孫。", "塚欄寒月色，人哭苦吟魂。墓雨滴碑字，年年添蘚痕。"]'),
('yuding-5','雪十二韻','可止','唐','御定全唐诗','yuding','','[]','落處咸過尺，翛然物象淒。瑞凝金殿上，寒甚玉關西。',144,'御定全唐詩/json/825.json','["落處咸過尺，翛然物象淒。瑞凝金殿上，寒甚玉關西。", "潤比江河普，明將日月齊。淩雲花頂膩，鎖徑竹梢低。", "出谷樵童怯，歸林野鳥迷。煮茶融破練，磨墨染成黳。", "陷兔埋平澤，和魚凍合溪。入樓消酒力，當檻寫詩題。", "道路依憑馬，朝昏委託雞。洞深猿作族，松亞鶴移棲。", "及夏清岩穴，經春溜石梯。豐年兼泰國，天道育黔黎。"]'),
('yuding-6','精舍遇雨','可止','唐','御定全唐诗','yuding','','[]','空門寂寂淡吾身，溪雨微微洗客塵。',32,'御定全唐詩/json/825.json','["空門寂寂淡吾身，溪雨微微洗客塵。", "臥向白雲情未盡，任他黃鳥醉芳春。"]'),
('yuding-7','小雪','可止','唐','御定全唐诗','yuding','','[]','落雪臨風不厭看，更多還恐蔽林巒。',32,'御定全唐詩/json/825.json','["落雪臨風不厭看，更多還恐蔽林巒。", "愁人正在書窗下，一片飛來一片寒。"]'),
('yuding-8','送婆羅門僧','可止','唐','御定全唐诗','yuding','','[]','雪嶺金河獨向東，吳山楚澤意無窮。',32,'御定全唐詩/json/825.json','["雪嶺金河獨向東，吳山楚澤意無窮。", "如今白首鄉心盡，萬里歸程在夢中。"]'),
('yuding-9','句','可止','唐','御定全唐诗','yuding','','[]','不知誰會喃喃語，必向王前報太平。（中山節度王處直座',51,'御定全唐詩/json/825.json','["不知誰會喃喃語，必向王前報太平。（中山節度王處直座", "詠白鵲，時諸侯兼併，王欲繼好息民，故雲。《高僧傳》）"]'),
('yuding-10','寒食日','雲表','唐','御定全唐诗','yuding','','[]','寒食悲看郭外春，野田無處不傷神。',32,'御定全唐詩/json/825.json','["寒食悲看郭外春，野田無處不傷神。", "平原累累添新塚，半是去年來哭人。"]'),
('yuding-11','自遣','歸仁','唐','御定全唐诗','yuding','','[]','日日為詩苦，誰論春與秋。一聯如得意，萬事總忘憂。',48,'御定全唐詩/json/825.json','["日日為詩苦，誰論春與秋。一聯如得意，萬事總忘憂。", "雨墮花臨砌，風吹竹近樓。不吟頭也白，任白此生頭。"]'),
('yuding-12','酬沈先輩卷','歸仁','唐','御定全唐诗','yuding','','[]','一百八十首，清泠韻可敲。任從人不愛，終是我難拋。',48,'御定全唐詩/json/825.json','["一百八十首，清泠韻可敲。任從人不愛，終是我難拋。", "桂魄吟來滿，蒲團坐得凹。先生聲價在，寰宇幾人抄。"]'),
('yuding-13','題賈島吟詩台','歸仁','唐','御定全唐诗','yuding','','[]','此台如可廢，此恨有誰平。縱使迷青草，終難沒舊名。',48,'御定全唐詩/json/825.json','["此台如可廢，此恨有誰平。縱使迷青草，終難沒舊名。", "天悲朝雨色，嶽哭夜猿聲。不是心偏苦，應關自古情。"]'),
('yuding-14','悼羅隱','歸仁','唐','御定全唐诗','yuding','','[]','一著讒書未快心，幾抽胸臆縱狂吟。管中窺豹我猶在，',40,'御定全唐詩/json/825.json','["一著讒書未快心，幾抽胸臆縱狂吟。管中窺豹我猶在，", "長安冠蓋皆塗地，仍喜先生葬碧岑。"]'),
('yuding-15','題楚廟','歸仁','唐','御定全唐诗','yuding','','[]','羞容難更返江東，誰問從來百戰功。天地有心歸道德，',40,'御定全唐詩/json/825.json','["羞容難更返江東，誰問從來百戰功。天地有心歸道德，", "也是男兒成敗事，不須惆悵對西風。"]'),
('yuding-16','牡丹','歸仁','唐','御定全唐诗','yuding','','[]','三春堪惜牡丹奇，半倚朱欄欲綻時。天下更無花勝此，',40,'御定全唐詩/json/825.json','["三春堪惜牡丹奇，半倚朱欄欲綻時。天下更無花勝此，", "除卻解禪心不動，算應狂殺五陵兒。"]'),
('yuding-17','舊國裏','卿雲','唐','御定全唐诗','yuding','','[]','舊居梨嶺下，風景近炎方。地暖生春早，家貧覺歲長。',48,'御定全唐詩/json/825.json','["舊居梨嶺下，風景近炎方。地暖生春早，家貧覺歲長。", "石房雲過濕，杉徑雨餘香。日夕竟無事，詩書聊自強。"]'),
('yuding-18','秋日江居閑詠','卿雲','唐','御定全唐诗','yuding','','[]','寄居江島邊，閑詠見秋殘。草白牛羊瘦，風高猿鳥寒。',48,'御定全唐詩/json/825.json','["寄居江島邊，閑詠見秋殘。草白牛羊瘦，風高猿鳥寒。", "檢方醫故疾，挑薺備中餐。時複停書卷，鉏莎種木蘭。"]'),
('yuding-19','長安言懷寄沈彬侍郎','卿雲','唐','御定全唐诗','yuding','','[]','故園梨嶺下，歸路接天涯。生作長安草，勝為邊地花。',48,'御定全唐詩/json/825.json','["故園梨嶺下，歸路接天涯。生作長安草，勝為邊地花。", "雁南飛不到，書北寄來賒。堪羨神仙客，青雲早致家。"]'),
('yuding-20','送人遊塞','卿雲','唐','御定全唐诗','yuding','','[]','去去玉關路，省君曾未行。塞深多伏寇，時靜亦屯兵。',48,'御定全唐詩/json/825.json','["去去玉關路，省君曾未行。塞深多伏寇，時靜亦屯兵。", "雪每先秋降，花嘗近夏生。閑陪射雕將，應到受降城。"]'),
('yuding-21','逢老人','隱巒','唐','御定全唐诗','yuding','','[]','路逢一老翁，兩鬢白如雪。一裏二裏行，四回五回歇。',24,'御定全唐詩/json/825.json','["路逢一老翁，兩鬢白如雪。一裏二裏行，四回五回歇。"]'),
('yuding-22','牧童','隱巒','唐','御定全唐诗','yuding','','[]','牧童見人俱不識，盡著芒鞋戴箬笠。朝陽未出眾山晴，',46,'御定全唐詩/json/825.json','["牧童見人俱不識，盡著芒鞋戴箬笠。朝陽未出眾山晴，", "三個五個騎羸牛，前村後村來放牧。笛聲才一舉，"]'),
('yuding-23','蜀中送人遊廬山','隱巒','唐','御定全唐诗','yuding','','[]','居遊正值芳春月，蜀道千山皆秀髮。溪邊十裏五裏花，',40,'御定全唐詩/json/825.json','["居遊正值芳春月，蜀道千山皆秀髮。溪邊十裏五裏花，", "君行試到山前問，山鳥只今相憶無。"]'),
('yuding-24','琴','隱巒','唐','御定全唐诗','yuding','','[]','七條絲上寄深意，澗水松風生十指。',32,'御定全唐詩/json/825.json','["七條絲上寄深意，澗水松風生十指。", "自乃知音猶尚稀，欲教更入何人耳。"]'),
('yuding-25','浮橋','隱巒','唐','御定全唐诗','yuding','','[]','橫壓驚波防沒溺，當初元創是軍機。',32,'御定全唐詩/json/825.json','["橫壓驚波防沒溺，當初元創是軍機。", "行人到此全無滯，一片江雲踏欲飛。"]'),
('yuding-26','宿九華化成寺莊','泠然','唐','御定全唐诗','yuding','','[]','佛寺孤莊千嶂間，我來詩境強相關。岩邊樹動猿下澗，',40,'御定全唐詩/json/825.json','["佛寺孤莊千嶂間，我來詩境強相關。岩邊樹動猿下澗，", "明朝更躡層霄去，誓共煙霞到老閑。"]'),
('yuding-27','乞荊浩畫','大愚','唐','御定全唐诗','yuding','','[]','六幅故牢健，知君恣筆蹤。不求千澗水，止要兩株松。',48,'御定全唐詩/json/825.json','["六幅故牢健，知君恣筆蹤。不求千澗水，止要兩株松。", "樹下留磐石，天邊縱遠峰。近岩幽濕處，惟藉墨煙濃。"]'),
('yuding-28','上歸州刺史代通狀二首','懷浚','唐','御定全唐诗','yuding','','[]','家在閩山西複西，其中歲歲有鶯啼。',64,'御定全唐詩/json/825.json','["家在閩山西複西，其中歲歲有鶯啼。", "如今不在鶯啼處，鶯在舊時啼處啼。", "家在閩山東複東，其中歲歲有花紅。", "而今不在花紅處，花在舊時紅處紅。"]'),
('yuding-29','辭郡守李公恩命','恒超','唐','御定全唐诗','yuding','','[]','虛著褐衣老，浮杯道不成。誓傳經論死，不染利名生。',48,'御定全唐詩/json/825.json','["虛著褐衣老，浮杯道不成。誓傳經論死，不染利名生。", "厭樹遮山色，憐窗向月明。他時隨範蠡，一棹五湖清。"]'),
('yuding-30','題廣愛寺楞伽山','淨顯','唐','御定全唐诗','yuding','','[]','靈異不能棲鳥雀，幽奇終不著猿猱。為經巢賊應無損，',25,'御定全唐詩/json/825.json','["靈異不能棲鳥雀，幽奇終不著猿猱。為經巢賊應無損，", "。"]'),
('yuding-31','《聞誦法華經》歌','修雅','唐','御定全唐诗','yuding','','[]','山色沉沉，松煙冪冪。空林之下，盤陀之石。石上有僧，',267,'御定全唐詩/json/825.json','["山色沉沉，松煙冪冪。空林之下，盤陀之石。石上有僧，", "十片五片，異花狼藉。偶然相見，未深相識。知是古之人，", "佛之意兮祖之髓，我之心兮經之旨。可憐彈指及舉手，", "光輝一萬八千土，土土皆作黃金色。四生六道一光中，", "今日親聞誦此經，始覺驢乘匪端的。我亦當年不出戶，", "我亦當年愛吟詠，將謂冥搜亂神定。今日親聞誦此經，", "今日親聞誦此經，始覺聚沙非小事。我昔曾游山與水，", "我昔心猿未調伏，常將金鎖虛拘束。今日親聞誦此經，", "醍醐之味珍且美，不在唇，不在齒，只在勞生方寸裏。", "師誦此經經一句，句句白牛親動步。白牛之步疾如風，", "世人縱識師之形，誰人能識師之名。師名醫王行佛令，"]'),
('yuding-32','歌','元寂','唐','御定全唐诗','yuding','','[]','酒禿酒禿，何榮何辱。但見衣冠成古丘，不見江河變陵穀。',26,'御定全唐詩/json/825.json','["酒禿酒禿，何榮何辱。但見衣冠成古丘，不見江河變陵穀。"]'),
('yuding-33','懷廬山舊隱','若虛','唐','御定全唐诗','yuding','','[]','九疊嵯峨倚著天，悔隨寒瀑下岩煙。深秋猿鳥來心上，',40,'御定全唐詩/json/825.json','["九疊嵯峨倚著天，悔隨寒瀑下岩煙。深秋猿鳥來心上，", "一枝筇竹遊江北，不見爐峰二十年。"]'),
('yuding-34','樂仙觀','若虛','唐','御定全唐诗','yuding','','[]','樂氏騎龍上碧天，東吳遺宅尚依然。悟來大道無多事，',40,'御定全唐詩/json/825.json','["樂氏騎龍上碧天，東吳遺宅尚依然。悟來大道無多事，", "松傾鶴死桑田變，華表歸鄉未有年。"]'),
('yuding-35','古鏡','若虛','唐','御定全唐诗','yuding','','[]','軒後紅爐獨鑄成，蘚痕磨落月輪呈。萬般物象皆能鑒，',40,'御定全唐詩/json/825.json','["軒後紅爐獨鑄成，蘚痕磨落月輪呈。萬般物象皆能鑒，", "百年肝膽堪將比，只怕看頻素發生。"]'),
('yuding-36','睹木平和尚','文益','唐','御定全唐诗','yuding','','[]','木平山裏人，貌古年複少。相看陌路同，論心秋月皎。',48,'御定全唐詩/json/825.json','["木平山裏人，貌古年複少。相看陌路同，論心秋月皎。", "懷衲線非蠶，助歌聲有鳥。城闕今日來，一謳曾已曉。"]'),
('yuding-37','鷺鷥','無則','唐','御定全唐诗','yuding','','[]','白蘋紅蓼碧江涯，日暖雙雙立睡時。',32,'御定全唐詩/json/825.json','["白蘋紅蓼碧江涯，日暖雙雙立睡時。", "願揭金籠放歸去，卻隨沙鶴鬥輕絲。"]'),
('yuding-38','百舌鳥二首','無則','唐','御定全唐诗','yuding','','[]','千愁萬恨過花時，似向春風怨別離。',64,'御定全唐詩/json/825.json','["千愁萬恨過花時，似向春風怨別離。", "若使眾禽俱解語，一生懷抱有誰知。", "長截鄰雞叫五更，數般名字百般聲。", "饒伊搖舌先知曉，也待青天明即鳴。"]'),
('yuding-39','賞牡丹應教','謙光','唐','御定全唐诗','yuding','','[]','擁衲對芳叢，由來事不同。鬢從今日白，花似去年紅。',48,'御定全唐詩/json/825.json','["擁衲對芳叢，由來事不同。鬢從今日白，花似去年紅。", "豔異隨朝露，馨香逐曉風。何須對零落，然後始知空。"]'),
('yuding-0','善哉行','貫休','唐','御定全唐诗','yuding','','[]','有美一人兮，婉如青揚。識曲別音兮，令姿煌煌。',67,'御定全唐詩/json/826.json','["有美一人兮，婉如青揚。識曲別音兮，令姿煌煌。", "繡袂捧琴兮，登君子堂。如彼萱草兮，使我憂忘。", "欲贈之以紫玉尺，白銀鐺。久不見之兮，湘水茫茫。"]'),
('yuding-1','讀離騷經','貫休','唐','御定全唐诗','yuding','','[]','湘江濱，湘江濱，蘭紅芷白波如銀，終須一去呼湘君。',67,'御定全唐詩/json/826.json','["湘江濱，湘江濱，蘭紅芷白波如銀，終須一去呼湘君。", "問湘神，雲中君，不知何以交靈均。我恐湘江之魚兮，", "又想靈均之骨兮終不曲。千年波底色如玉，"]'),
('yuding-2','陽春曲','貫休','唐','御定全唐诗','yuding','','[]','為口莫學阮嗣宗，不言是非非至公。為手須似朱雲輩，',50,'御定全唐詩/json/826.json','["為口莫學阮嗣宗，不言是非非至公。為手須似朱雲輩，", "歷數雍熙房與杜，魏公姚公宋開府。盡向天上仙宮閑處坐，"]'),
('yuding-3','白雪曲','貫休','唐','御定全唐诗','yuding','','[]','列鼎佩金章，淚眼看風枝。卻思食藜藿，身作屠沽兒。',72,'御定全唐詩/json/826.json','["列鼎佩金章，淚眼看風枝。卻思食藜藿，身作屠沽兒。", "負米無遠近，所希升鬥歸。為人無貴賤，莫學雞狗肥。", "斯言如不忘，別更無光輝。斯言如或忘，即安用人為。"]'),
('yuding-4','上留田','貫休','唐','御定全唐诗','yuding','','[]','父不父，兄不兄。上留田，蝥賊生。徒陟岡，淚崢嶸。',46,'御定全唐詩/json/826.json','["父不父，兄不兄。上留田，蝥賊生。徒陟岡，淚崢嶸。", "我欲使諸凡鳥雀，盡變為鶺鴒。我欲使諸凡草木，"]'),
('yuding-5','胡無人','貫休','唐','御定全唐诗','yuding','','[]','霍嫖姚，趙充國，天子將之平朔漠。肉胡之肉，燼胡帳幄。',95,'御定全唐詩/json/826.json','["霍嫖姚，趙充國，天子將之平朔漠。肉胡之肉，燼胡帳幄。", "千里萬里，唯留胡之空殼。邊風蕭蕭，榆葉初落。", "殺氣晝赤，枯骨夜哭。將軍既立殊勳，遂有胡無人曲。", "我聞之，天子富有四海，德被無垠。但令一物得所，"]'),
('yuding-6','苦寒行','貫休','唐','御定全唐诗','yuding','','[]','北風北風，職何嚴毒。摧壯士心，縮金烏足。凍雲囂囂，',25,'御定全唐詩/json/826.json','["北風北風，職何嚴毒。摧壯士心，縮金烏足。凍雲囂囂，"]'),
('yuding-7','蒿裏','貫休','唐','御定全唐诗','yuding','','[]','兔不遲，烏更急，但恐穆王八駿，著鞭不及。所以蒿裏，',50,'御定全唐詩/json/826.json','["兔不遲，烏更急，但恐穆王八駿，著鞭不及。所以蒿裏，", "折碑石人，莽穢榛沒。牛羊窸窣，時見牧童兒，弄枯骨。"]'),
('yuding-8','臨高臺','貫休','唐','御定全唐诗','yuding','','[]','涼風吹遠念，使我升高台。寧知數片雲，不是舊山來。',48,'御定全唐詩/json/826.json','["涼風吹遠念，使我升高台。寧知數片雲，不是舊山來。", "故人天一涯，久客殊未回。雁來不得書，空寄聲哀哀。"]'),
('yuding-9','杞梁妻','貫休','唐','御定全唐诗','yuding','','[]','秦之無道兮四海枯，築長城兮遮北胡。築人築土一萬里，',49,'御定全唐詩/json/826.json','["秦之無道兮四海枯，築長城兮遮北胡。築人築土一萬里，", "一號城崩塞色苦，再號杞梁骨出土。疲魂饑魄相逐歸，"]'),
('yuding-10','古離別','貫休','唐','御定全唐诗','yuding','','[]','離恨如旨酒，古今飲皆醉。只恐長江水，儘是兒女淚。',48,'御定全唐詩/json/826.json','["離恨如旨酒，古今飲皆醉。只恐長江水，儘是兒女淚。", "伊餘非此輩，送人空把臂。他日再相逢，清風動天地。"]'),
('yuding-11','戰城南二首','貫休','唐','御定全唐诗','yuding','','[]','萬里桑幹傍，茫茫古蕃壤。將軍貌憔悴，撫劍悲年長。',108,'御定全唐詩/json/826.json','["萬里桑幹傍，茫茫古蕃壤。將軍貌憔悴，撫劍悲年長。", "胡兵尚陵逼，久住亦非強。邯鄲少年輩，個個有伎倆。", "拖槍半夜去，雪片大如掌。", "磧中有陰兵，戰馬時驚蹶。輕猛李陵心，摧殘蘇武節。", "黃金鎖子甲，風吹色如鐵。十載不封侯，茫茫向誰說。"]'),
('yuding-12','少年行','貫休','唐','御定全唐诗','yuding','','[]','錦衣鮮華手擎鶻，閑行氣貌多輕忽。',80,'御定全唐詩/json/826.json','["錦衣鮮華手擎鶻，閑行氣貌多輕忽。", "稼穡艱難總不知，五帝三皇是何物。", "自拳五色裘，迸入他人宅。卻捉蒼頭奴，玉鞭打一百。", "面白如削玉，倡狂曲江曲。馬上黃金鞍，適來新賭得。"]'),
('yuding-13','夢遊仙四首','貫休','唐','御定全唐诗','yuding','','[]','夢到海中山，入個白銀宅。逢見一道士，稱是李八伯。',104,'御定全唐詩/json/826.json','["夢到海中山，入個白銀宅。逢見一道士，稱是李八伯。", "三四仙女兒，身著瑟瑟衣。手把明月珠，打落金色梨。", "車渠地無塵，行至瑤池濱。森森椿樹下，白龍來嗅人。", "宮殿崢嶸籠紫氣，金渠玉砂五色水。", "守閽仙婢相倚睡，偷摘蟠桃幾倒地。"]'),
('yuding-14','輕薄篇二首','貫休','唐','御定全唐诗','yuding','','[]','繡林錦野，春態相壓。誰家少年，馬蹄蹋蹋。',89,'御定全唐詩/json/826.json','["繡林錦野，春態相壓。誰家少年，馬蹄蹋蹋。", "鬥雞走狗夜不歸，一擲賭卻如花妾。誰雲不顛不狂，", "木落蕭蕭，蟲鳴唧唧。不覺朱蔫臉紅，霜劫鬢漆。", "世途多事，泣向秋日。方今少壯不努力，老大徒傷悲，"]'),
('yuding-15','長安道','貫休','唐','御定全唐诗','yuding','','[]','憧憧合合，八表一轍。黃塵霧合，車馬火熱。名湯風雨，',61,'御定全唐詩/json/826.json','["憧憧合合，八表一轍。黃塵霧合，車馬火熱。名湯風雨，", "紫氣銀輪兮常覆金闕。仙掌捧日兮濁河澄澈。", "愚將草木兮有言，與華封人兮不別。"]'),
('yuding-16','洛陽塵','貫休','唐','御定全唐诗','yuding','','[]','昔時昔時洛城人，今作茫茫洛城塵。我聞富有石季倫，',50,'御定全唐詩/json/826.json','["昔時昔時洛城人，今作茫茫洛城塵。我聞富有石季倫，", "真珠簾中，姑射神人。文金線玉，香成暮雲。孫秀若不殺，"]'),
('yuding-17','富貴曲二首','貫休','唐','御定全唐诗','yuding','','[]','有金張族，驕奢相續。瓊樹玉堂，雕牆繡轂。紈綺雜雜，',97,'御定全唐詩/json/826.json','["有金張族，驕奢相續。瓊樹玉堂，雕牆繡轂。紈綺雜雜，", "如神若仙，似蘭同雪。樂戒于極，胡不知輟。", "只欲更綴上落花，恨不能把住明月。太山肉盡，東海酒竭。", "佳人醉唱，敲玉釵折。甯知耘田車水翁，日日日灸背欲裂。"]'),
('yuding-18','野田黃雀行','貫休','唐','御定全唐诗','yuding','','[]','高樹風多，吹爾巢落。深蒿葉暖，宜爾依泊。莫近鴞類，',25,'御定全唐詩/json/826.json','["高樹風多，吹爾巢落。深蒿葉暖，宜爾依泊。莫近鴞類，"]'),
('yuding-19','古意九首','貫休','唐','御定全唐诗','yuding','','[]','一雨火雲盡，閉門心冥冥。蘭花與芙蓉，滿院同芳馨。',513,'御定全唐詩/json/826.json','["一雨火雲盡，閉門心冥冥。蘭花與芙蓉，滿院同芳馨。", "佳人天一涯，好鳥何嚶嚶。我有雙白璧，不羨于虞卿。", "我有徑寸珠，別是天地精。玩之室生白，瀟灑身安輕。", "只應天上人，見我雙眼明。", "陽烏爍萬物，草木懷春恩。茫茫塵土飛，培壅名利根。", "我本是蓑笠，幼知天子尊。學為毛氏詩，亦多直致言。", "不慕需臑類，附勢同崩奔。唯尋桃李蹊，去去長者門。", "美人如游龍，被服金鴛鴦。手把古刀尺，在彼白玉堂。", "文章深掣曳，珂佩鳴丁當。好風吹桃花，片片落銀床。", "何妨學羽翰，遠逐朱鳥翔。", "乾坤有清氣，散入詩人脾。聖賢遺清風，不在惡木枝。", "千人萬人中，一人兩人知。憶在東溪日，花開葉落時。", "幾擬以黃金，鑄作鐘子期。", "莫輕白雲白，不與風雨會。莫見守羊兒，或是初平輩。", "人生非日月，光輝豈常在。一榮與一辱，古今常相對。", "君不見於公門，子孫好冠蓋。", "古交如真金，百煉色不回。今交如暴流，倏忽生塵埃。", "我願君子氣，散為青松栽。我恐荊棘花，只為小人開。", "傷心複傷心，吟上高高臺。", "常思謝康樂，文章有神力。是何清風清，凜然似相識。", "一種為頑嚚，得作翻經石。一種為枯槁，得作登山屐。", "永嘉為郡後，山水添鮮碧。何當學羽翰，一去觀遺跡。", "常思李太白，仙筆驅造化。玄宗致之七寶床，", "紫皇殿前五色麟，忽然掣斷黃金鎖。五湖大浪如銀山，"]'),
('yuding-20','酷吏詞','貫休','唐','御定全唐诗','yuding','','[]','霰雨灂灂，風吼如劚。有叟有叟，暮投我宿。籲歎自語，',47,'御定全唐詩/json/826.json','["霰雨灂灂，風吼如劚。有叟有叟，暮投我宿。籲歎自語，", "所以祥風不來，和氣不復。蝗乎蠈乎，東西南北。"]'),
('yuding-21','還舉人歌行卷','貫休','唐','御定全唐诗','yuding','','[]','厚於鐵圍山上鐵，薄似雙成仙體纈。蜀機鳳雛動蹩躠，',48,'御定全唐詩/json/826.json','["厚於鐵圍山上鐵，薄似雙成仙體纈。蜀機鳳雛動蹩躠，", "古松直筆雷不折，雪衣女啄蟠桃缺。佩入龍宮步遲遲，"]'),
('yuding-22','陳宮詞','貫休','唐','御定全唐诗','yuding','','[]','緬想當時宮闕盛，荒宴椒房懱堯聖。玉樹花歌百花裏，',40,'御定全唐詩/json/826.json','["緬想當時宮闕盛，荒宴椒房懱堯聖。玉樹花歌百花裏，", "陳宮因此成野田，耕人犁破宮人鏡。"]'),
('yuding-23','擬齊梁酬所知見贈二首','貫休','唐','御定全唐诗','yuding','','[]','靜只焚香坐，詠懷悲歲闌。佳人忽有贈，滿手紅琅玕。',108,'御定全唐詩/json/826.json','["靜只焚香坐，詠懷悲歲闌。佳人忽有贈，滿手紅琅玕。", "不獨耀肌魄，將行為羽翰。酬如上青天，風雪空漫漫。", "美如仙鼎金，清如纖手琴。孫登嘯一聲，縹緲不可尋。", "但覺神洋洋，如入三昧林。釋手複在手，古意深複深。", "慚無英瓊瑤，何以酬知音。"]'),
('yuding-24','經古戰場','貫休','唐','御定全唐诗','yuding','','[]','茫茫凶荒，迥如天設。駐馬四顧，氣候迂結。秋空崢嶸，',69,'御定全唐詩/json/826.json','["茫茫凶荒，迥如天設。駐馬四顧，氣候迂結。秋空崢嶸，", "莫見地赤碧，儘是征血。昔人昔人既能忠盡於力，", "而使空曠年年，常貯愁煙。使我至此，不能無言。"]'),
('yuding-25','村行遇獵','貫休','唐','御定全唐诗','yuding','','[]','獵師紛紛走榛莽，女亦相隨把弓矢。南北東西盡殺心，',50,'御定全唐詩/json/826.json','["獵師紛紛走榛莽，女亦相隨把弓矢。南北東西盡殺心，", "傷嗟個輩亦是人，一生將此關身己。我聞天地之大德曰生，"]'),
('yuding-26','漁家','貫休','唐','御定全唐诗','yuding','','[]','赤蘆蓋屋低壓恰，沙漲柴門水痕疊。黃雞青犬花蒙籠，',48,'御定全唐詩/json/826.json','["赤蘆蓋屋低壓恰，沙漲柴門水痕疊。黃雞青犬花蒙籠，", "前山腳下得魚多，惡浪堆中盡頭睡。但得忘筌心自樂，"]'),
('yuding-27','田家作','貫休','唐','御定全唐诗','yuding','','[]','田家老翁無可作，晝甑蒸梨香漠漠。只向階前曝背眠，',48,'御定全唐詩/json/826.json','["田家老翁無可作，晝甑蒸梨香漠漠。只向階前曝背眠，", "自雲孫子解耕耘，四五年來腹多實。我聞此語心自悲，"]'),
('yuding-28','江邊祠','貫休','唐','御定全唐诗','yuding','','[]','松森森，江渾渾，江邊古祠空閉門。精靈應醉社日酒，',40,'御定全唐詩/json/826.json','["松森森，江渾渾，江邊古祠空閉門。精靈應醉社日酒，", "天符早晚下空碧，昨夜前村行霹靂。"]'),
('yuding-29','苦熱寄赤松道者','貫休','唐','御定全唐诗','yuding','','[]','天雲如燒人如炙，天地爐中更何適。蟬喘雷乾冰井融，',48,'御定全唐詩/json/826.json','["天雲如燒人如炙，天地爐中更何適。蟬喘雷乾冰井融，", "紫氣紅煙鮮的的，澗茗園瓜麹塵色，驕冷奢涼合相憶。"]'),
('yuding-30','偶作二首','貫休','唐','御定全唐诗','yuding','','[]','新詩一千首，古錦初下機。除月與鬼神，別未有人知。',132,'御定全唐詩/json/826.json','["新詩一千首，古錦初下機。除月與鬼神，別未有人知。", "子期去不返，浩浩良不悲。不知天地間，知者複是誰。", "門前數枝路，路路車馬鳴。名埃與利塵，千里萬里行。", "只見青山高，豈見青山平。朱門勢峨峨，冠蓋何光明。", "黃鳥在花裏，青蟬奪其聲。爾生非金玉，豈常貴複貞。", "寄言之子心，可以歸無形。"]'),
('yuding-31','夜夜曲','貫休','唐','御定全唐诗','yuding','','[]','蟪蛄切切風騷騷，芙蓉噴香蟾蜍高。',32,'御定全唐詩/json/826.json','["蟪蛄切切風騷騷，芙蓉噴香蟾蜍高。", "孤燈耿耿征婦勞，更深撲落金錯刀。"]'),
('yuding-32','春晚書山家屋壁二首','貫休','唐','御定全唐诗','yuding','','[]','柴門寂寂黍飯馨，山家煙火春雨晴。',72,'御定全唐詩/json/826.json','["柴門寂寂黍飯馨，山家煙火春雨晴。", "庭花濛濛水泠泠，小兒啼索樹上鶯。", "水香塘黑蒲森森，鴛鴦鸂鶒如家禽。前村後壟桑柘深，", "山翁留我宿又宿，笑指西坡瓜豆熟。"]'),
('yuding-33','春晚閒居寄陳嵩伯','貫休','唐','御定全唐诗','yuding','','[]','春霖閉門久，春色聚庭木。一夢辭舊山，四鄰有新哭。',48,'御定全唐詩/json/826.json','["春霖閉門久，春色聚庭木。一夢辭舊山，四鄰有新哭。", "菰蒲生白水，風篁擢纖玉。為憶湖上翁，花時獨冥目。"]'),
('yuding-34','長持經僧','貫休','唐','御定全唐诗','yuding','','[]','嘮嘮長夜坐，嘮嘮早起。杉森森，不見長，',33,'御定全唐詩/json/826.json','["嘮嘮長夜坐，嘮嘮早起。杉森森，不見長，", "傷嗟浮世之人，善事不曾入耳。"]'),
('yuding-35','茫茫曲','貫休','唐','御定全唐诗','yuding','','[]','茫茫複茫茫，滿眼皆埃塵。莫言白髮多，莖莖是愁筋。',56,'御定全唐詩/json/826.json','["茫茫複茫茫，滿眼皆埃塵。莫言白髮多，莖莖是愁筋。", "未達苦雕偽，及達多不仁。淺深與高低，盡能生棘榛。", "茫茫四大愁殺人。"]'),
('yuding-36','古鏡詞上劉侍郎','貫休','唐','御定全唐诗','yuding','','[]','至寶不自寶，照古還照今。仙人手胼胝，寥泬秋沉沉。',108,'御定全唐詩/json/826.json','["至寶不自寶，照古還照今。仙人手胼胝，寥泬秋沉沉。", "不是十二面，不是百煉金。若非八彩眉，不可輒照臨。", "即歸玉案頭，為君整冠簪。即居吾君手，照出天下心。", "恭聞太宗朝，此鏡當宸襟。六合懸清光，萬里無塵侵。", "此鏡今又出，天地還得一。"]'),
('yuding-37','送姜道士歸南嶽','貫休','唐','御定全唐诗','yuding','','[]','松品落落，雪格索索。眼有三角，頭峭五嶽。若不居嶽，',49,'御定全唐詩/json/826.json','["松品落落，雪格索索。眼有三角，頭峭五嶽。若不居嶽，", "萬里長風嘯一聲，九貞須拍黃金幾。落葉蕭蕭□杳□，"]'),
('yuding-38','了仙謠','貫休','唐','御定全唐诗','yuding','','[]','海中紫霧蓬萊島，安期子喬去何早。遊戲多騎白騏驎，',48,'御定全唐詩/json/826.json','["海中紫霧蓬萊島，安期子喬去何早。遊戲多騎白騏驎，", "始皇不得此深旨，遠遣徐福生憂惱。紫術黃精心上苗，"]'),
('yuding-0','循吏曲上王使君','貫休','唐','御定全唐诗','yuding','','[]','需宿需宿，炳爛光合。蒸蒸婺民，鐘此多福。自東自西，',50,'御定全唐詩/json/827.json','["需宿需宿，炳爛光合。蒸蒸婺民，鐘此多福。自東自西，", "大信不信，貽厥無朕。需女需女，爾亦須語。使君為理，"]'),
('yuding-1','古鏡詞','貫休','唐','御定全唐诗','yuding','','[]','我有一面鏡，新磨似秋月。上唯金膏香，下狀驪龍窟。',48,'御定全唐詩/json/827.json','["我有一面鏡，新磨似秋月。上唯金膏香，下狀驪龍窟。", "等閒不欲開，醜者多不悅。或問幾千年，軒轅手中物。"]'),
('yuding-2','懷張為、周樸','貫休','唐','御定全唐诗','yuding','','[]','張週二夫子，詩好人太癖。更不過嶺來，如今頭盡白。',61,'御定全唐詩/json/827.json','["張週二夫子，詩好人太癖。更不過嶺來，如今頭盡白。", "人傳禹力不到處，河聲流向西。又到處即閉戶，", "聖君在上知不知，赤面濁醪許多好。"]'),
('yuding-3','題弘顗三藏院','貫休','唐','御定全唐诗','yuding','','[]','儀清態淡雕瓊瑰，捲簾瀟灑無塵埃。嶽茶如乳庭花開，',48,'御定全唐詩/json/827.json','["儀清態淡雕瓊瑰，捲簾瀟灑無塵埃。嶽茶如乳庭花開，", "梵僧夢裏授微言，雪嶺白牛力深得。水精一索香一爐，"]'),
('yuding-4','古意代友人投所知','貫休','唐','御定全唐诗','yuding','','[]','青松雖有花，有花不如無。貧井泉雖清，且無金轆轤。',70,'御定全唐詩/json/827.json','["青松雖有花，有花不如無。貧井泉雖清，且無金轆轤。", "客從遠方來，遺我古銅鏡。掛之玉堂上，如對軒轅聖。", "天龍睡坤腹，土蝕金鬣綠。因知燕趙佳人顏似玉，"]'),
('yuding-5','聞知己入翰林','貫休','唐','御定全唐诗','yuding','','[]','天驥頭似鳥，倏忽四天下。南金色如椹，入火不見火。',60,'御定全唐詩/json/827.json','["天驥頭似鳥，倏忽四天下。南金色如椹，入火不見火。", "吾交二名士，遽立于帝左。鳳姿既出世，天意囑在我。", "奇哉子淵頌，無可無不可。"]'),
('yuding-6','上裴大夫二首','貫休','唐','御定全唐诗','yuding','','[]','我有一端綺，花彩鸞鳳群。佳人金錯刀，何以裁此文。',96,'御定全唐詩/json/827.json','["我有一端綺，花彩鸞鳳群。佳人金錯刀，何以裁此文。", "我有白雲琴，樸斫天地精。俚耳不使聞，慮同眾樂聽。", "指指法仙法，聲聲聖人聲。一彈四時和，再彈中古清。", "庭前梧桐枝，颯颯南風生。還希師曠懷，見我心不輕。"]'),
('yuding-7','上劉商州','貫休','唐','御定全唐诗','yuding','','[]','周邵籲噓氣，結為禎祥雲。客從遠方來，持此將贈君。',72,'御定全唐詩/json/827.json','["周邵籲噓氣，結為禎祥雲。客從遠方來，持此將贈君。", "時命偶不謬，授館終南東。愔愔良吏師，不寐如老農。", "丘軻文之天，代天有餘功。代天複代天，後稷何所從。"]'),
('yuding-8','閒居擬齊梁四首','貫休','唐','御定全唐诗','yuding','','[]','夜雨山草滋，爽籟生古木。閑吟竹仙偈，清于嚼金玉。',204,'御定全唐詩/json/827.json','["夜雨山草滋，爽籟生古木。閑吟竹仙偈，清于嚼金玉。", "蟋蟀啼壞牆，苟免悲局促。道人優曇花，迢迢遠山綠。", "果熟無低枝，芳香入屏帷。故人久不來，萱草何離離。", "苦吟齋貌減，更被杉風吹。獨賴湖上翁，時為烹露葵。", "紅藕映嘉魴，澄池照孤坐。池痕放文彩，雨氣增慵墮。", "山翁寄術藥，幸得秋病可。終召十七人，雲中備香火。", "清氣生滄洲，殘雲落林藪。放鶴久不歸，不知更歸否。", "支策到江湄，江皋木葉飛。自憐為客遠，還如鵲繞枝。", "南枝複北枝，玉露沾毛衣。"]'),
('yuding-9','塞上曲二首','貫休','唐','御定全唐诗','yuding','','[]','錦袷胡兒黑如漆，騎羊上冰如箭疾。蒲萄酒白雕臘紅，',88,'御定全唐詩/json/827.json','["錦袷胡兒黑如漆，騎羊上冰如箭疾。蒲萄酒白雕臘紅，", "一握黳髯一握絲，須知只為平戎術。", "去年轉鬥陰山腳，生得單于卻放卻。今年深入于不毛，", "甲穿雖即失黃金，劍缺猶能生紫氣。塞草萋萋兵士苦，"]'),
('yuding-10','擬齊梁體寄馮使君三首','貫休','唐','御定全唐诗','yuding','','[]','庭鳥多好音，相呼灌木中。竹房更何有，還如鳥巢空。',192,'御定全唐詩/json/827.json','["庭鳥多好音，相呼灌木中。竹房更何有，還如鳥巢空。", "賴逢富人侯，真東晉謝公。煌煌發令姿，珂佩鳴丁冬。", "故山有深霞，未如旌旗紅。慚非衛霍松，何以當清風。", "露益蟬聲長，蕙蘭垂紫帶。清吟待明月，孤雲忽為蓋。", "伊余石林人，本是燒畬輩。頻接謝公棋，輸多未曾賽。", "大道貴無心，聖賢為始慕。秋空共澄潔，美玉同貞素。", "偉哉桐江守，雌黃出金口。為文能廢興，談道弭空有。", "雪林槁枯者，坐石聽亦久。還疑紫磨身，成居靈運後。"]'),
('yuding-11','書匡山老僧庵','貫休','唐','御定全唐诗','yuding','','[]','筼簹紅實好鳥語，銀髯瘦僧貌如祖。香煙濛濛衣上聚，',24,'御定全唐詩/json/827.json','["筼簹紅實好鳥語，銀髯瘦僧貌如祖。香煙濛濛衣上聚，"]'),
('yuding-12','讀顧況歌行','貫休','唐','御定全唐诗','yuding','','[]','雪泥露金冰滴瓦，楓檉火著僧留坐。忽睹逋翁一軸歌，',70,'御定全唐詩/json/827.json','["雪泥露金冰滴瓦，楓檉火著僧留坐。忽睹逋翁一軸歌，", "妖狐爬出西子骨，雷車拶破織女機。憶昔鄱陽寺中見一碣，", "別，別，若非仙眼應難別。不可說，不可說，"]'),
('yuding-13','冬末病中作二首','貫休','唐','御定全唐诗','yuding','','[]','冬風吹草木，亦吹我病根。故人久不來，冷落如丘園。',180,'御定全唐詩/json/827.json','["冬風吹草木，亦吹我病根。故人久不來，冷落如丘園。", "聃龍與摩詰，籲歎非不聞。顧惟年少時，未合多憂勤。", "風鐘遠孤枕，雪水流凍痕。空餘微妙心，期空靜者論。", "胸中有一物，旅拒複攻擊。向下還上來，唯疑是肺石。", "山童頑且小，用之複何益。教洗煮茶鐺，雪團打鄰壁。", "宛轉無好姿，裴回更何適。庭前早梅樹，坐見花盡碧。", "屋老多鼠窠，窗卑露山脊。近來胸中物，已似輸藥力。", "微吟複微吟，依稀似莊舄。"]'),
('yuding-14','遇葉進士','貫休','唐','御定全唐诗','yuding','','[]','文章擬真宰，儀冠冷如璧。山寺偶相逢，眼青勝山色。',60,'御定全唐詩/json/827.json','["文章擬真宰，儀冠冷如璧。山寺偶相逢，眼青勝山色。", "氣隆多慷慨，語澹無他力。金繩殘果落，竹閣涼雨滴。", "自愧龍鍾人，見此沖天翼。"]'),
('yuding-15','寄杜使君','貫休','唐','御定全唐诗','yuding','','[]','清辰卷珠簾，盥漱香滿室。杉松經雪後，別有精彩出。',120,'御定全唐詩/json/827.json','["清辰卷珠簾，盥漱香滿室。杉松經雪後，別有精彩出。", "琅函芙蓉書，開之向階日。好鳥常解來，孤雲偶相失。", "有時作章句，氣概還鮮逸。茫茫世情世，誰人愛真實。", "清高慕玄度，宴默攀道一。殘磬隔風林，微陽解冰筆。", "亦知休明代，諒無經濟術。門前九個峰，終擬為文乞。"]'),
('yuding-16','寄高員外','貫休','唐','御定全唐诗','yuding','','[]','冷冽蒼黃風似劈，雪骨冰筋滿瑤席。庭松流汙相抵吃，',48,'御定全唐詩/json/827.json','["冷冽蒼黃風似劈，雪骨冰筋滿瑤席。庭松流汙相抵吃，", "倏忽維陽歲雲暮，寂寥不覺成章句。惟應將寄蕊珠宮，"]'),
('yuding-17','書陳處士屋壁二首','貫休','唐','御定全唐诗','yuding','','[]','有叟傲堯日，發白肌膚紅。妻子亦讀書，種蘭清溪東。',120,'御定全唐詩/json/827.json','["有叟傲堯日，發白肌膚紅。妻子亦讀書，種蘭清溪東。", "白雲有奇色，紫桂含天風。即應迎鶴書，肯羨于洞洪。", "高步前山前，高歌北山北。數載賣甘橙，山貲近雲足。", "新詩不將出，往往僧乞得。唯雲李太白，亦是偷桃賊。", "吟狂鬼神走，酒釅天地黑。青芻生階除，擷之束成束。"]'),
('yuding-18','對月作','貫休','唐','御定全唐诗','yuding','','[]','今人看此月，古人看此月。如何古人心，難向今人說。',76,'御定全唐詩/json/827.json','["今人看此月，古人看此月。如何古人心，難向今人說。", "古人求祿以及親，及親如之何？忠孝為朱輪。", "今人求祿唯庇身，庇身如之何？惡木多斜文。", "斜文複斜文，顛窒何紛紛。"]'),
('yuding-19','山茶花','貫休','唐','御定全唐诗','yuding','','[]','風裁日染開仙囿，百花色死猩血謬。',32,'御定全唐詩/json/827.json','["風裁日染開仙囿，百花色死猩血謬。", "今朝一朵墮階前，應有看人怨孫秀。"]'),
('yuding-20','上孫使君','貫休','唐','御定全唐诗','yuding','','[]','聖主得賢臣，天地方交泰。恭惟岳精粹，多出於昭代。',360,'御定全唐詩/json/827.json','["聖主得賢臣，天地方交泰。恭惟岳精粹，多出於昭代。", "君侯握文鏡，獨立塵埃外。王演俗容儀，崔陵小風概。", "馨香擁蘭雪，峻秀高嵩岱。嵇松領歲寒，莊劍無礱淬。", "威棱玉霜直，匠石金槌大。詩穿明月珠，道拍安期背。", "中興鸞鳳集，直道風雲會。萬卷似無書，三山如曆塊。", "德乎天所縱，清矣誰堪對。有法在朝端，無塵到冠蓋。", "具瞻從密勿，旦夕調鼎鼐。為君整衢尊，為君戢蕃塞。", "豈知吾後意，憂此毗陵最。親手賜彤弓，蒼生是繄賴。", "下車鄰寇散，是物冰壺內。龔遂愛廉平，次公太繁碎。", "袴襦砧動地，父母歌闤闠。□雪鎖戈鋋，非煙繞旌旆。", "寧思子產冰，肯羨任棠薤。忽如春再來，不獨天重戴。", "昂藏海嶠鶴，冷碧仙庭檜。物物動和氣，家家有新態。", "芙蓉開帟幕，錦帳無纖壒。鼓角穿凍雲，恩波動耕耒。", "奸回改精魄，禮教書紳帶。必於堯舜日，還似房杜輩。", "野人有章句，格力亦慷慨。若不入丘門，世間更誰愛。"]'),
('yuding-21','哭靈一上人','貫休','唐','御定全唐诗','yuding','','[]','一公何不在，空有遠公名。共說岑山路，今時不可行。',72,'御定全唐詩/json/827.json','["一公何不在，空有遠公名。共說岑山路，今時不可行。", "舊房松更老，新塔草初生。經論傳緇侶，文章遍墨卿。", "禪林枝幹折，法宇棟樑傾。誰俊修僧史，應知傳已成。"]'),
('yuding-22','行路難','貫休','唐','御定全唐诗','yuding','','[]','君不見山高海深人不測，古往今來轉青碧。',261,'御定全唐詩/json/827.json','["君不見山高海深人不測，古往今來轉青碧。", "淺近輕浮莫與交，地卑只解生荊棘。誰道黃金如糞土，", "不會當時作天地，剛有多般愚與智。到頭還用真宰心，", "義不義兮仁不仁，擬學長生更容易。負心為壚複為火，", "君不見道傍廢井生古木，本是驕奢貴人屋。", "幾度美人照影來，素綆銀瓶濯纖玉。雲飛雨散今如此，", "休說遺編行者幾，至竟終須合天理。敗他成此亦何功，", "九有茫茫共堯日，浪死虛生亦非一。清淨玄音竟不聞，", "君不見道傍樹有寄生枝，青青鬱鬱同榮衰。", "無情之物尚如此，為人不及還堪悲。父歸墳兮未朝夕，", "我聞忽如負芒刺，不獨為君空歎息。古人尺布猶可縫，", "若如此，不遄死兮更何俟。"]'),
('yuding-23','泊秋江','貫休','唐','御定全唐诗','yuding','','[]','岸如洞庭山似剡，船漾清溪涼勝簟。',32,'御定全唐詩/json/827.json','["岸如洞庭山似剡，船漾清溪涼勝簟。", "月白風高不得眠，枯葦叢邊釣師魘。"]'),
('yuding-24','嘲商客','貫休','唐','御定全唐诗','yuding','','[]','葦蕭蕭，風摵摵，落日江頭何處客。',32,'御定全唐詩/json/827.json','["葦蕭蕭，風摵摵，落日江頭何處客。", "斜倚帆檣不喚人，五湖浪向心中白。"]'),
('yuding-25','寄王滌','貫休','唐','御定全唐诗','yuding','','[]','梅月多開戶，衣裳潤欲滴。寂寥雖無形，不是小讎敵。',72,'御定全唐詩/json/827.json','["梅月多開戶，衣裳潤欲滴。寂寥雖無形，不是小讎敵。", "地虛草木壯，雨白桃李赤。永日無人來，庭花苦狼藉。", "吟高好鳥覷，風靜茶煙直。唯思萊子來，衣拖五般色。"]'),
('yuding-26','上馮使君五首','貫休','唐','御定全唐诗','yuding','','[]','撐船碧江上，春日何遲遲。汀花最深處，拾得鴛鴦兒。',121,'御定全唐詩/json/827.json','["撐船碧江上，春日何遲遲。汀花最深處，拾得鴛鴦兒。", "漁父無憂苦，水仙亦何別。眠在綠葦邊，不知釣筒發。", "樵叟無憂苦，地仙亦何別。茆屋岸花中，弄孫頭似雪。", "扣舷得新詩，茶煮桃花水。n5々數片帆，去去殊未已。", "仁政無不及，乳獺將子行。誰家苦竹林，中有讀書聲。"]'),
('yuding-27','擬君子有所思二首','貫休','唐','御定全唐诗','yuding','','[]','我愛正考甫，思賢作商頌。我愛揚子雲，理亂皆如鳳。',115,'御定全唐詩/json/827.json','["我愛正考甫，思賢作商頌。我愛揚子雲，理亂皆如鳳。", "振衣中夜起，露花香旖旎。撲碎驪龍明月珠，", "寂寥千載不相逢，無限區區盡虛擲。君不見沈約道，", "安得龍猛筆，點石為黃金。散為酷吏家，使無貪殘心。", "甘棠密葉成翠幄，款鳳不來天地塞。所以傾國傾城人，"]'),
('yuding-28','古塞下曲四首','貫休','唐','御定全唐诗','yuding','','[]','古塞腥膻地，胡兵聚如蠅。寒雕中髇石，落在黃河冰。',192,'御定全唐詩/json/827.json','["古塞腥膻地，胡兵聚如蠅。寒雕中髇石，落在黃河冰。", "蒼茫邏逤城，枿枿賊氣興。鑄金禱秋穹，還擬相憑陵。", "戰骨踐成塵，飛入征人目。黃雲忽變黑，戰鬼作陣哭。", "陰風吼大漠，火號出不得。誰為天子前，唱此邊城曲。", "日向平沙出，還向平沙沒。飛蓬落軍營，驚雕去天末。", "帝鄉青樓倚霄漢，歌吹掀天對花月。豈知塞上望鄉人，", "狼煙在陣雲，匈奴愛輕敵。領兵不知數，牛羊複吞磧。", "嚴冬大河枯，嫖姚去深擊。戰血染黃沙，風吹映天赤。"]'),
('yuding-29','鼓腹曲','貫休','唐','御定全唐诗','yuding','','[]','我昔不幸兮遭百罹，蒼蒼留我兮到好時。',90,'御定全唐詩/json/827.json','["我昔不幸兮遭百罹，蒼蒼留我兮到好時。", "耳聞鐘鼓兮生豐肌，白髮卻黑兮自不知。東鄰老人好吹笛，", "往往醉倒潢洿之水邊兮人盡識，孰雲六五帝兮四三皇。", "如夔如龍兮如龔黃，吾不知此之言兮是何之言兮。"]'),
('yuding-30','經曠禪師院','貫休','唐','御定全唐诗','yuding','','[]','吾師楞伽山中人，氣岸古淡僧麒麟。曹溪老兄一與語，',115,'御定全唐詩/json/827.json','["吾師楞伽山中人，氣岸古淡僧麒麟。曹溪老兄一與語，", "憶昔十四五年前苦寒節，禮師問師楞伽月。", "此時師握玉麈尾，報我卻雲非日月，一敲粉碎狂性歇。", "庭松無韻冷撼骨，搔窗擦簷數枝雪。邇來流浪于吳越，", "水檀香火遺影在，甘露松枝月中折。寶師往日真隱心，"]'),
('yuding-31','邊上作三首','貫休','唐','御定全唐诗','yuding','','[]','山無綠兮水無清，風既毒兮沙亦腥。',100,'御定全唐詩/json/827.json','["山無綠兮水無清，風既毒兮沙亦腥。", "胡兒走馬疾飛鳥，聯翩射落雲中聲。", "陣雲忽向沙中起，探得胡兵過遼水。", "堪嗟護塞征戍兒，未戰已疑身是鬼。", "見說青塚穴，中有白野狐。時時出沙磧，向東而號呼。", "號呼複號呼，畫師圖得無。"]'),
('yuding-32','送張拾遺赴施州司戶','貫休','唐','御定全唐诗','yuding','','[]','道之大道古太古，二字為名爭莽鹵。社稷安危在直言，',114,'御定全唐詩/json/827.json','["道之大道古太古，二字為名爭莽鹵。社稷安危在直言，", "一言偶未合堯聰，賈生須看湘江水。", "君不見頃者百官排闥赴延英，陽城不死存令名。", "又不見仲尼遙奇司馬子，佩玉垂紳合如此。", "公乎公乎施之掾，江上春風喜相見。畏天之命複行行，", "且啜千年羹，醉巴酒。"]'),
('yuding-33','書倪氏屋壁三首','貫休','唐','御定全唐诗','yuding','','[]','茶烹綠乳花映簾，撐沙苦筍銀纖纖。',96,'御定全唐詩/json/827.json','["茶烹綠乳花映簾，撐沙苦筍銀纖纖。", "窗中山色青翠粘，主人于我情無厭。", "白桑紅椹鶯咽咽，面揉玉塵餅挑雪。", "將為數日已一月，主人于我特地切。", "水嬌草媚掩山路，睡槎鴛鴦如畫作。", "春光靄靄忽已暮，主人剛地不放去。"]'),
('yuding-34','續姚梁公坐右銘','貫休','唐','御定全唐诗','yuding','','[]','善為爾諸身，行為爾性命。禍福必可轉，莫愨言前定。',188,'御定全唐詩/json/827.json','["善為爾諸身，行為爾性命。禍福必可轉，莫愨言前定。", "見人之得，如己之得，則美無不克。見人之失，如己之失，", "忠孝信行，越食逾衣。生天地間，未或非假。身危彩虹，", "豔殃爾壽須戒，酒腐爾腸須畏。勵志須至，撲滿必破。", "非莫非於飾非，過莫過於文過。及物陰功，子孫必封。", "無恃文學，是司奇薄。患隨不忍，害逐無足。一此一彼，", "毋擔虛譽，無背至理。恬和愻暢，沖融終始。", "天人之行，盡此而已。丁甯丁甯，戴發含齒。"]'),
('yuding-35','上盧少卿覓千文','貫休','唐','御定全唐诗','yuding','','[]','荊山有美玉，含華尚炳爛。堪為聖君璽，堪為聖君案。',60,'御定全唐詩/json/827.json','["荊山有美玉，含華尚炳爛。堪為聖君璽，堪為聖君案。", "草木潤不凋，煙霞覆不散。野人到山下，仰視星辰畔。", "倘或如栗黃，保之上霄漢。"]'),
('yuding-36','謝盧少卿惠千文','貫休','唐','御定全唐诗','yuding','','[]','廬山有石鏡，高倚無塵垢。晝景分煙蘿，夜魄侵星斗。',48,'御定全唐詩/json/827.json','["廬山有石鏡，高倚無塵垢。晝景分煙蘿，夜魄侵星斗。", "苞含物象列，搜照魚龍吼。寄謝天地間，毫端皆我有。"]'),
('yuding-0','大蜀皇帝壽春節進堯銘舜頌二首：堯銘','貫休','唐','御定全唐诗','yuding','','[]','金冊昭昭，列聖孤標。仲尼有言，巍巍帝堯。承天眷命，',100,'御定全唐詩/json/828.json','["金冊昭昭，列聖孤標。仲尼有言，巍巍帝堯。承天眷命，", "吾皇則之，小心翼翼。秉陽亭毒，不遑暇食。土階苔綠，", "漢高將將，太宗兵柄。吾皇則之，日新德盛。朽索六馬，", "既玉其葉，亦金其枝。葉葉枝枝，百工允厘。享國如堯，"]'),
('yuding-1','大蜀皇帝壽春節進堯銘舜頌二首：舜頌','貫休','唐','御定全唐诗','yuding','','[]','高高曆山，有黍有粟。皇皇大舜，合堯玄德。五典克從，',85,'御定全唐詩/json/828.json','["高高曆山，有黍有粟。皇皇大舜，合堯玄德。五典克從，", "吾皇則之，無斁無逸。綏厥品匯，光光得一。千輻臨頂，", "納隍孜孜，考考切切。六宗是禋，五瑞斯列。排麟環鳳，", "壽春亦然，萬年萬年。"]'),
('yuding-2','大蜀高祖潛龍日獻陳情偈頌','貫休','唐','御定全唐诗','yuding','','[]','有叟有叟，居嶽之室。忽振金湯，下彼巉崒。聞蜀風景，',75,'御定全唐詩/json/828.json','["有叟有叟，居嶽之室。忽振金湯，下彼巉崒。聞蜀風景，", "揭日月行，符湯禹出。天步孔艱，橫流犯蹕。穆穆蜀俗，", "無雨不膏，有露皆滴。有叟有叟，無實行實。一瓶一衲，"]'),
('yuding-3','寄大願和尚','貫休','唐','御定全唐诗','yuding','','[]','道朗居太山，達磨住熊耳。手擎清涼月，靈光溢天地。',168,'御定全唐詩/json/828.json','["道朗居太山，達磨住熊耳。手擎清涼月，靈光溢天地。", "盡騎金師子，去世久已矣。吾師隱廬嶽，外念全刳削。", "擲孔聖之日月，相空王之橐鑰。曾升麟德殿，譚無著，", "邇來便止于匡霍，瀑布千尋噴冷煙，旃檀一枝翹瘦鶴。", "峴首故人清信在，千書萬書取不諾。微人昔為門下人，", "一從散席歸寧後，溪寺更有誰相親。青山古木入白浪，", "桐江太守社中人，還送郤超米千石。寶書遽掩修章句，"]'),
('yuding-4','上顧大夫','貫休','唐','御定全唐诗','yuding','','[]','碧海漾仙洲，驪珠外無寶。一岳倚青冥，群山盡如草。',168,'御定全唐詩/json/828.json','["碧海漾仙洲，驪珠外無寶。一岳倚青冥，群山盡如草。", "君侯聖朝瑞，動只關玄造。誰雲倚天劍，含霜在懷抱。", "誰雲青雲險，門前是平道。洪民亦何幸，裏巷清如掃。", "至化無經綸，至神無祝禱。即應炳文柄，孤平去浩浩。", "即應調鼎味，比屋堪封保。野人慕正化，來自海邊島。", "經傳髻裏珠，詩學池中藻。閉門十餘載，庭杉共枯槁。", "今朝投至鑒，得不傾肝腦。斯文如未精，歸山更探討。"]'),
('yuding-5','寒月送玄士入天臺','貫休','唐','御定全唐诗','yuding','','[]','之子逍遙塵世薄，格淡於雲語如鶴。相見唯談海上山，',72,'御定全唐詩/json/828.json','["之子逍遙塵世薄，格淡於雲語如鶴。相見唯談海上山，", "僮擔赤籠密雪裏，世人無人留得之。想入紅霞路深邃，", "送君丁寧有深旨，好尋佛窟遊銀地。雪眉衲僧皆正氣，"]'),
('yuding-6','上杜使君','貫休','唐','御定全唐诗','yuding','','[]','為魚須處海，為木須在嶽。一登君子堂，頓覺心寥廓。',156,'御定全唐詩/json/828.json','["為魚須處海，為木須在嶽。一登君子堂，頓覺心寥廓。", "右聽青女鏡，左聽宣尼鐸。政術似蒲盧，詩情出沖漠。", "從來苦清苦，近更加澹薄。訟庭何所有，一隻兩隻鶴。", "煙霞色擁牆，禾黍香侵郭。嚴霜與美雨，皆從二天落。", "蒼生苦瘡痍，如何盡消削。聖君新雨露，更作誰恩渥。", "即捉五色筆，密勿金鑾角。即同房杜手，把乾坤橐鑰。", "休說蔔圭峰，開門對林壑。"]'),
('yuding-7','送僧入馬頭山','貫休','唐','御定全唐诗','yuding','','[]','馬頭寶峰，秀塞寒空。有叟有叟，真隱其中。無味醍醐，',41,'御定全唐詩/json/828.json','["馬頭寶峰，秀塞寒空。有叟有叟，真隱其中。無味醍醐，", "湯雪去，無人及，空望真氣江上立。"]'),
('yuding-8','上盧使君','貫休','唐','御定全唐诗','yuding','','[]','夔龍在廟堂，雖然有僉議。蒼生得父母，自是天之意。',180,'御定全唐詩/json/828.json','["夔龍在廟堂，雖然有僉議。蒼生得父母，自是天之意。", "鄱陽氣候正，文物皆鮮媚。金鏡有餘光，春風少閑地。", "膺門倚寒碧，到者寧容易。賓從皆鳳毛，爪牙悉猿臂。", "樓臺千萬戶，錦繡龍歌沸。大惠蟲鳥全，至嚴龍虎畏。", "可憐召伯樹，婆娑不勝翠。詩搜日月華，道咽神仙味。", "嘉樹白雀來，祥煙甘露墜。中川一帶香，□開幽邃地。", "逸少情有餘，東山境不啻。恭聞聖天子，廊廟猶虛位。", "應知黎庶心，只恐征書至。"]'),
('yuding-9','送顥雅禪師','貫休','唐','御定全唐诗','yuding','','[]','霜鋒擗石鳥雀聚，帆凍陰飆吹不舉。芬陀利香釋驎虎，',40,'御定全唐詩/json/828.json','["霜鋒擗石鳥雀聚，帆凍陰飆吹不舉。芬陀利香釋驎虎，", "苦卻樂，樂卻苦，盧至黃金忽如土。"]'),
('yuding-10','和楊使君游赤松山','貫休','唐','御定全唐诗','yuding','','[]','為郡三星無一事，龔黃意外扳喬松。日邊揚曆不爭路，',72,'御定全唐詩/json/828.json','["為郡三星無一事，龔黃意外扳喬松。日邊揚曆不爭路，", "捫蘿蓋輸山屐伴，駐旆不見朝霞濃。乳猿劇黠掛險樹，", "石羊依稀齕瑤草，桃花仿佛開仙宮。終當歸補吾君袞，"]'),
('yuding-11','送崔使君','貫休','唐','御定全唐诗','yuding','','[]','柳門柳門，芳草芊綿。日日日日，黯然黯然。',117,'御定全唐詩/json/828.json','["柳門柳門，芳草芊綿。日日日日，黯然黯然。", "子牟戀闕歸闕，王粲下樓相別。食實得地，頗淹歲月。", "今朝天子在上，合雪必雪。況絳之牧，文行炳潔。", "釋謂緣因，久昵清塵。王嘉迎安，遠狎遺民。嫓彼二子，", "麟步規矩，鳳翥昂枿。峴首仁蹤項頻跋，商雲乳麝香可撮，"]'),
('yuding-12','杜侯行','貫休','唐','御定全唐诗','yuding','','[]','天目連天搏秀氣，崢嶸作起新城地。德門鐘秀光盛時，',178,'御定全唐詩/json/828.json','["天目連天搏秀氣，崢嶸作起新城地。德門鐘秀光盛時，", "江表唯傳君子營，劍沖牛鬥疏真宰。金昆玉季輕三鼓，", "我聞大中咸通真令主，相惟大杜兼小杜。", "但能致君活國濟生人，亦何必須踏金梯，折桂樹。", "宣宗懿宗調舜琴，大杜小杜為殷霖。出將入相兮功德深，", "常言一呼百萬何足雲，終取封侯之印大如鬥。", "恭聞吾皇似堯禹，搜索賢良皆面睹。杜侯杜侯，", "人之戴兮天筆注，國之福兮天固祚。四海無波八表臣，"]'),
('yuding-13','偶作五首','貫休','唐','御定全唐诗','yuding','','[]','誰信心火多，多能焚大國。誰信鬢上絲，莖莖出蠶腹。',308,'御定全唐詩/json/828.json','["誰信心火多，多能焚大國。誰信鬢上絲，莖莖出蠶腹。", "嘗聞養蠶婦，未曉上桑樹。下樹畏蠶饑，兒啼亦不顧。", "一春膏血盡，豈止應王賦。如何酷吏酷，盡為搜將去。", "蠶蛾為蝶飛，偽葉空滿枝。冤梭與恨機，一見一沾衣。", "機生機，巧生巧，心鑊烘烘日煎炒。闖蜀眉嚬遊海島，", "孰雲我輕薄，石頭如何喚作玉。孰雲我是非，", "豈不見大鵬點翼蓋十洲，是何之物鳴啾啾。", "君子食即食，何必在珍華。小人食不食，縱食如泥沙。", "清歌且莫唱，妙舞亦休誇。爾非鳳炙麒麟肉，", "君不見金陵風台月榭煙霞光，如今五裏十裏野火燒茫茫。", "君不見西施綠珠顏色可傾國，樂極悲來留不得。", "君不見漢王力盡得乾坤，如何秋雨灑廟門。", "銅台老樹作精魅，金穀野狐多子孫。幾許繁華幾更改，", "茫茫欲火欲燒人，惆悵無因為君說。"]'),
('yuding-14','山中作','貫休','唐','御定全唐诗','yuding','','[]','山為水精宮，藉花無塵埃。吟狂嶽似動，筆落天瓊瑰。',44,'御定全唐詩/json/828.json','["山為水精宮，藉花無塵埃。吟狂嶽似動，筆落天瓊瑰。", "伊余自樂道，不論才不才。有時鬼笑兩三聲，"]'),
('yuding-15','聞前王使君在澤潞居','貫休','唐','御定全唐诗','yuding','','[]','為善無近名，竊名者得聲不如心，誠哉是言也。',161,'御定全唐詩/json/828.json','["為善無近名，竊名者得聲不如心，誠哉是言也。", "使君聖朝瑞，幹符初刺婺。德變人性靈，筆變人風土。", "煙霞與蟲鳥，和氣將美雨。千里與萬里，各各來相附。", "信哉有良吏，玄讖應百數。古人古人自古人，", "攀轅既不及，旌旆沖風露。大駕已西幸，飄零何處去。", "婺人空悲哀，對生祠泣沾莓苔。忽聞暫寄河之北，", "使四野霧廓，八紘鏡開。皇天無親，長與善鄰，宜哉宜哉。"]'),
('yuding-16','將入匡山別芳晝二公二首','貫休','唐','御定全唐诗','yuding','','[]','噴嵐堆黛塞寒碧，窗前古雪如白石。',64,'御定全唐詩/json/828.json','["噴嵐堆黛塞寒碧，窗前古雪如白石。", "臨岐約我來不來，若來須撥紅霞覓。", "紅豆樹間滴紅雨，戀師不得依師住。", "世情世界愁殺人，錦繡穀中歸舍去。"]'),
('yuding-17','送楊秀才','貫休','唐','御定全唐诗','yuding','','[]','北山峨峨香拂拂，翠漲青奔勢巉崒。赤松君宅在其中，',122,'御定全唐詩/json/828.json','["北山峨峨香拂拂，翠漲青奔勢巉崒。赤松君宅在其中，", "水精簾卷桃花開，文錦娉婷眾非一。撫長離，坎答鼓。", "花姑吹簫，弄玉起舞。三萬八千為半日，海涸鼇枯等閒睹。", "愛共安期棋，苦識彭祖祖。有時朝玉京，紅雲擁金虎。", "石橋亦是神仙住，白鳳飛來又飛去。五雲縹緲羽翼高，"]'),
('yuding-18','別杜將軍','貫休','唐','御定全唐诗','yuding','','[]','伊余本是胡為者，采蕈鋤茶在窮野。偶披蓑笠事空王，',73,'御定全唐詩/json/828.json','["伊余本是胡為者，采蕈鋤茶在窮野。偶披蓑笠事空王，", "遽逢天步艱難日，深藏溪穀空長歎。偶出重圍遇英哲，", "東風來兮歌式微，深雲道人召來歸。燕辭大廈兮將何為，"]'),
('yuding-19','送夢上人歸京','貫休','唐','御定全唐诗','yuding','','[]','伊餘龍鍾歸海涯，千山萬水情自怡。夢公別我還上國，',48,'御定全唐詩/json/828.json','["伊餘龍鍾歸海涯，千山萬水情自怡。夢公別我還上國，", "前程勝事未可涯，但恐圭峰難入手。蓮峰掌記韓拾遺，"]'),
('yuding-20','問岳禪師疾','貫休','唐','御定全唐诗','yuding','','[]','世病如山嶽，世醫皆拱手。道病如金鎖，師遭鎖鎖否。',73,'御定全唐詩/json/828.json','["世病如山嶽，世醫皆拱手。道病如金鎖，師遭鎖鎖否。", "伊昔芙蓉頰，談經似主涉。蘇合晝氤氳，天花似飛蝶。", "覺樹垂實，魔輩刺疾。病也不問，終不皴膝。春光冉冉，"]'),
('yuding-21','上荊南府主三讓德政碑','貫休','唐','御定全唐诗','yuding','','[]','明明赫赫中興主，動納諸隍冠前古。四海英雄盡戢兵，',91,'御定全唐詩/json/828.json','["明明赫赫中興主，動納諸隍冠前古。四海英雄盡戢兵，", "一從寇滅二十年，琬琰雕鐫賜重疊。荊州化風何卓異，", "君侯捧碑西拜泣，臣且何人恩洊及。鳳凰銜下雕龍文，", "我恐江淹五色筆，作不立此碑之碑文不得。"]'),
('yuding-22','施萬病丸','貫休','唐','御定全唐诗','yuding','','[]','我聞昔有海上翁，鬚眉皎白塵土中。葫蘆盛藥行如風，',48,'御定全唐詩/json/828.json','["我聞昔有海上翁，鬚眉皎白塵土中。葫蘆盛藥行如風，", "玉毫調禦偏讚揚，金輪釋梵咸歸禮。賢守運心亦相似，"]'),
('yuding-23','甘雨應祈','貫休','唐','御定全唐诗','yuding','','[]','春雨偶愆期，草木亦未覺。君侯不遑處，退食或閉閣。',96,'御定全唐詩/json/828.json','["春雨偶愆期，草木亦未覺。君侯不遑處，退食或閉閣。", "東海浪滔滔，西江波漠漠。得不願身為大虯，金其角，", "使不蘇者蘇，不足者足。情通上玄，如膏綿綿。有叟有叟，", "乳女啼兮，蒸黍馨兮。炙背捫虱兮，複何經營兮。"]'),
('yuding-24','寄韓團練','貫休','唐','御定全唐诗','yuding','','[]','真宰動洪爐，萬物皆消息。唯有三珠樹，不用東風力。',168,'御定全唐詩/json/828.json','["真宰動洪爐，萬物皆消息。唯有三珠樹，不用東風力。", "君子天廟器，頭骨何巉崱。海內久聞名，江西偶相識。", "誰不有詩機，麟龍不解織。誰不有心地，蘭茝不曾植。", "多君二俱作，獨立千仞壁。話道出先天，憑師動臻極。", "青霄雁行律，紅露荊花滴。偶然成遠別，別後長相憶。", "行至鄱陽郡，又見謝安石。留我遇殘冬，身心苦恬寂。", "江上春又至，引頸山空積。何日再相逢，天香滿瑤席。"]'),
('yuding-25','春野作五首','貫休','唐','御定全唐诗','yuding','','[]','閒步淺青平綠，流水征車自逐。',124,'御定全唐詩/json/828.json','["閒步淺青平綠，流水征車自逐。", "誰家挾彈少年，擬打紅衣啄木。", "山花雨打盡，滿地如爛錦。遠尋鷓鴣雛，拾得一團蕈。", "大牛苦耕田，乳犢望似泣。萬事皆天意，綠草頭蕺蕺。", "斜陽射破塚，髑髏半出地。不知誰氏子，獨自作意氣。", "牛兒小，牛女少，拋牛沙上鬥百草。鉏隴老人又太老，"]'),
('yuding-26','深山逢老僧二首','貫休','唐','御定全唐诗','yuding','','[]','衲衣線粗心似月，自把短鋤鋤榾柮。',64,'御定全唐詩/json/828.json','["衲衣線粗心似月，自把短鋤鋤榾柮。", "青石溪邊踏葉行，數片雲隨兩眉雪。", "山童貌頑名乞乞，放火燒畬采崖蜜。", "擔頭何物帶山香，一籮白蕈一籮栗。"]'),
('yuding-27','道情偈','貫休','唐','御定全唐诗','yuding','','[]','草木亦有性，與我將不別。我若似草木，成道無時節。',48,'御定全唐詩/json/828.json','["草木亦有性，與我將不別。我若似草木，成道無時節。", "世人不會道，向道卻嗔道。傷嗟此輩人，寶山不得寶。"]'),
('yuding-28','懷二三朝友','貫休','唐','御定全唐诗','yuding','','[]','傷心複傷心，流光似飛電。有惠驪龍十斛珠，',42,'御定全唐詩/json/828.json','["傷心複傷心，流光似飛電。有惠驪龍十斛珠，", "有惠黃金一萬斤，不如一見於仁人。我昔讀詩書，"]'),
('yuding-29','偶作','貫休','唐','御定全唐诗','yuding','','[]','君子稱一善，馨香遍九垓。小人妒一善，處處生嫌猜。',60,'御定全唐詩/json/828.json','["君子稱一善，馨香遍九垓。小人妒一善，處處生嫌猜。", "口如暴死人，鐵尺拗不開。稂莠蝕田髓，積陰成冬雷。", "因知咋舌人，千古空悠哉。"]'),
('yuding-30','義士行','貫休','唐','御定全唐诗','yuding','','[]','先生先生不可遇，愛平不平眉鬥豎。',32,'御定全唐詩/json/828.json','["先生先生不可遇，愛平不平眉鬥豎。", "黃昏雨雹空似黳，別我不知何處去。"]'),
('yuding-31','觀懷素草書歌','貫休','唐','御定全唐诗','yuding','','[]','張顛顛後顛非顛，直至懷素之顛始是顛。師不譚經不說禪，',237,'御定全唐詩/json/828.json','["張顛顛後顛非顛，直至懷素之顛始是顛。師不譚經不說禪，", "鐵石畫兮墨須入，金尊竹葉數鬥餘。半斜半傾山衲濕，", "羅刹石上坐伍子胥，蒯通八字立對漢高祖。", "勢崩騰兮不可止，天機暗轉鋒鋩裏。閃電光邊霹靂飛，", "乍如沙場大戰後，斷槍橛箭皆狼藉。又似深山朽石上，", "或細微，仙衣半拆金線垂。或妍媚，桃花半紅公子醉。", "我恐山為墨兮磨海水，天與筆兮書大地，乃能略展狂僧意。", "常恨與師不相識，一見此書空歎息。伊昔張渭任華葉季良，", "石橋被燒燒，良玉土不蝕，錐畫沙兮印印泥。", "世人世人爭得測，知師雄名在世間，明月清風有何極。"]'),
('yuding-32','送盧舍人三首','貫休','唐','御定全唐诗','yuding','','[]','一曰：勸君不用登峴首山，讀羊祜碑，男兒事業須自奇。',205,'御定全唐詩/json/828.json','["一曰：勸君不用登峴首山，讀羊祜碑，男兒事業須自奇。", "此碑山頭如日月，日日照人人不知。人不知，", "二曰：勸君登商山，不用覓商山皓，雲深雪深騾馬倒。", "我願終南太華變為金，吾後見之不為寶。我願九州四海紙，", "三曰：君不見釋梵諸天壽億垓，天上人間去複來。", "君又不見紫金為輪一千幅，寶洲□四皆臣伏。", "輪王釋梵作何因，只是弘隆重大乘福。自古皇王與賢哲，", "君不見近代韋裴蔣與蕭，文房書府師百僚。", "代天理物映千古，布發掩泥非一朝。大哉釋梵輪王璞，"]'),
('yuding-33','宿深村','貫休','唐','御定全唐诗','yuding','','[]','行行一宿深村裏，雞犬豐年鬧如市。',32,'御定全唐詩/json/828.json','["行行一宿深村裏，雞犬豐年鬧如市。", "黃昏見客闔家喜，月下取魚戽塘水。"]'),
('yuding-34','黃鶯','貫休','唐','御定全唐诗','yuding','','[]','一種為春禽，花中開羽翼。如何此鳥身，便是黃金色。',36,'御定全唐詩/json/828.json','["一種為春禽，花中開羽翼。如何此鳥身，便是黃金色。", "黃金色，若逢竹實終不食。"]'),
('yuding-35','送越將歸會稽','貫休','唐','御定全唐诗','yuding','','[]','面如玉盤身八尺，燕語清獰戰袍窄。古岳龍腥一匣霜，',40,'御定全唐詩/json/828.json','["面如玉盤身八尺，燕語清獰戰袍窄。古岳龍腥一匣霜，", "他年必帥邯鄲兒，與我殺輕班定遠。"]'),
('yuding-36','別仙客','貫休','唐','御定全唐诗','yuding','','[]','巨鼇頭縮翻仙翠，蟠桃爛落珊瑚地。',32,'御定全唐詩/json/828.json','["巨鼇頭縮翻仙翠，蟠桃爛落珊瑚地。", "浪濺霓旌濕鵬翅，略別千年太容易。"]'),
('yuding-37','寒江上望','貫休','唐','御定全唐诗','yuding','','[]','荒岸燒未死，白雲癡不動。極目無人行，浪打取魚籠。',24,'御定全唐詩/json/828.json','["荒岸燒未死，白雲癡不動。極目無人行，浪打取魚籠。"]'),
('yuding-38','讀唐史','貫休','唐','御定全唐诗','yuding','','[]','我愛李景伯，內宴執良規。君臣道昭彰，天顏終熙怡。',60,'御定全唐詩/json/828.json','["我愛李景伯，內宴執良規。君臣道昭彰，天顏終熙怡。", "大簸怕清風，糠秕繚亂飛。洪爐烹五金，黃金終自奇。", "大哉為忠臣，舍此何所之。"]'),
('yuding-39','樵叟','貫休','唐','御定全唐诗','yuding','','[]','樵父貌饑帶塵土，自言一生苦寒苦。',32,'御定全唐詩/json/828.json','["樵父貌饑帶塵土，自言一生苦寒苦。", "擔頭擔個赤瓷罌，斜陽獨立蒙籠塢。"]'),
('yuding-0','春山行','貫休','唐','御定全唐诗','yuding','','[]','重疊太古色，濛濛花雨時。好峰行恐盡，流水語相隨。',48,'御定全唐詩/json/829.json','["重疊太古色，濛濛花雨時。好峰行恐盡，流水語相隨。", "黑壤生紅黍，黃猿領白兒。因思石橋月，曾與故人期。"]'),
('yuding-1','送諫官南遷','貫休','唐','御定全唐诗','yuding','','[]','危行危言者，從天落海涯。如斯為遠客，始是好男兒。',48,'御定全唐詩/json/829.json','["危行危言者，從天落海涯。如斯為遠客，始是好男兒。", "瘴雜交州雨，犀揩馬援碑。不知千萬里，誰複識辛毗。"]'),
('yuding-2','懷香爐峰道人','貫休','唐','御定全唐诗','yuding','','[]','常思峰頂叟，石窟土為床。日日先見日，煙霞多異香。',48,'御定全唐詩/json/829.json','["常思峰頂叟，石窟土為床。日日先見日，煙霞多異香。", "冥心同槁木，掃雪帶微陽。終必相尋去，斯人不可忘。"]'),
('yuding-3','觀李翰林真二首','貫休','唐','御定全唐诗','yuding','','[]','日角浮紫氣，凜然塵外清。雖稱李太白，知是那星精。',96,'御定全唐詩/json/829.json','["日角浮紫氣，凜然塵外清。雖稱李太白，知是那星精。", "禦宴千鐘飲，蕃書一筆成。宜哉杜工部，不錯道騎鯨。", "誰氏子丹青，毫端曲有靈。屹如山忽墮，爽似酒初醒。", "天馬難攏勒，仙房久閉扃。若非如此輩，何以傲彤庭。"]'),
('yuding-4','晚泊湘江作','貫休','唐','御定全唐诗','yuding','','[]','煙浪漾秋色，高吟似有鄰。一輪湘渚月，萬古獨醒人。',48,'御定全唐詩/json/829.json','["煙浪漾秋色，高吟似有鄰。一輪湘渚月，萬古獨醒人。", "岸濕穿花遠，風香禱廟頻。只應諛佞者，到此不傷神。"]'),
('yuding-5','淮上逢故人','貫休','唐','御定全唐诗','yuding','','[]','故園離亂後，十載始逢君。長恨南熏奏，尋常只自聞。',48,'御定全唐詩/json/829.json','["故園離亂後，十載始逢君。長恨南熏奏，尋常只自聞。", "荒窗秋見嶽，赤地夜生雲。莫歎謀身晚，中興正用文。"]'),
('yuding-6','《讀杜工部集》二首','貫休','唐','御定全唐诗','yuding','','[]','造化拾無遺，唯應杜甫詩。豈非玄域橐，奪得古人旗。',96,'御定全唐詩/json/829.json','["造化拾無遺，唯應杜甫詩。豈非玄域橐，奪得古人旗。", "日月精華薄，山川氣概卑。古今吟不盡，惆悵不同時。", "甫也道亦喪，孤身出蜀城。彩毫終不撅，白雪更能輕。", "命薄相如命，名齊李白名。不知耒陽令，何以葬先生。"]'),
('yuding-7','題簡禪師院','貫休','唐','御定全唐诗','yuding','','[]','機忘室亦空，靜與沃洲同。唯有半庭竹，能生竟日風。',48,'御定全唐詩/json/829.json','["機忘室亦空，靜與沃洲同。唯有半庭竹，能生竟日風。", "思山海月上，出定印香終。繼後傳衣者，還須立雪中。"]'),
('yuding-8','讀劉得仁、賈島集二首','貫休','唐','御定全唐诗','yuding','','[]','二公俱作者，其奈亦迂儒。且有諸峰在，何將一第籲。',96,'御定全唐詩/json/829.json','["二公俱作者，其奈亦迂儒。且有諸峰在，何將一第籲。", "句還如菡萏，誰複贈襜褕。想得重泉下，依前與眾殊。", "役思曾沖尹，多言阻國親。桂枝何所直，陋巷不勝貧。", "馬病唯湯雪，門荒劣有人。伊餘吟亦苦，為爾一眉嚬。"]'),
('yuding-9','天臺老僧','貫休','唐','御定全唐诗','yuding','','[]','獨住無人處，松龕嶽色侵。僧中九十臘，雲外一生心。',48,'御定全唐詩/json/829.json','["獨住無人處，松龕嶽色侵。僧中九十臘，雲外一生心。", "白髮垂不剃，青眸笑轉深。猶能指孤月，為我暫開襟。"]'),
('yuding-10','經費隱君舊宅','貫休','唐','御定全唐诗','yuding','','[]','巉岩玉九株，秀濕掩蒼梧。祥瑞久不出，羲軒消得無。',48,'御定全唐詩/json/829.json','["巉岩玉九株，秀濕掩蒼梧。祥瑞久不出，羲軒消得無。", "雨和高瀑濁，燒熁大櫧枯。到此思歸去，迢迢隔五湖。"]'),
('yuding-11','秋末懷舊山','貫休','唐','御定全唐诗','yuding','','[]','昔住匡廬北，無人知姓名。侵雲收穀粟，引蟻上柑橙。',48,'御定全唐詩/json/829.json','["昔住匡廬北，無人知姓名。侵雲收穀粟，引蟻上柑橙。", "寒雨雪兼落，枯林虎獨行。誰能將白髮，共向此中生。"]'),
('yuding-12','春過鄱陽湖','貫休','唐','御定全唐诗','yuding','','[]','百慮片帆下，風波極目看。吳山兼鳥沒，楚色入衣寒。',48,'御定全唐詩/json/829.json','["百慮片帆下，風波極目看。吳山兼鳥沒，楚色入衣寒。", "過此愁人處，始知行路難。夕陽沙島上，回首一長歎。"]'),
('yuding-13','寄僧野和尚','貫休','唐','御定全唐诗','yuding','','[]','鳥外更誰親，諸峰即四鄰。白頭寒枕石，青衲爛無塵。',48,'御定全唐詩/json/829.json','["鳥外更誰親，諸峰即四鄰。白頭寒枕石，青衲爛無塵。", "橡栗堆行徑，猿猴繞定身。儻然重結社，願作掃壇人。"]'),
('yuding-14','寄馮使君','貫休','唐','御定全唐诗','yuding','','[]','端居碧雲暮，好鳥啼紅芳。滿郭桃李熟，捲簾風雨香。',48,'御定全唐詩/json/829.json','["端居碧雲暮，好鳥啼紅芳。滿郭桃李熟，捲簾風雨香。", "清吟繡段句，默念芙蓉章。未得歸山去，頻升謝守堂。"]'),
('yuding-15','寄紫閣隱者','貫休','唐','御定全唐诗','yuding','','[]','積翠藏一叟，常思未得遊。不知在岩下，為複在峰頭。',48,'御定全唐詩/json/829.json','["積翠藏一叟，常思未得遊。不知在岩下，為複在峰頭。", "苔上枯藤笐，泉淋破石樓。伊余更何事，不學此翁休。"]'),
('yuding-16','寄天臺道友','貫休','唐','御定全唐诗','yuding','','[]','大是清虛地，高吟到日晡。水聲金磬亂，雲片玉盤粗。',120,'御定全唐詩/json/829.json','["大是清虛地，高吟到日晡。水聲金磬亂，雲片玉盤粗。", "仙有遺蹤在，人還得意無。石碑文不直，壁畫色多枯。", "冷立千年鶴，閑燒六一爐。松枝垂似物，山勢秀難圖。", "紫府程非遠，清溪徑不迂。馨香柏上露，皎潔水中珠。", "賢聖無他術，圓融只在吾。寄言桐柏子，珍重保之乎。"]'),
('yuding-17','旅中懷孫路','貫休','唐','御定全唐诗','yuding','','[]','暮塵微雨收，蟬急楚鄉秋。一片月出海，幾家人上樓。',48,'御定全唐詩/json/829.json','["暮塵微雨收，蟬急楚鄉秋。一片月出海，幾家人上樓。", "砌香殘果落，汀草宿煙浮。唯有知音者，相思歌白頭。"]'),
('yuding-18','貽世','貫休','唐','御定全唐诗','yuding','','[]','至理不誤物，悠悠自不明。黃金燒欲盡，白發火邊生。',49,'御定全唐詩/json/829.json','["至理不誤物，悠悠自不明。黃金燒欲盡，白發火邊生。", "苦惑神仙cX，難收日月精。捕風兼系影，信矣不須爭。"]'),
('yuding-19','覽李秀才卷','貫休','唐','御定全唐诗','yuding','','[]','香沐整山衣，開君一軸詩。吟當秋景苦，味出雪林遲。',48,'御定全唐詩/json/829.json','["香沐整山衣，開君一軸詩。吟當秋景苦，味出雪林遲。", "經濟幾人到，工夫兩鬢知。因嗟和氏淚，不是等閒垂。"]'),
('yuding-20','懷方幹、張為','貫休','唐','御定全唐诗','yuding','','[]','冥搜入仙窟，半夜水堂前。吾道只如此，古人多亦然。',48,'御定全唐詩/json/829.json','["冥搜入仙窟，半夜水堂前。吾道只如此，古人多亦然。", "螢沈荒塢霧，月苦綠梧蟬。因憶垂綸者，滄浪何處邊。"]'),
('yuding-21','四皓圖','貫休','唐','御定全唐诗','yuding','','[]','何人圖四皓，如語話嘮嘮。雙鬢雪相似，是誰年最高。',48,'御定全唐詩/json/829.json','["何人圖四皓，如語話嘮嘮。雙鬢雪相似，是誰年最高。", "溪苔連豹褥，仙酒汙雲袍。想得忘秦日，伊餘亦合逃。"]'),
('yuding-22','懷白閣道侶','貫休','唐','御定全唐诗','yuding','','[]','寒思白閣層，石屋兩三僧。斜雪掃不盡，饑猿喚得應。',48,'御定全唐詩/json/829.json','["寒思白閣層，石屋兩三僧。斜雪掃不盡，饑猿喚得應。", "香然一字火，磬過數潭冰。終必相尋去，孤懷久不勝。"]'),
('yuding-23','讀孟郊集','貫休','唐','御定全唐诗','yuding','','[]','東野子何之，詩人始見詩。清刳霜雪髓，吟動鬼神司。',48,'御定全唐詩/json/829.json','["東野子何之，詩人始見詩。清刳霜雪髓，吟動鬼神司。", "舉世言多媚，無人師此師。因知吾道後，冷淡亦如斯。"]'),
('yuding-24','懷四明亮公','貫休','唐','御定全唐诗','yuding','','[]','孤峰含紫煙，師住此安禪。不下便不下，如斯太可憐。',48,'御定全唐詩/json/829.json','["孤峰含紫煙，師住此安禪。不下便不下，如斯太可憐。", "坐侵天井黑，吟久海霞蔫。豈覺塵埃裏，干戈已十年。"]'),
('yuding-25','秋過錢塘江','貫休','唐','御定全唐诗','yuding','','[]','巨浸東隅極，山吞大野平。因知吳相恨，不盡海濤聲。',48,'御定全唐詩/json/829.json','["巨浸東隅極，山吞大野平。因知吳相恨，不盡海濤聲。", "黑氣騰蛟窟，秋雲入戰城。遊人千萬里，過此白髭生。"]'),
('yuding-26','上俞許二判官','貫休','唐','御定全唐诗','yuding','','[]','近拋蓑笠者，急善遇休明。未省親宗伯，焉能識正聲。',48,'御定全唐詩/json/829.json','["近拋蓑笠者，急善遇休明。未省親宗伯，焉能識正聲。", "病容經夏在，嶽夢入秋並。無限林中意，今逢許郭傾。"]'),
('yuding-27','懷劉得仁','貫休','唐','御定全唐诗','yuding','','[]','詩名動帝畿，身謝亦因詩。白日只如哭，皇天得不知。',49,'御定全唐詩/json/829.json','["詩名動帝畿，身謝亦因詩。白日只如哭，皇天得不知。", "旅墳孤fb嶽，羸僕泣如兒。多少求名者，聞之淚盡垂。"]'),
('yuding-28','歸故林後寄二三知己','貫休','唐','御定全唐诗','yuding','','[]','昨別楚江邊，逡巡早數年。詩雖清到後，人更瘦於前。',48,'御定全唐詩/json/829.json','["昨別楚江邊，逡巡早數年。詩雖清到後，人更瘦於前。", "岸翠連喬岳，汀沙入壞田。何時重一見，談笑有茶煙。"]'),
('yuding-29','春寄西山陳陶','貫休','唐','御定全唐诗','yuding','','[]','搔首複搔首，孤懷草萋萋。春光已滿目，君在西山西。',48,'御定全唐詩/json/829.json','["搔首複搔首，孤懷草萋萋。春光已滿目，君在西山西。", "塹水成文去，庭柯擎翠低。所思不可見，黃鳥花中啼。"]'),
('yuding-30','秋末江行','貫休','唐','御定全唐诗','yuding','','[]','四顧木落盡，扁舟增所思。雲沖遠燒出，帆轉大荒遲。',48,'御定全唐詩/json/829.json','["四顧木落盡，扁舟增所思。雲沖遠燒出，帆轉大荒遲。", "天際霜雪作，水邊蒿艾衰。斷猿不堪聽，一聽亦同悲。"]'),
('yuding-31','送人歸新羅','貫休','唐','御定全唐诗','yuding','','[]','昨夜西風起，送君歸故鄉。積愁窮地角，見日上扶桑。',48,'御定全唐詩/json/829.json','["昨夜西風起，送君歸故鄉。積愁窮地角，見日上扶桑。", "蜃氣生初霽，潮痕匝亂荒。從茲頭各白，魂夢一相望。"]'),
('yuding-32','思匡山賈匡','貫休','唐','御定全唐诗','yuding','','[]','山兄詩癖甚，寒夜更何為。覓句唯頑坐，嚴霜打不知。',48,'御定全唐詩/json/829.json','["山兄詩癖甚，寒夜更何為。覓句唯頑坐，嚴霜打不知。", "石膏粘木屐，崖蜜落冰池。近見禪僧說，生涯勝往時。"]'),
('yuding-33','偶作','貫休','唐','御定全唐诗','yuding','','[]','十載獨扃扉，唯為二雅詩。道孤終不雜，頭白更何疑。',48,'御定全唐詩/json/829.json','["十載獨扃扉，唯為二雅詩。道孤終不雜，頭白更何疑。", "句冷杉松與，霜嚴鼓角知。修心對閑鏡，明月印秋池。"]'),
('yuding-34','贈方幹','貫休','唐','御定全唐诗','yuding','','[]','盛名與高隱，合近謝敷村。弟子已得桂，先生猶灌園。',48,'御定全唐詩/json/829.json','["盛名與高隱，合近謝敷村。弟子已得桂，先生猶灌園。", "垂綸侵海介，拾句曆雲根。白日升天路，如君別有門。"]'),
('yuding-35','漁父','貫休','唐','御定全唐诗','yuding','','[]','一葉一竿竹，眉須雪欲零。陸應無祖業，香必是伊腥。',48,'御定全唐詩/json/829.json','["一葉一竿竹，眉須雪欲零。陸應無祖業，香必是伊腥。", "兒亦名魚鷓，歌稱我洞庭。回頭深自愧，舊業近滄溟。"]'),
('yuding-36','題友人山居','貫休','唐','御定全唐诗','yuding','','[]','卜居鄰塢寺，魂夢又相關。鶴本如雲白，君初似我閑。',48,'御定全唐詩/json/829.json','["卜居鄰塢寺，魂夢又相關。鶴本如雲白，君初似我閑。", "月明僧渡水，木落火連山。從此天臺約，來茲未得還。"]'),
('yuding-37','寄宋使君','貫休','唐','御定全唐诗','yuding','','[]','寺倚烏龍腹，窗中見碧棱。空廊人畫祖，古殿鶴窺燈。',48,'御定全唐詩/json/829.json','["寺倚烏龍腹，窗中見碧棱。空廊人畫祖，古殿鶴窺燈。", "風吼深松雪，爐寒一鼎冰。唯應謝內史，知此道心澄。"]'),
('yuding-38','懷武夷紅石子二首','貫休','唐','御定全唐诗','yuding','','[]','常思紅石子，獨自住山椒。窗外猩猩語，爐中姹姹嬌。',96,'御定全唐詩/json/829.json','["常思紅石子，獨自住山椒。窗外猩猩語，爐中姹姹嬌。", "乳香諸洞滴，地秀眾峰朝。曾見奇人說，煙霞恨太遙。", "弋者終何慕，高吟坐綠鼇。燒侵薑芋窖，僧與水雲袍。", "竹鞘畬刀缺，松枝獵箭牢。何時一相見，清話擘蟠桃。"]'),
('yuding-39','送人征蠻','貫休','唐','御定全唐诗','yuding','','[]','七縱七擒處，君行事可攀。亦知磨一劍，不獨定諸蠻。',48,'御定全唐詩/json/829.json','["七縱七擒處，君行事可攀。亦知磨一劍，不獨定諸蠻。", "樹盡低銅柱，潮常沸火山。名須麟閣上，好去及瓜還。"]'),
('yuding-40','懷周朴、張為','貫休','唐','御定全唐诗','yuding','','[]','二子無消息，多應各自耕。巴江思杜甫，漳水憶劉楨。',48,'御定全唐詩/json/829.json','["二子無消息，多應各自耕。巴江思杜甫，漳水憶劉楨。", "白髮應全白，生涯作麼生。寄書多不達，空念重行行。"]'),
('yuding-41','寄令狐郎中','貫休','唐','御定全唐诗','yuding','','[]','雨打繁暑盡，放懷步微涼。綠苔狂似人，入我白玉堂。',48,'御定全唐詩/json/829.json','["雨打繁暑盡，放懷步微涼。綠苔狂似人，入我白玉堂。", "塹鳥眠堪畫，庭檉夜益香。唯應蕊宮子，時到虎溪傍。"]'),
('yuding-42','鄱陽道中作','貫休','唐','御定全唐诗','yuding','','[]','鄱陽古岸邊，無一樹無蟬。路轉他山大，砧驅鄉思偏。',48,'御定全唐詩/json/829.json','["鄱陽古岸邊，無一樹無蟬。路轉他山大，砧驅鄉思偏。", "湖平帆盡落，天淡月初圓。何事堯雲下，干戈滿許田。"]'),
('yuding-43','歸故林別知己','貫休','唐','御定全唐诗','yuding','','[]','別離無古今，柳色向人深。萬里長江水，平生不印心。',48,'御定全唐詩/json/829.json','["別離無古今，柳色向人深。萬里長江水，平生不印心。", "遠書容北雁，贈別謝南金。愧勉青雲志，余懷非陸沈。"]'),
('yuding-44','送僧遊天臺','貫休','唐','御定全唐诗','yuding','','[]','囊空心亦空，城郭去騰騰。眼作麼是眼，僧誰識此僧。',48,'御定全唐詩/json/829.json','["囊空心亦空，城郭去騰騰。眼作麼是眼，僧誰識此僧。", "歇隈紅樹久，笑看白雲崩。已有天臺約，深秋必共登。"]'),
('yuding-45','詠竹根珓子','貫休','唐','御定全唐诗','yuding','','[]','出處慚林藪，才微幸一陽。不緣懷片善，豈得近馨香。',48,'御定全唐詩/json/829.json','["出處慚林藪，才微幸一陽。不緣懷片善，豈得近馨香。", "節亦因人淨，聲從擲地彰。但令筋力在，永願報時昌。"]'),
('yuding-46','硯瓦','貫休','唐','御定全唐诗','yuding','','[]','淺薄雖頑樸，其如近筆端。低心蒙潤久，入匣更身安。',48,'御定全唐詩/json/829.json','["淺薄雖頑樸，其如近筆端。低心蒙潤久，入匣更身安。", "應念研磨苦，無為瓦礫看。儻然仁不棄，還可比琅玕。"]'),
('yuding-47','水壺子','貫休','唐','御定全唐诗','yuding','','[]','良匠曾陶瑩，多居筆硯中。一從親幾案，常恐近兒童。',48,'御定全唐詩/json/829.json','["良匠曾陶瑩，多居筆硯中。一從親幾案，常恐近兒童。", "卓立澄心久，提攜注意通。不應嫌器小，還有濟人功。"]'),
('yuding-48','筆','貫休','唐','御定全唐诗','yuding','','[]','莫訝書紳苦，功成在一毫。自從蒙管錄，便覺用心勞。',48,'御定全唐詩/json/829.json','["莫訝書紳苦，功成在一毫。自從蒙管錄，便覺用心勞。", "手點時難棄，身閑架亦高。何妨成五色，永願助風騷。"]'),
('yuding-49','棋','貫休','唐','御定全唐诗','yuding','','[]','棋信無聲樂，偏宜境寂寥。著高圖暗合，勢王氣彌驕。',48,'御定全唐詩/json/829.json','["棋信無聲樂，偏宜境寂寥。著高圖暗合，勢王氣彌驕。", "人事掀天盡，光陰動地銷。因知韋氏論，不獨為吳朝。"]'),
('yuding-50','夜對雪作寄友生','貫休','唐','御定全唐诗','yuding','','[]','皓彩中宵合，開門失所蹤。何年今夜意，共子在孤峰。',48,'御定全唐詩/json/829.json','["皓彩中宵合，開門失所蹤。何年今夜意，共子在孤峰。", "氣射燈花落，光侵壁罅濃。唯君心似我，吟到五更鐘。"]'),
('yuding-51','題惠琮律師院','貫休','唐','御定全唐诗','yuding','','[]','苦節兼青目，公卿話有餘。唯傳黃葉喻，還似白泉居。',48,'御定全唐詩/json/829.json','["苦節兼青目，公卿話有餘。唯傳黃葉喻，還似白泉居。", "猿撥孤雲破，鐘撞眾木疏。社壇蹤跡在，重結複何如。"]'),
('yuding-52','寄清泠山道人','貫休','唐','御定全唐诗','yuding','','[]','常憶清泠子，深雲種早禾。萬緣雖不涉，一句子如何。',48,'御定全唐詩/json/829.json','["常憶清泠子，深雲種早禾。萬緣雖不涉，一句子如何。", "蹤跡諸峰匝，衣裳老虱多。江頭無事也，終必到煙蘿。"]'),
('yuding-53','秋盡途中作','貫休','唐','御定全唐诗','yuding','','[]','行行芳草歇，潭島葉紛紛。山色路無盡，砧聲客強聞。',48,'御定全唐詩/json/829.json','["行行芳草歇，潭島葉紛紛。山色路無盡，砧聲客強聞。", "殘陽曜極野，黑水浸空墳。那得無鄉思，前程入楚雲。"]'),
('yuding-54','秋居寄王相公三首','貫休','唐','御定全唐诗','yuding','','[]','禪林蟬□落，地燥可生苔。好句慵收拾，清風作麼來。',144,'御定全唐詩/json/829.json','["禪林蟬□落，地燥可生苔。好句慵收拾，清風作麼來。", "餅唯餐喜悅，社已得宗雷。還似山中日，柴門更不開。", "松聲高似瀑，藥熟色如花。誰道全無病，時猶不在家。", "山童舂菽粉，園叟送銀瓜。誰訪孫弘閣，談玄到日斜。", "氣與非常合，常人爭得知。直須窮到底，始是出家兒。", "閣雀銜紅粟，鄰僧背古碑。只應王與謝，時有沃州期。"]'),
('yuding-55','《讀玄宗幸蜀記》','貫休','唐','御定全唐诗','yuding','','[]','宋璟姚崇死，中庸遂變移。如何遊萬里，只為一胡兒。',144,'御定全唐詩/json/829.json','["宋璟姚崇死，中庸遂變移。如何遊萬里，只為一胡兒。", "泣溻乾坤色，飄零日月旗。火從龍闕起，淚向馬嵬垂。", "始憶張丞相，全師郭子儀。百官皆剽劫，九廟盡崩隳。", "塵撲銀輪暗，雷奔棧閣危。幸臣方賜死，野老不勝悲。", "及溜飄淪日，行宮寂寞時。人心雖未厭，天意亦難知。", "聖兩歸丹禁，承幹動四夷。因知納諫諍，始是太平基。"]'),
('yuding-0','聞征四處士','貫休','唐','御定全唐诗','yuding','','[]','一詔群公起，移山四海聞。因知丈夫事，須佐聖明君。',48,'御定全唐詩/json/830.json','["一詔群公起，移山四海聞。因知丈夫事，須佐聖明君。", "白酒全傾甕，蒲輪半載雲。從茲居諫署，筆硯幾人焚。"]'),
('yuding-1','送友人下第游邊','貫休','唐','御定全唐诗','yuding','','[]','失意窮邊去，孤城值晚春。黑山霞不赤，白日鬼隨人。',48,'御定全唐詩/json/830.json','["失意窮邊去，孤城值晚春。黑山霞不赤，白日鬼隨人。", "角咽胡風緊，沙昏磧月新。明時至公在，回首莫因循。"]'),
('yuding-2','寄匡山紀公','貫休','唐','御定全唐诗','yuding','','[]','錦繡谷中人，相思入夢頻。寄言無別事，琢句似終身。',48,'御定全唐詩/json/830.json','["錦繡谷中人，相思入夢頻。寄言無別事，琢句似終身。", "書捲鬚求旨，鬚根易得銀。斯言如不惑，千里亦相親。"]'),
('yuding-3','聞無相道人順世五首','貫休','唐','御定全唐诗','yuding','','[]','一事不經營，孤峰長老情。惟餐橡子餅，愛說道君兄。',240,'御定全唐詩/json/830.json','["一事不經營，孤峰長老情。惟餐橡子餅，愛說道君兄。", "池藕香狸掘，山神白日行。又聞行腳也，何處化群生。", "自昔尋師日，顛峰絕頂頭。雖聞不相似，特地使人愁。", "庭樹雪摧殘，上有白獮猴。大哉法中龍，去去不可留。", "常思將道者，高論地爐傍。迂談無世味，夜深山木僵。", "下山遭離亂，多病惟深藏。一別三十年，煙水空茫茫。", "石霜既順世，吾師亦不住。杉桂有猩猩，糠秕無句句。", "土肥多孟蕨，道老如嬰孺。莫比優曇花，斯人更難遇。", "百千萬億偈，共他勿交涉。所以那老人，密傳與迦葉。", "吾師得此法，不論劫不劫。去矣不可留，無蹤若為躡。"]'),
('yuding-4','苦熱','貫休','唐','御定全唐诗','yuding','','[]','松桂枝不動，陽烏飛半天。稻麻須結實，沙石欲生煙。',48,'御定全唐詩/json/830.json','["松桂枝不動，陽烏飛半天。稻麻須結實，沙石欲生煙。", "毒氣仍幹扇，高枝不立蟬。舊山多積雪，歸去是何年。"]'),
('yuding-5','鄂渚贈祥公','貫休','唐','御定全唐诗','yuding','','[]','寂寥堆積者，自為是高僧。客遠何人識，吟多冷病增。',48,'御定全唐詩/json/830.json','["寂寥堆積者，自為是高僧。客遠何人識，吟多冷病增。", "松煙青透壁，雪氣細吹燈。猶賴師于我，依依非面朋。"]'),
('yuding-6','懷武昌棲一二首','貫休','唐','御定全唐诗','yuding','','[]','常憶能吟一，房連古帝墟。無端多忤物，唯我獨知渠。',96,'御定全唐詩/json/830.json','["常憶能吟一，房連古帝墟。無端多忤物，唯我獨知渠。", "病癒囊空後，神清木落初。只因烽火起，書劄自茲疏。", "清風江上月，霜灑月中砧。得句先呈佛，無人知此心。", "寂寥從鬼出，蒼翠到門深。惟有雙峰寺，時時獨去尋。"]'),
('yuding-7','寒食郊外','貫休','唐','御定全唐诗','yuding','','[]','寒食將吾族，相隨過石溪。塚花沾酒落，林鳥學人啼。',48,'御定全唐詩/json/830.json','["寒食將吾族，相隨過石溪。塚花沾酒落，林鳥學人啼。", "白水穿蕪疾，新霞出霧低。不堪回首望，家在赤松西。"]'),
('yuding-8','送道士歸天臺','貫休','唐','御定全唐诗','yuding','','[]','道高留不住，道去更何雲。舉世皆趨世，如君始愛君。',48,'御定全唐詩/json/830.json','["道高留不住，道去更何雲。舉世皆趨世，如君始愛君。", "徑侵銀地滑，瀑到石城聞。它日如相憶，金桃一為分。"]'),
('yuding-9','經孟浩然鹿門舊居二首','貫休','唐','御定全唐诗','yuding','','[]','孟子終焉處，遊人得得過。dz深黃狖小，地暖白雲多。',97,'御定全唐詩/json/830.json','["孟子終焉處，遊人得得過。dz深黃狖小，地暖白雲多。", "孔聖嗟大謬，玄宗爭奈何。空餘峴山色，千古共嵯峨。", "花落穀鶯啼，精靈安在哉。青山不可問，永日獨裴回。", "塚穴應藏虎，荒碑只見苔。伊餘亦惆悵，昨日郢城回。"]'),
('yuding-10','春送禪師歸閩中','貫休','唐','御定全唐诗','yuding','','[]','春色滿三湘，送師還故鄉。穿霞逢黑yU，乞食得紅薑。',49,'御定全唐詩/json/830.json','["春色滿三湘，送師還故鄉。穿霞逢黑yU，乞食得紅薑。", "大化宗門辟，孤禪海樹涼。儻為新句偈，寄我亦何妨。"]'),
('yuding-11','途中逢周樸','貫休','唐','御定全唐诗','yuding','','[]','東西南北路，相遇共興哀。世濁無知己，子從何處來。',48,'御定全唐詩/json/830.json','["東西南北路，相遇共興哀。世濁無知己，子從何處來。", "菊衰芳草在，程遠宿煙開。儻遇中興主，還應不用媒。"]'),
('yuding-12','避寇山中作','貫休','唐','御定全唐诗','yuding','','[]','山翠碧嵯峨，攀牽去者多。淺深俱得地，好惡未知他。',48,'御定全唐詩/json/830.json','["山翠碧嵯峨，攀牽去者多。淺深俱得地，好惡未知他。", "有草皆為戶，無人不荷戈。相逢空悵望，更有好時麼。"]'),
('yuding-13','避寇上唐臺山','貫休','唐','御定全唐诗','yuding','','[]','蒼黃緣鳥道，峰脅見樓臺。檉桂香皆滴，煙霞濕不開。',48,'御定全唐詩/json/830.json','["蒼黃緣鳥道，峰脅見樓臺。檉桂香皆滴，煙霞濕不開。", "僧高眉半白，山老石多摧。莫問塵中事，如今正可哀。"]'),
('yuding-14','題嶧桐律師院','貫休','唐','御定全唐诗','yuding','','[]','律中麟角者，高淡出塵埃。芳草不曾觸，幾生如此來。',48,'御定全唐詩/json/830.json','["律中麟角者，高淡出塵埃。芳草不曾觸，幾生如此來。", "壑風吹磬斷，杉露滴花開。如結林中社，伊餘亦願陪。"]'),
('yuding-15','上馮使君渡水僧障子','貫休','唐','御定全唐诗','yuding','','[]','跣足拄巴藤，潺湲渡幾曾。盡權無著印，不是等閒僧。',48,'御定全唐詩/json/830.json','["跣足拄巴藤，潺湲渡幾曾。盡權無著印，不是等閒僧。", "熊耳應初到，牛頭始去登。畫來偏覺好，將寄柳吳興。"]'),
('yuding-16','秋夜玩月懷玉霄道士','貫休','唐','御定全唐诗','yuding','','[]','光異磨礱出，輪非雕斫成。今宵剛道別，舉世勿人爭。',48,'御定全唐詩/json/830.json','["光異磨礱出，輪非雕斫成。今宵剛道別，舉世勿人爭。", "征婦砧添怨，詩人哭到明。惟宜華頂叟，笙磬有餘聲。"]'),
('yuding-17','上杭州令狐使君','貫休','唐','御定全唐诗','yuding','','[]','顏冉德無鄰，分憂浙水濱。愛山成大癖，求瘼似諸身。',48,'御定全唐詩/json/830.json','["顏冉德無鄰，分憂浙水濱。愛山成大癖，求瘼似諸身。", "視事奸回盡，登樓海嶽春。野人如有幸，應得見陶鈞。"]'),
('yuding-18','懷諸葛玨二首','貫休','唐','御定全唐诗','yuding','','[]','諸葛子作者，詩曾我細看。出山因覓孟，踏雪去尋韓。',96,'御定全唐詩/json/830.json','["諸葛子作者，詩曾我細看。出山因覓孟，踏雪去尋韓。", "謬獨哭不錯，常流飲實難。知音知便了，歸去舊江幹。", "羸馬與羸童，微吟冒北風。店孤僧共歇，日落思無窮。", "囊草無非刺，魏人那識公。鶯花五陵道，去去與誰同。"]'),
('yuding-19','懷錢唐羅隱、章魯封','貫休','唐','御定全唐诗','yuding','','[]','二子依公子，雞鳴狗盜徒。青雲十上苦，白髮一莖無。',48,'御定全唐詩/json/830.json','["二子依公子，雞鳴狗盜徒。青雲十上苦，白髮一莖無。", "風澀潮聲惡，天寒角韻孤。別離千萬里，何以慰榮枯。"]'),
('yuding-20','送沈侍郎','貫休','唐','御定全唐诗','yuding','','[]','從知無遠近，木落去閩城。地入無諸俗，冠峨甲乙精。',48,'御定全唐詩/json/830.json','["從知無遠近，木落去閩城。地入無諸俗，冠峨甲乙精。", "山多高興亂，江直好風生。儉府清無事，唯應薦禰衡。"]'),
('yuding-21','題宿禪師院','貫休','唐','御定全唐诗','yuding','','[]','身閒心亦然，如此已多年。語淡不著物，茶香別有泉。',48,'御定全唐詩/json/830.json','["身閒心亦然，如此已多年。語淡不著物，茶香別有泉。", "古衣和蘚衲，新偈幾人傳。時說秋歸夢，孤峰在海邊。"]'),
('yuding-22','秋晚泊石頭驛有寄','貫休','唐','御定全唐诗','yuding','','[]','蕭索漳江北，何人慰寂寥。北風人獨立，南國信空遙。',48,'御定全唐詩/json/830.json','["蕭索漳江北，何人慰寂寥。北風人獨立，南國信空遙。", "燒塢新雲白，漁家眾木凋。所思不可見，行雁在青霄。"]'),
('yuding-23','別盧使君','貫休','唐','御定全唐诗','yuding','','[]','杜宇聲聲急，行行楚水濆。道無裨政化，行處傲孤雲。',96,'御定全唐詩/json/830.json','["杜宇聲聲急，行行楚水濆。道無裨政化，行處傲孤雲。", "幸到膺門下，頻蒙俸粟分。詩雖曾引玉，棋數中埋軍。", "山好還尋去，恩深豈易雲。扇風千里泰，車雨九重聞。", "晴霧和花氣，危檣鼓浪文。終期陶鑄日，再見信陵君。"]'),
('yuding-24','秋夜吟','貫休','唐','御定全唐诗','yuding','','[]','如愚複愛詩，木落即眠遲。思苦香消盡，更深筆尚隨。',48,'御定全唐詩/json/830.json','["如愚複愛詩，木落即眠遲。思苦香消盡，更深筆尚隨。", "饑童舂赤黍，繁露灑烏椑。看卻龍鍾也，歸山是底時。"]'),
('yuding-25','桐江閒居作十二首','貫休','唐','御定全唐诗','yuding','','[]','木落雨翛翛，桐江古岸頭。擬歸仙掌去，剛被謝公留。',576,'御定全唐詩/json/830.json','["木落雨翛翛，桐江古岸頭。擬歸仙掌去，剛被謝公留。", "猛燒侵茶塢，殘霞照角樓。坐來還有意，流水面前流。", "香刹通真觀，樓臺倚郡城。陰森古樹氣，粗淡老僧情。", "壁畫連山潤，仙鐘扣月清。何須結西社，大道本無生。", "靜室焚檀印，深爐燒鐵瓶。茶和阿魏暖，火種柏根馨。", "數隻飛來鶴，成堆讀了經。何妨似支遁，騎馬入青冥。", "不問賡桑子，唯師妙吉祥。等閒眠片石，不覺到斜陽。", "獨自收櫧葉，教童探柏瓤。王孫莫指笑，淡泊味還長。", "詩琢冰成句，多將大道論。人誰知此意，日日只關門。", "乳鼠穿荒壁，溪龜上淨盆。因知無事貴，言外更無言。", "紅黍飯溪苔，清吟茗數杯。只應唯道在，無意俟時來。", "樹疊藏仙洞，山蒸足爆雷。從他嫌複笑，門更不曾開。", "蟬急野蕭蕭，山中信屢招。樹香烹菌術，詩□□瓊瑤。", "諸境教人認，荒榛引燒燒。吾皇禮金骨，誰□美南朝。", "露滴滴蘅茅，秋成爽氣交。霜椑如蜜裹，□□似鹽苞。", "浮蘚侵蛩穴，微陽落鶴巢。還如山裏日，門更絕人敲。", "塹鳥毛衣別，頻來似愛吟。蕭條秋病後，斑駁綠苔深。", "珠翠籠金像，風泉灑玉琴。孰知吾所適，終不是心心。", "芙蓉峰裏居，關閉複何如。白玃兼花鹿，多年不見渠。", "紅泉香滴瀝，丹桂冷扶疏。唯有西溪叟，時時到弊廬。", "憶在山中日，為僧鬢欲衰。一燈常到曉，十載不離師。", "水汲冰溪滑，鐘撞雪閣危。從來多自省，不學擬何為。", "囊非撲滿器，門更絕人過。土井連岡冷，風簾迸葉多。", "村童頑似鐵，山菜硬如莎。唯有前山色，窗中無奈何。"]'),
('yuding-26','寄馮使君','貫休','唐','御定全唐诗','yuding','','[]','山風與霜氣，浩浩滿松枝。永日燒杉子，無人共此時。',48,'御定全唐詩/json/830.json','["山風與霜氣，浩浩滿松枝。永日燒杉子，無人共此時。", "為文攀諷諫，得道在毫釐。唯有桐江守，常憐志不卑。"]'),
('yuding-27','經棲白舊院二首','貫休','唐','御定全唐诗','yuding','','[]','竺卿何處去，觸目盡淒涼。不見中秋月，空餘一炷香。',96,'御定全唐詩/json/830.json','["竺卿何處去，觸目盡淒涼。不見中秋月，空餘一炷香。", "殘花飄暮雨，枯葉蓋啼螿。誰禮新墳塔，蕭條渭水傍。", "國寶還亡一，時多李德林。故人卿相泣，承制渥恩深。", "舊槁誰收得，空堂影似吟。裴回不能去，寒日下西岑。"]'),
('yuding-28','贈李佑道人','貫休','唐','御定全唐诗','yuding','','[]','闒茸複埃塵，難親複易親。皆疑有仙術，問著卻愁人。',48,'御定全唐詩/json/830.json','["闒茸複埃塵，難親複易親。皆疑有仙術，問著卻愁人。", "只是耽浮蟻，曾雲見泣麟。相逢先合手，渾似有前因。"]'),
('yuding-29','贈景和尚院','貫休','唐','御定全唐诗','yuding','','[]','藏經看幾遍，眉有數條霜。萬境心都泯，深冬日亦長。',48,'御定全唐詩/json/830.json','["藏經看幾遍，眉有數條霜。萬境心都泯，深冬日亦長。", "窗虛花木氣，衲掛水雲鄉。時說秋歸夢，峰頭雪滿床。"]'),
('yuding-30','上宋使君','貫休','唐','御定全唐诗','yuding','','[]','折桂文如錦，分憂力若春。位高空倚命，詩妙古無人。',48,'御定全唐詩/json/830.json','["折桂文如錦，分憂力若春。位高空倚命，詩妙古無人。", "有感禾爭熟，無私吏盡貧。野人如有幸，應得見陶鈞。"]'),
('yuding-31','離亂後寄九峰和尚二首','貫休','唐','御定全唐诗','yuding','','[]','亂後知深隱，庵應近石樓。異香因雪歇，仙果落池浮。',97,'御定全唐詩/json/830.json','["亂後知深隱，庵應近石樓。異香因雪歇，仙果落池浮。", "詩老全拋格，心空未到頭。還應嫌笑我，世路獨悠悠。", "蕭灑複蕭灑，松根獨據梧。瀑冰吟次折，遠燒坐來無。", "老ch寒披衲，孤雲靜入廚。不知知我否，已到不區區。"]'),
('yuding-32','送黃賓於赴舉','貫休','唐','御定全唐诗','yuding','','[]','冬暮雨霏霏，行人喜可稀。二階□夜雪，亞聖在春闈。',48,'御定全唐詩/json/830.json','["冬暮雨霏霏，行人喜可稀。二階□夜雪，亞聖在春闈。", "馬疾頑童遠，山荒凍葉飛。□師無一事，應見麗龜歸。"]'),
('yuding-33','題靈溪暢公墅','貫休','唐','御定全唐诗','yuding','','[]','境清僧格冷，新斬古林開。舊隱還如此，令人來又來。',48,'御定全唐詩/json/830.json','["境清僧格冷，新斬古林開。舊隱還如此，令人來又來。", "嵐飛黏似霧，茶好碧於苔。但使心清淨，從渠歲月催。"]'),
('yuding-34','送高九經赴舉','貫休','唐','御定全唐诗','yuding','','[]','回也曾言志，明君則事之。中興今若此，須去更何疑。',72,'御定全唐詩/json/830.json','["回也曾言志，明君則事之。中興今若此，須去更何疑。", "志列秋霜好，忠言劇諫奇。陸機游洛日，文舉薦衡時。", "虎跡商山雪，雲痕嶽廟碑。夫君將潦倒，一說向深知。"]'),
('yuding-35','東西二林寺流水','貫休','唐','御定全唐诗','yuding','','[]','水爾何如此，區區矻矻流。牆牆邊瀝瀝，砌砌下啾啾。',120,'御定全唐詩/json/830.json','["水爾何如此，區區矻矻流。牆牆邊瀝瀝，砌砌下啾啾。", "味不卑於乳，聲常占得秋。崩騰成大瀑，落托出深溝。", "遠曆神仙窟，高淋竹樹頭。數家舂碓磑，幾處浴猿猴。", "共月穿峰罅，喧僧睡石樓。派通天宇闊，溜入楚江浮。", "為潤知何極，無邊始自由。好歸江海裏，長負濟川舟。"]'),
('yuding-36','送王貞白重試東歸','貫休','唐','御定全唐诗','yuding','','[]','心苦酬心了，東歸謝所知。可憐重試者，如折兩三枝。',48,'御定全唐詩/json/830.json','["心苦酬心了，東歸謝所知。可憐重試者，如折兩三枝。", "雨毒逢花少，山多愛馬遲。此行三可羨，正值倒戈時。"]'),
('yuding-37','早秋即事寄馮使君','貫休','唐','御定全唐诗','yuding','','[]','金脈火初微，開門竹杖隨。此身全是病，今日更嗔誰。',48,'御定全唐詩/json/830.json','["金脈火初微，開門竹杖隨。此身全是病，今日更嗔誰。", "落葉崢嶸處，諸峰爽拔時。唯思棠樹下，高論入圓伊。"]'),
('yuding-38','贈景和尚院','貫休','唐','御定全唐诗','yuding','','[]','貌古眉如雪，看經二十霜。尋常對詩客，只勸療心瘡。',48,'御定全唐詩/json/830.json','["貌古眉如雪，看經二十霜。尋常對詩客，只勸療心瘡。", "炭火邕湖瀅，山晴紫竹涼。怡然無一事，流水自湯湯。"]'),
('yuding-39','寄西山胡汾','貫休','唐','御定全唐诗','yuding','','[]','待價欲要君，山前獨灌園。雖然不識面，要且已消魂。',48,'御定全唐詩/json/830.json','["待價欲要君，山前獨灌園。雖然不識面，要且已消魂。", "鹿睡紅霞影，泉淋白石門。伊余心更苦，何日共深論。"]'),
('yuding-40','題師穎和尚院','貫休','唐','御定全唐诗','yuding','','[]','師院清無敵，師心智不知。臘高清眼細，閑甚白雲卑。',48,'御定全唐詩/json/830.json','["師院清無敵，師心智不知。臘高清眼細，閑甚白雲卑。", "煮茗然楓枿，泥牆劄祖碑。愛師終不及，謾住許多時。"]'),
('yuding-41','遊雲頂山晚望','貫休','唐','御定全唐诗','yuding','','[]','雲頂聊一望，山靈草木奇。黔南在何處，堪笑複堪悲。',48,'御定全唐詩/json/830.json','["雲頂聊一望，山靈草木奇。黔南在何處，堪笑複堪悲。", "菊歇香未歇，露繁蟬不饑。明朝又西去，錦水與峨眉。"]'),
('yuding-42','劉相公見訪','貫休','唐','御定全唐诗','yuding','','[]','千騎擁朱輪，香塵豈是塵。如何補袞服，來看衲衣人。',96,'御定全唐詩/json/830.json','["千騎擁朱輪，香塵豈是塵。如何補袞服，來看衲衣人。", "莊叟因先覺，空王有宿因。對花無俗態，愛竹見天真。", "欹枕松窗迥，題牆道意新。戒師慚匪什，都講更勝詢。", "桃熟多紅璺，茶香有碧筋。高宗多不寐，終是夢中人。"]'),
('yuding-43','寄赤松舒道士二首','貫休','唐','御定全唐诗','yuding','','[]','不見高人久，空令鄙吝多。遙思青嶂下，無那白雲何。',96,'御定全唐詩/json/830.json','["不見高人久，空令鄙吝多。遙思青嶂下，無那白雲何。", "子愛寒山子，歌惟樂道歌。會應陪太守，一日到煙蘿。", "餘亦如君也，詩魔不敢魔。一餐兼午睡，萬事不如他。", "雨陣沖溪月，蛛絲罥砌莎。近知山果熟，還擬寄來麼。"]'),
('yuding-44','鄂渚逢楊贊禹','貫休','唐','御定全唐诗','yuding','','[]','流浪兵荒苦，相思歲月闌。理惟通至道，人或謂無端。',48,'御定全唐詩/json/830.json','["流浪兵荒苦，相思歲月闌。理惟通至道，人或謂無端。", "燒猛湖煙赤，窗空雪月寒。知音不可見，始為一吟看。"]'),
('yuding-45','別性空禪師','貫休','唐','御定全唐诗','yuding','','[]','積翠迸一瀑，紅霞碧霧開。方尋此境去，莫問幾時回。',48,'御定全唐詩/json/830.json','["積翠迸一瀑，紅霞碧霧開。方尋此境去，莫問幾時回。", "蕩槳入簷石，思詩聞早雷。唯師心似我，欲近不然灰。"]'),
('yuding-46','送胡處士','貫休','唐','御定全唐诗','yuding','','[]','不名兼不利，相遇海西濆。白字未幹發，清時錯愛雲。',48,'御定全唐詩/json/830.json','["不名兼不利，相遇海西濆。白字未幹發，清時錯愛雲。", "頭巾多酒氣，竹杖有苔文。久積希顏意，林中又送君。"]'),
('yuding-47','寄瀾公二首','貫休','唐','御定全唐诗','yuding','','[]','小一頭應白，孤高住歙城。不知安樂否，何以近無生。',96,'御定全唐詩/json/830.json','["小一頭應白，孤高住歙城。不知安樂否，何以近無生。", "燒逼鴻行側，風乾雪朕清。途中逢此信，珍重未精誠。", "荒亂拋深隱，飄零遠寓居。片雲無定所，得力是逢渠。", "瀑灂群公社，江崩古帝墟。終期再相見，招手複何如。"]'),
('yuding-48','寄棲一上人','貫休','唐','御定全唐诗','yuding','','[]','花塹接滄洲，陰雲閑楚丘。雨聲雖到夜，吟味不如秋。',48,'御定全唐詩/json/830.json','["花塹接滄洲，陰雲閑楚丘。雨聲雖到夜，吟味不如秋。", "古屋藏花鴿，荒園聚亂流。無機心便是，何用話歸休。"]'),
('yuding-49','送僧之湖南','貫休','唐','御定全唐诗','yuding','','[]','湘水萬餘裏，師遊芳草生。登山乞食後，無伴入雲行。',48,'御定全唐詩/json/830.json','["湘水萬餘裏，師遊芳草生。登山乞食後，無伴入雲行。", "宿雨和花落，春牛擁霧耕。不知今夜月，何處聽猿聲。"]'),
('yuding-50','秋末寄張侍郎','貫休','唐','御定全唐诗','yuding','','[]','靜坐黔城北，離仁半歲強。霧中紅黍熟，燒後白雲香。',48,'御定全唐詩/json/830.json','["靜坐黔城北，離仁半歲強。霧中紅黍熟，燒後白雲香。", "多病如何好，無心去始長。寂寥還得句，溪上寄三張。"]'),
('yuding-51','古塞曲三首','貫休','唐','御定全唐诗','yuding','','[]','單于烽火動，都護去天涯。別賜黃金甲，親臨白玉除。',144,'御定全唐詩/json/830.json','["單于烽火動，都護去天涯。別賜黃金甲，親臨白玉除。", "塞垣須靜謐，師旅審安危。定遠條支寵，如今勝古時。", "方見將軍貴，分明對冕旒。聖恩如遠被，狂虜不難收。", "臣節唯期死，功勳敢望侯。終辭修裏第，從此出皇州。", "百萬精兵動，參差便渡遼。如何好白日，亦照此天驕。", "遠樹深疑賊，驚蓬迥似雕。凱歌何日唱，磧路共天遙。"]'),
('yuding-52','古塞下曲七首','貫休','唐','御定全唐诗','yuding','','[]','下營依遁甲，分帥把河隍。地使人心惡，風吹旗焰荒。',336,'御定全唐詩/json/830.json','["下營依遁甲，分帥把河隍。地使人心惡，風吹旗焰荒。", "搜山得探卒，放火獵黃羊。唯有南飛雁，聲聲斷客腸。", "歸去是何年，山連邏逤川。蒼黃曾戰地，空闊養雕天。", "旗插蒸沙堡，槍擔卓槊泉。蕭條寒日落，號令徹窮邊。", "虜寇日相持，如龍馬不肥。突圍金甲破，趁賊鐵槍飛。", "漢月堂堂上，胡雲慘慘微。黃河冰已合，猶未送征衣。", "南北惟堪恨，東西實可嗟。常飛侵夏雪，何處有人家。", "風刮陰山薄，河推大岸斜。只應寒夜夢，時見故園花。", "不是將軍勇，胡兵豈易當。雨曾淋火陣，箭又中金瘡。", "鐵嶺全無土，豺群亦有狼。因思無戰日，天子是陶唐。", "榆葉飄蕭盡，關防烽寨重。寒來知馬疾，戰後覺人凶。", "燒逐飛蓬死，沙生毒霧濃。誰能奏明主，功業已堪封。", "萬戰千征地，蒼茫古塞門。陰兵為客祟，惡酒發刀痕。", "風落昆侖石，河崩苜蓿根。將軍更移帳，日日近西蕃。"]'),
('yuding-53','古塞上曲七首','貫休','唐','御定全唐诗','yuding','','[]','幽並兒百萬，百戰未曾輸。蕃界已深入，將軍仍遠圖。',336,'御定全唐詩/json/830.json','["幽並兒百萬，百戰未曾輸。蕃界已深入，將軍仍遠圖。", "月明風拔帳，磧暗鬼騎狐。但有東歸日，甘從筋力枯。", "中軍殺白馬，白日祭蒼蒼。號變旗幡亂，鼙幹草木黃。", "朔雲含凍雨，枯骨放妖光。故國今何處，參差近鬼方。", "白雁兼羌笛，幾年垂淚聽。陰風吹殺氣，永日在青冥。", "遠戍秋添將，邊烽夜雜星。嫖姚頭半白，猶自看兵經。", "久雨始無塵，邊聲四散聞。浸河荒寨柱，吹角白頭軍。", "戰馬齕腥草，烏鳶識陣雲。征人心力盡，枯骨更遭焚。", "帳幕侵奚界，憑陵未可涯。擒生行別路，尋箭向平沙。", "赤落蒲桃葉，香微甘草花。不堪登隴望，白日又西斜。", "地角天涯外，人號鬼哭邊。大河流敗卒，寒日下蒼煙。", "殺氣諸蕃動，軍書一箭傳。將軍莫惆悵，高處是燕然。", "山接胡奴水，河連勃勃城。數州今已伏，此命豈堪輕。", "磧吼旄頭落，風乾刁鬥清。因嗟李陵苦，只得沒蕃名。"]'),
('yuding-54','古出塞曲三首','貫休','唐','御定全唐诗','yuding','','[]','掃盡狂胡跡，回頭望故關。相逢惟死鬥，豈易得生還。',144,'御定全唐詩/json/830.json','["掃盡狂胡跡，回頭望故關。相逢惟死鬥，豈易得生還。", "縱宴參胡樂，收兵過雪山。不封十萬戶，此事亦應閑。", "玉帳將軍意，殷勤把酒論。功高寧在我，陣沒與招魂。", "塞色干戈束，軍容喜氣屯。男兒今始是，譀出玉關門。", "回首隴山頭，連天草木秋。聖君應入夢，半路遣封侯。", "水不擔陰雪，柴令倒戍樓。歸來麟閣上，春色滿皇州。"]'),
('yuding-55','聞赤松舒道士下世','貫休','唐','御定全唐诗','yuding','','[]','地變賢人喪，瘡痍不可觀。一聞消息苦，千種破除難。',240,'御定全唐詩/json/830.json','["地變賢人喪，瘡痍不可觀。一聞消息苦，千種破除難。", "陰騭那虛擲，深山近始安。玄關評兔角，玉器琢雞冠。", "傲野高難狎，融怡美不殫。冀迎新渥澤，遽逐逝波瀾。", "蛻殼埋金隧，飛精駕錦鸞。傾摧千仞壁，枯歇一株蘭。", "仙廟詩雖繼，苔牆篆必鞔。煙霞成片黯，松桂著行幹。", "影拄溪流咽，堂扃隙月寒。寂寥遺藥犬，縹緲想瓊竿。", "伊昔相尋遠，留連幾盡歡。論詩花作席，炙菌葉為盤。", "彭伉心相似，承禎趣一般。琴彈溪月側，棋次砌雲殘。", "倏忽成千古，飄零見百端。荊襄春浩浩，吳越浪漫漫。", "已矣紅霞子，空留白石壇。無弦亦須絕，回首一長歎。"]'),
('yuding-56','贈抱麻劉舍人','貫休','唐','御定全唐诗','yuding','','[]','郡政今良吏，門風古縉紳。萬年唐社稷，一個哭麻人。',217,'御定全唐詩/json/830.json','["郡政今良吏，門風古縉紳。萬年唐社稷，一個哭麻人。", "憤烈身先死，敷揚氣益貞。天乎資大寶，泰矣見忠臣。", "得罪鐘多故，投荒豈是迍。玉寒方重澀，松古更青皴。", "鵬cR甯唯白，龍多豈止荀。道孤梳有雪，恩重淚盈巾。", "喻蜀須憑草，成周必仗仁。三峰宵旰切，萬里渥恩新。", "賦鵩言無累，依劉德有鄰。風期仁祖帽，鼠訝史雲塵。", "禪叟知何幸，玄談有宿因。雙溪逢陸海，荊渚遇平津。", "落日愁聞笛，何人為吐茵。生徒希匠化，寰海仰經綸。", "疾愈蟬聲老，年豐雨滴頻。劉虯師弟子，時喜一相親。"]'),
('yuding-0','夜寒寄盧給事二首','貫休','唐','御定全唐诗','yuding','','[]','刻羽流商否，霜風動地吹。邇來唯自惜，知合是誰知。',96,'御定全唐詩/json/831.json','["刻羽流商否，霜風動地吹。邇來唯自惜，知合是誰知。", "塹雪消難盡，鄰僧睡太奇。知音不可得，始為一吟之。", "心苦味不苦，世衰吾道微。清如吞雪雹，誰把比珠璣。", "作者相收拾，常人任是非。舊居滄海上，歸去即應歸。"]'),
('yuding-1','送葉蒙赴舉','貫休','唐','御定全唐诗','yuding','','[]','年年屈複屈，惆悵曲江湄。自古身榮者，多非年少時。',48,'御定全唐詩/json/831.json','["年年屈複屈，惆悵曲江湄。自古身榮者，多非年少時。", "空囊投刺遠，大雪入關遲。來歲還公道，平人不用疑。"]'),
('yuding-2','聞王慥常侍卒三首','貫休','唐','御定全唐诗','yuding','','[]','世亂君巡狩，清賢又告亡。星辰皆有角，日月略無光。',144,'御定全唐詩/json/831.json','["世亂君巡狩，清賢又告亡。星辰皆有角，日月略無光。", "金柱連天折，瑤階被賊荒。令人轉惆悵，無路問蒼蒼。", "宗社運微衰，山摧甘井枯。不知千載後，更有此人無。", "政入龔黃甲，詩輕沈宋徒。受恩酬未得，不覺只長籲。", "儻在扶天步，重興古國風。還如齊晏子，再見狄梁公。", "棠樹梅溪北，佳城舜廟東。誰修循吏傳，對此莫匆匆。"]'),
('yuding-3','秋晚野步','貫休','唐','御定全唐诗','yuding','','[]','藤屨兼閩竹，吟行一水傍。樹涼蟬不少，溪斷路多荒。',48,'御定全唐詩/json/831.json','["藤屨兼閩竹，吟行一水傍。樹涼蟬不少，溪斷路多荒。", "燒岳陰風起，田家濁酒香。登高吟更苦，微月出蒼茫。"]'),
('yuding-4','聞大願和尚順世三首','貫休','唐','御定全唐诗','yuding','','[]','王室今如毀，仍聞喪我師。古容圖得否，內院去無疑。',144,'御定全唐詩/json/831.json','["王室今如毀，仍聞喪我師。古容圖得否，內院去無疑。", "嶽鬼月中哭，松龕雪次隳。直須文五色，始可立高碑。", "鄴衛松杉外，芝蘭季孟間。盡希重詔出，只待六龍還。", "不疾成千古，令焚動四山。感恩終有淚，遙寄水潺潺。", "師稟盡名卿，孤峰老稱情。若遊三點外，爭把七賢平。", "苦霧埋空室，啼猿有咽聲。今朝益惆悵，曾沐下床迎。"]'),
('yuding-5','聞葉蒙及第','貫休','唐','御定全唐诗','yuding','','[]','憶昨送君詩，平人不用疑。吾徒若不得，天道即應私。',48,'御定全唐詩/json/831.json','["憶昨送君詩，平人不用疑。吾徒若不得，天道即應私。", "塵土茫茫曉，麟龍草草騎。相思不可見，又是落花時。"]'),
('yuding-6','送僧之靈夏','貫休','唐','御定全唐诗','yuding','','[]','舊識為邊帥，師遊勝事兼。連天唯白草，野餅有紅鹽。',48,'御定全唐詩/json/831.json','["舊識為邊帥，師遊勝事兼。連天唯白草，野餅有紅鹽。", "蕃近風多勃，河渾磧半淹。因知心似月，處處有人瞻。"]'),
('yuding-7','書無相道人庵','貫休','唐','御定全唐诗','yuding','','[]','造化太茫茫，端居紫石房。心遺無句句，頂處有霜霜。',48,'御定全唐詩/json/831.json','["造化太茫茫，端居紫石房。心遺無句句，頂處有霜霜。", "白鹿眠枯葉，清泉灑毳囊。寄言疑未決，須道雪溪旁。"]'),
('yuding-8','明進士北齋避暑','貫休','唐','御定全唐诗','yuding','','[]','相訪多沖雨，由來德有鄰。捲簾繁暑退，濕樹一蟬新。',48,'御定全唐詩/json/831.json','["相訪多沖雨，由來德有鄰。捲簾繁暑退，濕樹一蟬新。", "道在誰為主，吾衰自有因。只應江海上，還作狎鷗人。"]'),
('yuding-9','晚春寄吳融、于競二侍郎','貫休','唐','御定全唐诗','yuding','','[]','白頭為遠客，常憶白雲間。只覺老轉老，不知閑是閑。',48,'御定全唐詩/json/831.json','["白頭為遠客，常憶白雲間。只覺老轉老，不知閑是閑。", "花含宜細雨，室冷是深山。唯有霜台客，依依是往還。"]'),
('yuding-10','喜不思上人來','貫休','唐','御定全唐诗','yuding','','[]','沃州那不住，一別許多時。幾度懷君夜，相逢出夢遲。',48,'御定全唐詩/json/831.json','["沃州那不住，一別許多時。幾度懷君夜，相逢出夢遲。", "瓶擔千丈瀑，偈是七言詩。若向羅浮去，伊餘亦願隨。"]'),
('yuding-11','秋懷赤松道士','貫休','唐','御定全唐诗','yuding','','[]','仙觀在雲端，相思星斗寒。常憐呼鶴易，卻恨見君難。',48,'御定全唐詩/json/831.json','["仙觀在雲端，相思星斗寒。常憐呼鶴易，卻恨見君難。", "石罅青蛇濕，風榸白菌幹。終期花月下，壇上聽君彈。"]'),
('yuding-12','送劉逖赴閩辟','貫休','唐','御定全唐诗','yuding','','[]','離亂生涯盡，依劉是見機。從來吟太苦，不得力還稀。',48,'御定全唐詩/json/831.json','["離亂生涯盡，依劉是見機。從來吟太苦，不得力還稀。", "路入閩山熟，江浮瘴雨肥。何須折楊柳，相送已依依。"]'),
('yuding-13','苦雨中作','貫休','唐','御定全唐诗','yuding','','[]','通宵複連夕，其狀只如傾。卻遣思山者，忽然嫌水聲。',48,'御定全唐詩/json/831.json','["通宵複連夕，其狀只如傾。卻遣思山者，忽然嫌水聲。", "好花飄草盡，古壁欲雲生。不奈天難問，迢迢遠客情。"]'),
('yuding-14','送僧歸日本','貫休','唐','御定全唐诗','yuding','','[]','焚香祝海靈，開眼夢中行。得達即便是，無生可作輕。',48,'御定全唐詩/json/831.json','["焚香祝海靈，開眼夢中行。得達即便是，無生可作輕。", "流黃山火著，碇石索雷鳴。想到夷王禮，還為上寺迎。"]'),
('yuding-15','贈信安鄭道人','貫休','唐','御定全唐诗','yuding','','[]','貌古似蒼鶴，心清如鼎湖。仍聞得新義，便欲注陰符。',48,'御定全唐詩/json/831.json','["貌古似蒼鶴，心清如鼎湖。仍聞得新義，便欲注陰符。", "點化金常有，閑行影漸無。杳兮中便是，應不食菖蒲。"]'),
('yuding-16','送吏部劉相公除東川','貫休','唐','御定全唐诗','yuding','','[]','帝念梓州民，年年戰伐頻。山川無草木，烽火沒煙塵。',144,'御定全唐詩/json/831.json','["帝念梓州民，年年戰伐頻。山川無草木，烽火沒煙塵。", "政亂皆因亂，安人必藉仁。皇天開白日，殷鼎輟誠臣。", "一日離君側，千官送渭濱。酒傾紅琥珀，馬控白騏驎。", "渥澤番番降，壺漿處處陳。旌幢山色濕，邛僰鳥啼新。", "帟幕還名儉，良醫始姓秦。軍雄城似嶽，地變物含春。", "白必侵雙鬢，清應誡四鄰。吾皇重命相，更合是何人。"]'),
('yuding-17','送智光禪伯','貫休','唐','御定全唐诗','yuding','','[]','萬事歸一衲，曹溪初去尋。從來相狎輩，盡不是知音。',48,'御定全唐詩/json/831.json','["萬事歸一衲，曹溪初去尋。從來相狎輩，盡不是知音。", "乞食林花落，穿雲翠巘深。終希重一見，示我祖師心。"]'),
('yuding-18','夜對雪寄杜使君','貫休','唐','御定全唐诗','yuding','','[]','片片含天意，紛紛勢莫拘。灑于諸瑞後，憂恐一冬無。',96,'御定全唐詩/json/831.json','["片片含天意，紛紛勢莫拘。灑于諸瑞後，憂恐一冬無。", "鶴凚聲偏密，風焦片益粗。冷牽人夢轉，清逼瘴根徂。", "掃徑僧傾笠，為詩士棄爐。橋高銀螮蝀，峰峻玉浮圖。", "盈尺何須問，豐年已可□。遙思郢中曲，句句出冰壺。"]'),
('yuding-19','送王轂及第後歸江西','貫休','唐','御定全唐诗','yuding','','[]','太宗羅俊彥，桂玉比光輝。難得終須得，言歸始是歸。',48,'御定全唐詩/json/831.json','["太宗羅俊彥，桂玉比光輝。難得終須得，言歸始是歸。", "風帆天際吼，金鶚月中飛。五府如交辟，魚書莫便稀。"]'),
('yuding-20','送盧瞻罷廬陵幕歸閿鄉','貫休','唐','御定全唐诗','yuding','','[]','文行成身事，從知貴得仁。歸來還寂寞，何以慰交親。',48,'御定全唐詩/json/831.json','["文行成身事，從知貴得仁。歸來還寂寞，何以慰交親。", "芳草色似動，胡桃花又新。昌朝有知己，好作諫垣臣。"]'),
('yuding-21','避寇白沙驛作','貫休','唐','御定全唐诗','yuding','','[]','避亂無深淺，蒼黃古驛東。草枯牛尚齕，霞濕燒微紅。',48,'御定全唐詩/json/831.json','["避亂無深淺，蒼黃古驛東。草枯牛尚齕，霞濕燒微紅。", "□□時時□，人愁處處同。猶逢好時否，孤坐雪濛濛。"]'),
('yuding-22','聞李頻員外卒','貫休','唐','御定全唐诗','yuding','','[]','蒼蒼難可問，問答亦難聞。落葉平津岸，愁人李使君。',48,'御定全唐詩/json/831.json','["蒼蒼難可問，問答亦難聞。落葉平津岸，愁人李使君。", "文章應力竭，茅土始天分。又逐東風去，迢迢隔嶺雲。"]'),
('yuding-23','江陵寄翰林韓偓學士','貫休','唐','御定全唐诗','yuding','','[]','久住荊溪北，禪關掛綠蘿。風清閒客去，睡美落花多。',48,'御定全唐詩/json/831.json','["久住荊溪北，禪關掛綠蘿。風清閒客去，睡美落花多。", "萬事皆妨道，孤峰謾憶他。新詩舊知己，始為味如何。"]'),
('yuding-24','閒居作','貫休','唐','御定全唐诗','yuding','','[]','閑門微雪下，慵惰計全成。默坐便終日，孤峰只此清。',48,'御定全唐詩/json/831.json','["閑門微雪下，慵惰計全成。默坐便終日，孤峰只此清。", "身心閑少夢，杉竹冷多聲。唯有西峰叟，相逢眼最明。"]'),
('yuding-25','和韋相公見示閑臥','貫休','唐','御定全唐诗','yuding','','[]','刻形求得相，事事未嘗眠。霖雨方為雨，非煙豈是煙。',240,'御定全唐詩/json/831.json','["刻形求得相，事事未嘗眠。霖雨方為雨，非煙豈是煙。", "童收庭樹果，風曳案頭箋。仲虺專為誥，何充雅愛禪。", "靜嫌山色遠，病是酒杯偏。蜩響初穿壁，蘭芽半出磚。", "堂懸金粟像，門枕禦溝泉。旦沐雖頻握，融帷孰敢褰。", "德高群彥表，善植幾生前。修補烏皮幾，深藏子敬氈。", "扶持千載聖，瀟灑一聲蟬。棋陣連殘月，僧交似大顛。", "常知生似幻，維重直如弦。餅憶蓴羹美，茶思嶽瀑煎。", "只聞溫樹譽，堪鄙竹林賢。脫穎三千士，馨香四十年。", "寬平開義路，淡濘潤清田。哲後知如子，空王夙有緣。", "對歸香滿袖，吟次月當川。休說慚如揵，堯天即梵天。"]'),
('yuding-26','寄山中伉禪師','貫休','唐','御定全唐诗','yuding','','[]','舉世遭心使，吾師獨使心。萬緣冥目盡，一句不言深。',48,'御定全唐詩/json/831.json','["舉世遭心使，吾師獨使心。萬緣冥目盡，一句不言深。", "野火燒禪石，殘霞照栗林。秋風溪上路，終願一相尋。"]'),
('yuding-27','秋寄棲一','貫休','唐','御定全唐诗','yuding','','[]','一別一公後，相思時一籲。眼中瘡校未，般若偈持無。',48,'御定全唐詩/json/831.json','["一別一公後，相思時一籲。眼中瘡校未，般若偈持無。", "卷句冰團大，爐煙櫪橛粗。勸君君記取，不用更他圖。"]'),
('yuding-28','懷匡山山長二首','貫休','唐','御定全唐诗','yuding','','[]','白石峰之半，先生好在麼。捲簾當大瀑，常恨不如他。',96,'御定全唐詩/json/831.json','["白石峰之半，先生好在麼。捲簾當大瀑，常恨不如他。", "杉罅龍涎溢，潭坳石發多。吾皇搜草澤，爭奈謝安何。", "見說面前峰，尋常醉亦登。雨餘多菌出，燒甚古崖崩。", "覓句曾沖虎，耕田半為僧。聞名多歲也，常恨不飛騰。"]'),
('yuding-29','懷高真動二首','貫休','唐','御定全唐诗','yuding','','[]','知爾今何處，孤高獨不群。論詩唯許我，窮易到無文。',96,'御定全唐詩/json/831.json','["知爾今何處，孤高獨不群。論詩唯許我，窮易到無文。", "貰酒兒穿雪，尋僧月照雲。何時再相見，兵寇尚紛紛。", "久別無消息，今秋忽得書。諸孤婚嫁苦，求己世情疏。", "亂甚無喬木，溪多不釣魚。只應金嶽色，如爾複如餘。"]'),
('yuding-30','秋末入匡山船行八首','貫休','唐','御定全唐诗','yuding','','[]','楚國茱萸月，吳吟梨栗船。遠遊無定所，高臥是何年。',384,'御定全唐詩/json/831.json','["楚國茱萸月，吳吟梨栗船。遠遊無定所，高臥是何年。", "浪卷紛紛葉，檣沖澹澹煙。去心還自喜，廬岳倚青天。", "蘆葦深花裏，漁歌一曲長。人心雖憶越，帆態似浮湘。", "石獺銜魚白，汀茅浸浪黃。等閒千萬里，道在亦無妨。", "島上離家化，茅茨竹戶開。黃桑雙鵲喜，白日有誰來。", "擔浪澆秋芋，緣灘取淨苔。回頭深自愧，舊業本蒿萊。", "匡阜層層翠，修江疊疊波。從來未曾到，此去複如何。", "水廟寒鴉集，沙村夕照多。誰如垂釣者，孤坐鬢皤皤。", "晚泊蒼茫浦，風微浪亦粗。估喧如亥合，檣密似林枯。", "地峻湖無□，潮寒蚌有珠。東西無定所，何用問前途。", "島香思賈島，江碧憶清江。囊橐誰相似，饞慵世少雙。", "鼉驚入窟月，燒到系船樁。謾有歸鄉夢，前頭是楚邦。", "南北雖無適，東西亦似萍。霞根生石片，象跡壞沙汀。", "莽莽蒹葭赤，微微蜃蛤腥。因思範蠡輩，未免亦飄零。", "曉色千檣去，長江八月時。雨淙山骨出，槔擉岸形卑。", "野水畬田黑，荒汀獨鳥癡。如今是清世，誰道出山遲。"]'),
('yuding-31','送僧歸華山','貫休','唐','御定全唐诗','yuding','','[]','心枯衲亦枯，歸嶽揭空盂。七貴留不住，孤雲出更孤。',48,'御定全唐詩/json/831.json','["心枯衲亦枯，歸嶽揭空盂。七貴留不住，孤雲出更孤。", "燒灰猶湯足，雪片似黏須。他日如相覓，還應道到吳。"]'),
('yuding-32','送友人之嶺外','貫休','唐','御定全唐诗','yuding','','[]','五嶺難為客，君遊早晚回。一囊秋課苦，萬里瘴雲開。',48,'御定全唐詩/json/831.json','["五嶺難為客，君遊早晚回。一囊秋課苦，萬里瘴雲開。", "金柱根應動，風雷舶欲來。明時好□進，莫滯長卿才。"]'),
('yuding-33','送盧舍人朝覲','貫休','唐','御定全唐诗','yuding','','[]','膻行無為日，垂衣帝道亨。聖真千載聖，明必萬年明。',144,'御定全唐詩/json/831.json','["膻行無為日，垂衣帝道亨。聖真千載聖，明必萬年明。", "重德須朝覲，流年不可輕。洪才傳出世，清甲得高名。", "罕玉藏無映，嵇松畫不成。起銜軒後敕，醉別亞夫營。", "燒闊荊州熟，霞新峴首晴。重重堯雨露，去去漢公卿。", "白髮應從白，清貧但更清。夢緣丹陛險，春傍彩衣生。", "既握鐘繇筆，須調傅說羹。倘因星使出，一望問支鏗。"]'),
('yuding-34','上馮使君山水障子','貫休','唐','御定全唐诗','yuding','','[]','憶山歸未得，畫出亦堪憐。崩岸全隳路，荒村半有煙。',144,'御定全唐詩/json/831.json','["憶山歸未得，畫出亦堪憐。崩岸全隳路，荒村半有煙。", "筆句岡勢轉，墨搶燒痕顛。遠浦深通海，孤峰冷倚天。", "柴棚坐逸士，露茗煮紅泉。繡與蓮峰競，威如劍閣牽。", "石門關麈鹿，氣候有神仙。茅屋書窗小，苔階滴瀑圓。", "松根擊石朽，桂葉蝕霜鮮。畫出欺王墨，擎將獻惠連。", "新詩寧妄說，舊隱實如然。願似窗中列，時聞大雅篇。"]'),
('yuding-35','送令狐煥赴闕','貫休','唐','御定全唐诗','yuding','','[]','渚宮遙落日，相送碧江湄。陟也須為相，天乎更贊誰。',48,'御定全唐詩/json/831.json','["渚宮遙落日，相送碧江湄。陟也須為相，天乎更贊誰。", "風高檣力出，霞熱鳥行遲。此去多來客，無忘慰所思。"]'),
('yuding-36','送吳融員外赴闕','貫休','唐','御定全唐诗','yuding','','[]','漢文思賈傅，賈傅遂生還。今日又如此，送君非等閒。',48,'御定全唐詩/json/831.json','["漢文思賈傅，賈傅遂生還。今日又如此，送君非等閒。", "雲寒猶惜雪，燒猛似烹山。應笑無機者，騰騰天地間。"]'),
('yuding-37','送姚洎拾遺自江陵幕赴京','貫休','唐','御定全唐诗','yuding','','[]','捧詔動征輪，分飛楚水濱。由來真廟器，多作伏蒲人。',120,'御定全唐詩/json/831.json','["捧詔動征輪，分飛楚水濱。由來真廟器，多作伏蒲人。", "舍魯知非願，朝天不話貧。沙頭千騎送，島上一蟬新。", "莫使身侵貴，無矜貴逼身。玉階凝正色，蘭苑漲芳塵。", "鑾輅方離華，車書漸似秦。流年飄倏忽，書劄莫因循。", "涼雨鳴紅葉，非煙閉紫宸。憑將西社意，一說向荀陳。"]'),
('yuding-38','送僧入石霜','貫休','唐','御定全唐诗','yuding','','[]','舉世只堪籲，空知與道俱。論心齊至聖，對鏡破凡夫。',216,'御定全唐詩/json/831.json','["舉世只堪籲，空知與道俱。論心齊至聖，對鏡破凡夫。", "業王如雲合，頭低似箭驅。三清徒妄想，千載亦須臾。", "唯我流陽叟，深雲領毳徒。盡騎香白象，皆握月明珠。", "寂寞排松榻，斕斑半雪須。苔侵長者論，嵐蝕祖師圖。", "翠巘金鐘曉，香林寶月孤。兟兟齊白趾，赫赫共洪爐。", "山色鋤難盡，松根踏欲無。難評傳的的，須到不區區。", "撩舍新羅瘦，爐煙榾柮粗。燒畬平虎窟，分瀑入香廚。", "師去情何切，人間事莫拘。穿林宿古塚，踏葉揭空盂。", "無事終無事，令枯便合枯。他年相覓在，亦不是生蘇。"]'),
('yuding-39','送僧歸南康','貫休','唐','御定全唐诗','yuding','','[]','殼殼學得律，還鄉見苦情。遠思芳草盛，不入楚山行。',48,'御定全唐詩/json/831.json','["殼殼學得律，還鄉見苦情。遠思芳草盛，不入楚山行。", "帆入汀煙健，經吟戍月清。到鄉同學輩，應到贛江迎。"]'),
('yuding-40','送陳秀才赴舉兼寄韓舍人','貫休','唐','御定全唐诗','yuding','','[]','主聖臣賢日，求名莫等閒。直須詩似玉，不用力如山。',48,'御定全唐詩/json/831.json','["主聖臣賢日，求名莫等閒。直須詩似玉，不用力如山。", "草白兵初息，年豐駕已還。憑將安養意，一說向曾顏。"]'),
('yuding-41','送友人及第後歸台州','貫休','唐','御定全唐诗','yuding','','[]','得桂為邊辟，翩翩頗合宜。嫖姚留不住，晝錦已歸遲。',48,'御定全唐詩/json/831.json','["得桂為邊辟，翩翩頗合宜。嫖姚留不住，晝錦已歸遲。", "島側花藏虎，湖心浪撼棋。終期華頂下，共禮淥身師。"]'),
('yuding-42','晚春寄張侍郎','貫休','唐','御定全唐诗','yuding','','[]','遐想涪陵岸，山花半已殘。人心何以遣，天步正艱難。',48,'御定全唐詩/json/831.json','["遐想涪陵岸，山花半已殘。人心何以遣，天步正艱難。", "鳥聽黃袍小，城臨白帝寒。應知窗下夢，日日到江幹。"]'),
('yuding-43','寄景判官兼思州葉使君','貫休','唐','御定全唐诗','yuding','','[]','獨住西峰半，尋常欲下難。石多桐屐齾，香甚藥花幹。',48,'御定全唐詩/json/831.json','["獨住西峰半，尋常欲下難。石多桐屐齾，香甚藥花幹。", "荏苒新鶯老，窮通亦自寬。髯參與短簿，始為一吟看。"]'),
('yuding-44','送盧秀才應舉','貫休','唐','御定全唐诗','yuding','','[]','幾載阻兵荒，一名終不忘。還沖猛風雪，如畫冷朝陽。',48,'御定全唐詩/json/831.json','["幾載阻兵荒，一名終不忘。還沖猛風雪，如畫冷朝陽。", "句好慵將出，囊空卻不忙。明年公道日，去去必穿楊。"]'),
('yuding-45','聞新蟬寄桂雍','貫休','唐','御定全唐诗','yuding','','[]','新蟬終夜叫，嘒嘒隔溪濆。杜宇仍相雜，故人聞不聞。',48,'御定全唐詩/json/831.json','["新蟬終夜叫，嘒嘒隔溪濆。杜宇仍相雜，故人聞不聞。", "捲簾花動月，冥目砌生雲。終共謝時去，西山鸞鶴群。"]'),
('yuding-46','寄懷楚和尚二首','貫休','唐','御定全唐诗','yuding','','[]','吾師師子兒，而複貌瑰奇。何得文明代，不為王者師。',96,'御定全唐詩/json/831.json','["吾師師子兒，而複貌瑰奇。何得文明代，不為王者師。", "鐵盂湯雪早，石炭煮茶遲。謾有參尋意，因循到亂時。", "跳躑諸峰險，回翔萬里空。爭將金鎖鎖，那把玉籠籠。", "印缺香崩火，窗疏蠍吃風。永懷今已矣，吟坐雪濛濛。"]'),
('yuding-47','和韋相公話婺州陳事','貫休','唐','御定全唐诗','yuding','','[]','昔事堪惆悵，談玄愛白牛。千場花下醉，一片夢中游。',48,'御定全唐詩/json/831.json','["昔事堪惆悵，談玄愛白牛。千場花下醉，一片夢中游。", "耕避初平石，燒殘沈約樓。無因更重到，且副濟川舟。"]'),
('yuding-0','遇五天僧入五台五首','貫休','唐','御定全唐诗','yuding','','[]','十萬里到此，辛勤詎可論。唯雲吾上祖，見買給孤園。',240,'御定全唐詩/json/832.json','["十萬里到此，辛勤詎可論。唯雲吾上祖，見買給孤園。", "一月行沙磧，三更到鐵門。白頭鄉思在，回首一銷魂。", "雪嶺頂危坐，乾坤四顧低。河橫於闐北，日落月支西。", "水石香多白，猿猱老不啼。空餘忍辱草，相對色萋萋。", "遠禮清涼寺，尋真似善才。身心無所得，日月不將來。", "白疊還圖像，滄溟亦泛杯。唐人亦何幸，處處覺花開。", "塗足油應盡，幹陀帔半隳。辟支迦狀貌，刹利帝家兒。", "結印魔應哭，遊心聖不知。深嗟頭已白，不得遠相隨。", "送迎經幾國，多化帝王心。電激青蓮目，環垂紫磨金。", "眉根霜入細，梵夾蠹難侵。必似陀波利，他年不可尋。"]'),
('yuding-1','經普化禪師影院','貫休','唐','御定全唐诗','yuding','','[]','大一今何處，登堂似昔時。曾蒙金印印，得異野幹兒。',48,'御定全唐詩/json/832.json','["大一今何處，登堂似昔時。曾蒙金印印，得異野幹兒。", "影束龍神在，門荒桐竹衰。誰雲續僧史，別位著吾師。"]'),
('yuding-2','秋寄李頻使君二首','貫休','唐','御定全唐诗','yuding','','[]','為郎須塞詔，當路亦驅驅。貴不因人得，清還似句無。',96,'御定全唐詩/json/832.json','["為郎須塞詔，當路亦驅驅。貴不因人得，清還似句無。", "燒煙連野白，山藥拶階枯。想得征黃詔，如今已在途。", "務簡趣難陪，清吟共綠苔。葉和秋蟻落，僧帶野香來。", "留客朝嘗酒，憂民夜畫灰。終期冒風雪，江上見宗雷。"]'),
('yuding-3','上東林和尚','貫休','唐','御定全唐诗','yuding','','[]','讓紫歸青壁，高名四海聞。雖然無一事，得不是要君。',48,'御定全唐詩/json/832.json','["讓紫歸青壁，高名四海聞。雖然無一事，得不是要君。", "道只傳伊字，詩多笑碧雲。應憐門下客，餘力亦為文。"]'),
('yuding-4','江邊道士','貫休','唐','御定全唐诗','yuding','','[]','獨住大江濱，不知何代人。藥壚生紫氣，肌肉似紅銀。',48,'御定全唐詩/json/832.json','["獨住大江濱，不知何代人。藥壚生紫氣，肌肉似紅銀。", "酒釅竹屋爛，符收山鬼仁。何妨將我去，一看武陵春。"]'),
('yuding-5','送僧之湖外','貫休','唐','御定全唐诗','yuding','','[]','去旨趣非常，春風爾莫狂。惟擎一鐵缽，舊亦講金剛。',48,'御定全唐詩/json/832.json','["去旨趣非常，春風爾莫狂。惟擎一鐵缽，舊亦講金剛。", "午飯孤煙裏，宵禪大石旁。羨師終不及，湘浪淥茫茫。"]'),
('yuding-6','懷謬獨一','貫休','唐','御定全唐诗','yuding','','[]','常憶蘭陵子，瑰奇皴渴才。思還如我苦，時不為伊來。',48,'御定全唐詩/json/832.json','["常憶蘭陵子，瑰奇皴渴才。思還如我苦，時不為伊來。", "嶽霞猱擲雪，湖月浪翻杯。未聞沾寸祿，此事亦堪哀。"]'),
('yuding-7','送廬山衲僧','貫休','唐','御定全唐诗','yuding','','[]','飛錫下崆gk，清高世少雙。凍天方篩雪，別我去何邦。',49,'御定全唐詩/json/832.json','["飛錫下崆gk，清高世少雙。凍天方篩雪，別我去何邦。", "燒繞赤烏亥，雲漫白蚌江。路人爭得識，空仰鬢眉龐。"]'),
('yuding-8','寄西山胡汾、吳樵','貫休','唐','御定全唐诗','yuding','','[]','帶經鋤隴者，何止手胼胝。覓句句句好，慚予筋力衰。',48,'御定全唐詩/json/832.json','["帶經鋤隴者，何止手胼胝。覓句句句好，慚予筋力衰。", "雲塠臨案冷，鹿隊過門遲。相憶空回首，江頭日暮時。"]'),
('yuding-9','休糧僧','貫休','唐','御定全唐诗','yuding','','[]','不食更何憂，自由中自由。身輕嫌衲重，天旱為民愁。',48,'御定全唐詩/json/832.json','["不食更何憂，自由中自由。身輕嫌衲重，天旱為民愁。", "應器誰將去，生台蟻不遊。會須傳此術，相共老山丘。"]'),
('yuding-10','送杜使君朝覲','貫休','唐','御定全唐诗','yuding','','[]','借寇借不得，清聲徹帝聰。坐來千里泰，歸去一囊空。',96,'御定全唐詩/json/832.json','["借寇借不得，清聲徹帝聰。坐來千里泰，歸去一囊空。", "遺愛封疆熟，扳轅草木同。路遙山不少，江靜思無窮。", "花舸沖煙濕，朱衣照浪紅。援毫兩岸曉，欹枕滿旗風。", "道罕將人合，心難與聖通。從茲林下客，應□代天功。"]'),
('yuding-11','送人之嶺外','貫休','唐','御定全唐诗','yuding','','[]','見說還南去，迢迢有侶無。時危須早轉，親老莫他圖。',48,'御定全唐詩/json/832.json','["見說還南去，迢迢有侶無。時危須早轉，親老莫他圖。", "小店蛇羹黑，空山象糞枯。三閭遺廟在，為我一嗚呼。"]'),
('yuding-12','題弘式和尚院兼呈杜使君','貫休','唐','御定全唐诗','yuding','','[]','二雅兼二密，愔愔只自怡。臘高雲屐朽，貌古畫師疑。',48,'御定全唐詩/json/832.json','["二雅兼二密，愔愔只自怡。臘高雲屐朽，貌古畫師疑。", "塹蟻緣金錫，壚煙惹雪眉。仍聞有新作，只是寄相思。"]'),
('yuding-13','湖頭別墅三首','貫休','唐','御定全唐诗','yuding','','[]','梨栗鳥啾啾，高歌若自由。人誰知此意，舊業在湖頭。',144,'御定全唐詩/json/832.json','["梨栗鳥啾啾，高歌若自由。人誰知此意，舊業在湖頭。", "饑鼠掀菱殼，新蟬避栗皺。不知江海上，戈甲幾時休。", "桑柘參桐竹，陰陰一徑苔。更無他事出，只有衲僧來。", "塹蟻爭生食，窗經卷燒灰。可憐門外路，日日起塵埃。", "南北如仙境，東西似畫圖。園飛青啄木，簷掛白蜘蛛。", "鄰叟教修廢，牛童與納租。寄言來往客，不用問榮枯。"]'),
('yuding-14','三峽聞猿','貫休','唐','御定全唐诗','yuding','','[]','歷歷數聲猿，寥寥渡白煙。應棲多月樹，況是下霜天。',48,'御定全唐詩/json/832.json','["歷歷數聲猿，寥寥渡白煙。應棲多月樹，況是下霜天。", "萬里客危坐，千山境悄然。更深仍不住，使我欲移船。"]'),
('yuding-15','聞知聞赴成都辟請','貫休','唐','御定全唐诗','yuding','','[]','文翁還化蜀，帟幕列鵷鸞。飲水臨人易，燒山覓士難。',48,'御定全唐詩/json/832.json','["文翁還化蜀，帟幕列鵷鸞。飲水臨人易，燒山覓士難。", "錦機花正合，棕蕈火初幹。知己相思否，如何借羽翰。"]'),
('yuding-16','題淮南惠照寺律師院','貫休','唐','御定全唐诗','yuding','','[]','儀冠凝寒玉，端居似沃州。學徒梧有鳳，律藏目無牛。',48,'御定全唐詩/json/832.json','["儀冠凝寒玉，端居似沃州。學徒梧有鳳，律藏目無牛。", "茗滑香黏齒，鐘清雪滴樓。還須結西社，來往悉諸侯。"]'),
('yuding-17','秋末長興寺作','貫休','唐','御定全唐诗','yuding','','[]','荒寺古江濱，莓苔地絕塵。長廊飛亂葉，寒雨更無人。',48,'御定全唐詩/json/832.json','["荒寺古江濱，莓苔地絕塵。長廊飛亂葉，寒雨更無人。", "栗不和皺落，僧多到骨貧。行行行未得，孤坐更誰親。"]'),
('yuding-18','寄杭州靈隱寺宋震使君','貫休','唐','御定全唐诗','yuding','','[]','罷郡歸侵夏，仍聞靈隱居。僧房謝脁語，寺額葛洪書。',48,'御定全唐詩/json/832.json','["罷郡歸侵夏，仍聞靈隱居。僧房謝脁語，寺額葛洪書。", "月樹獮猴睡，山池菡萏疏。吾皇愛清靜，莫便結吾廬。"]'),
('yuding-19','送人歸夏口','貫休','唐','御定全唐诗','yuding','','[]','雁雁葉紛紛，行人豈易聞。千山與萬水，何處更逢君。',48,'御定全唐詩/json/832.json','["雁雁葉紛紛，行人豈易聞。千山與萬水，何處更逢君。", "貌不長如玉，人生只似雲。倘經三祖寺，一為禮龕墳。"]'),
('yuding-20','送新羅僧歸本國','貫休','唐','御定全唐诗','yuding','','[]','忘身求至教，求得卻東歸。離岸乘空去，終年無所依。',48,'御定全唐詩/json/832.json','["忘身求至教，求得卻東歸。離岸乘空去，終年無所依。", "月沖陰火出，帆拶大鵬飛。想得還鄉後，多應著紫衣。"]'),
('yuding-21','避寇入銀山','貫休','唐','御定全唐诗','yuding','','[]','草草穿銀峽，崎嶇路未諳。傍山為店戍，永日繞溪潭。',48,'御定全唐詩/json/832.json','["草草穿銀峽，崎嶇路未諳。傍山為店戍，永日繞溪潭。", "燒地生芚蕨，人家煮偽蠶。翻如歸舊隱，步步入煙嵐。"]'),
('yuding-22','聞友人駕前及第','貫休','唐','御定全唐诗','yuding','','[]','見心知命好，一別隔煙波。世亂無全士，君方掇大科。',48,'御定全唐詩/json/832.json','["見心知命好，一別隔煙波。世亂無全士，君方掇大科。", "早隨鑾輅轉，莫戀蜀山多。必貢安時策，忠言奈爾何。"]'),
('yuding-23','避地毗陵上王慥使君','貫休','唐','御定全唐诗','yuding','','[]','至理至昭昭，心通即不遙。聖威無遠近，吾道太孤標。',240,'御定全唐詩/json/832.json','["至理至昭昭，心通即不遙。聖威無遠近，吾道太孤標。", "辛苦蘇氓俗，端貞答盛朝。氣高吞海嶽，貧甚似漁樵。", "庾亮風流澹，劉寬政事超。清須遭貴遇，隱已被誰招。", "栗塢修禪寺，仙香寄石橋。風雷巡稼穡，魚鳥合歌謠。", "視事私終殺，憂民態亦凋。道高無不及，恩甚固難消。", "大寇山難隔，孤城數合燒。烽煙終日起，湯沐用心燋。", "勇義排千陣，誅鋤擬一朝。誓盟違日月，旌旆過寒潮。", "古驛江雲入，荒宮海雨飄。仙松添瘦碧，天驥減豐膘。", "似在陳兼衛，終為宋與姚。已觀雲似鹿，即報首皆梟。", "盡願回清鏡，重希在此條。應憐千萬戶，禱祝向唐堯。"]'),
('yuding-24','送崔尚書朝覲','貫休','唐','御定全唐诗','yuding','','[]','至理契穹旻，方生甫與申。一麾歌政正，三相賀仁人。',144,'御定全唐詩/json/832.json','["至理契穹旻，方生甫與申。一麾歌政正，三相賀仁人。", "叵似盧懷慎，全如邵信臣。澄渟消宿蠹，煦愛劇陽春。", "對客煙花拆，焚香渥澤新。征黃還有自，挽鄧住無因。", "峽水全輸潔，巫娥卻訝神。宋均顏未老，劉寵骨應貧。", "大醉辭王翦，含香望紫宸。三峰初有雪，萬里正無塵。", "伊昔林中社，多招席上珍。終期仙掌下，香火一相親。"]'),
('yuding-25','寒夜有懷同志','貫休','唐','御定全唐诗','yuding','','[]','永夜殊不寐，懷君正寂寥。疏鐘寒遍郭，微雪靜鳴條。',48,'御定全唐詩/json/832.json','["永夜殊不寐，懷君正寂寥。疏鐘寒遍郭，微雪靜鳴條。", "南省雁孤下，西林鶴屢招。終當謝時去，與子住山椒。"]'),
('yuding-26','寄新定桂雍','貫休','唐','御定全唐诗','yuding','','[]','獨自住烏龍，應憐是衲僧。句須人未道，君此事偏能。',48,'御定全唐詩/json/832.json','["獨自住烏龍，應憐是衲僧。句須人未道，君此事偏能。", "塢濕雲埋觀，溪寒月照罾。相思不可見，江上立騰騰。"]'),
('yuding-27','贈靈鷲山道潤禪師院','貫休','唐','御定全唐诗','yuding','','[]','常恨煙波隔，聞名二十年。結為清氣引，來到法堂前。',48,'御定全唐詩/json/832.json','["常恨煙波隔，聞名二十年。結為清氣引，來到法堂前。", "薪拾紛紛葉，茶烹滴滴泉。莫嫌來又去，天道本泠然。"]'),
('yuding-28','幹霄亭晚望懷王棨侍郎','貫休','唐','御定全唐诗','yuding','','[]','霜打汀島赤，孤煙生池塘。清吟倚大樹，瑤草何馨香。',48,'御定全唐詩/json/832.json','["霜打汀島赤，孤煙生池塘。清吟倚大樹，瑤草何馨香。", "久別青雲士，常思白石房。誰能共歸去，流水似鳴璫。"]'),
('yuding-29','海邊見羅鄴','貫休','唐','御定全唐诗','yuding','','[]','清世詩聲出，誰人得似君。命通須有日，天未喪斯文。',48,'御定全唐詩/json/832.json','["清世詩聲出，誰人得似君。命通須有日，天未喪斯文。", "楚木寒連寺，修江碧入雲。相思喜相見，庭葉正紛紛。"]'),
('yuding-30','送僧之東都','貫休','唐','御定全唐诗','yuding','','[]','之子之東洛，囊中有偈新。紅塵誰不入，獨鶴自難親。',48,'御定全唐詩/json/832.json','["之子之東洛，囊中有偈新。紅塵誰不入，獨鶴自難親。", "定鼎門連岳，黃河凍過春。憑師將遠意，說似社中人。"]'),
('yuding-31','送于兢補闕赴京','貫休','唐','御定全唐诗','yuding','','[]','亂離吾道在，不覺到清時。得句下雪嶽，送君登玉墀。',48,'御定全唐詩/json/832.json','["亂離吾道在，不覺到清時。得句下雪嶽，送君登玉墀。", "冷驚蟬韻斷，涼觸火雲隳。倘遇南來使，無忘問所之。"]'),
('yuding-32','送鄭准赴舉','貫休','唐','御定全唐诗','yuding','','[]','兩河兵火後，西笑見吾曹。海靜三山出，天空一鶚高。',48,'御定全唐詩/json/832.json','["兩河兵火後，西笑見吾曹。海靜三山出，天空一鶚高。", "賃居槐拶屋，行卷雪埋袍。他日如相覓，栽桃近海濤。"]'),
('yuding-33','寄拄杖上王使君','貫休','唐','御定全唐诗','yuding','','[]','拄杖鄰僧與，殊常不可名。一條黳玉重，百兩紫金輕。',48,'御定全唐詩/json/832.json','["拄杖鄰僧與，殊常不可名。一條黳玉重，百兩紫金輕。", "有乳盤春力，無心合道情。惟宜高處著，將寄謝宣城。"]'),
('yuding-34','秋望寄王使君','貫休','唐','御定全唐诗','yuding','','[]','靜躡紅蘭徑，憑高曠望時。無端求句苦，永日壑風吹。',48,'御定全唐詩/json/832.json','["靜躡紅蘭徑，憑高曠望時。無端求句苦，永日壑風吹。", "大月生峰角，殘霞在樹枝。只應劉越石，清嘯正相宜。"]'),
('yuding-35','送緣有禪師與雷處士入武夷山','貫休','唐','御定全唐诗','yuding','','[]','師與雷居士，尋山道入閩。應將熊耳印，別授武夷君。',48,'御定全唐詩/json/832.json','["師與雷居士，尋山道入閩。應將熊耳印，別授武夷君。", "崖罅仙棺出，江垠毒草分。他年相覓在，莫苦入深雲。"]'),
('yuding-36','送友生入越投知己','貫休','唐','御定全唐诗','yuding','','[]','才大終難住，東浮景漸暄。知將刖足恨，去擊李膺門。',48,'御定全唐詩/json/832.json','["才大終難住，東浮景漸暄。知將刖足恨，去擊李膺門。", "宿霧開花塢，春潮入苧村。預思秋薦後，一鶚出乾坤。"]'),
('yuding-37','寄烏龍山賈泰處士','貫休','唐','御定全唐诗','yuding','','[]','庭果色如丹，相思夕照殘。雲邊踏燒去，月下把書看。',48,'御定全唐詩/json/832.json','["庭果色如丹，相思夕照殘。雲邊踏燒去，月下把書看。", "澗水仙居共，窗風漆樹寒。吾君方側席，未可便懷安。"]'),
('yuding-38','題大安寺通禪師院','貫休','唐','御定全唐诗','yuding','','[]','應行諸嶽遍，象屣半無綱。一法尋常說，此機仍未忘。',48,'御定全唐詩/json/832.json','["應行諸嶽遍，象屣半無綱。一法尋常說，此機仍未忘。", "窗閑藤影老，衲厚瀑痕荒。寄語迷津者，來茲問不妨。"]'),
('yuding-39','春晚寄盧使君','貫休','唐','御定全唐诗','yuding','','[]','滿郭春如畫，空堂心自澄。禪拋金鼎藥，詩和玉壺冰。',48,'御定全唐詩/json/832.json','["滿郭春如畫，空堂心自澄。禪拋金鼎藥，詩和玉壺冰。", "白雨飄花盡，晴霞向閣凝。寂寥還得句，因寄柳吳興。"]'),
('yuding-40','武昌縣與晝公兼寄邑宰','貫休','唐','御定全唐诗','yuding','','[]','小一何人識，騰騰天地間。尋常如一鶴，亦不愛青山。',48,'御定全唐詩/json/832.json','["小一何人識，騰騰天地間。尋常如一鶴，亦不愛青山。", "鐵缽年多赤，麻衣帶毳斑。只聞尋五柳，時到月中還。"]'),
('yuding-41','別東林僧','貫休','唐','御定全唐诗','yuding','','[]','大士宅裏宿，芙蓉龕畔遊。自憐□□在，子莫苦相留。',48,'御定全唐詩/json/832.json','["大士宅裏宿，芙蓉龕畔遊。自憐□□在，子莫苦相留。", "燥葉飄山席，孤雲傍茗甌。裴回不能去，房在好峰頭。"]'),
('yuding-42','避地寄高蟾','貫休','唐','御定全唐诗','yuding','','[]','荒寺雨微微，空堂獨掩扉。高吟多忤俗，此貌若為饑。',48,'御定全唐詩/json/832.json','["荒寺雨微微，空堂獨掩扉。高吟多忤俗，此貌若為饑。", "旅夢遭鴻喚，家山被賊圍。空餘老萊子，相見獨依依。"]'),
('yuding-43','懷武夷山禪師','貫休','唐','御定全唐诗','yuding','','[]','萬疊仙山裏，無緣見有緣。紅心蕉繞屋，白額虎同禪。',48,'御定全唐詩/json/832.json','["萬疊仙山裏，無緣見有緣。紅心蕉繞屋，白額虎同禪。", "古木苔封菌，深崖乳雜泉。終期還此去，世事只如然。"]'),
('yuding-44','秋末閒居作','貫休','唐','御定全唐诗','yuding','','[]','幽居山不別，落葉與階平。盡日吟詩坐，無端個病成。',48,'御定全唐詩/json/832.json','["幽居山不別，落葉與階平。盡日吟詩坐，無端個病成。", "徑苔因旱赤，池水入冬清。惟有東峰叟，相尋月下行。"]'),
('yuding-45','贈許征君','貫休','唐','御定全唐诗','yuding','','[]','晝公友秦奚，來往踏溪雲。如今又到我，還愛許征君。',48,'御定全唐詩/json/832.json','["晝公友秦奚，來往踏溪雲。如今又到我，還愛許征君。", "落花鳥銜來，永日香氤氳。終期將爾曹，歸去麋鹿群。"]'),
('yuding-46','秋夜作因懷天臺道者','貫休','唐','御定全唐诗','yuding','','[]','萬事何須問，良時即此時。高秋半夜雨，落葉滿前池。',48,'御定全唐詩/json/832.json','["萬事何須問，良時即此時。高秋半夜雨，落葉滿前池。", "靜怕龍神識，貧從草木欺。平生無限事，只有道人知。"]'),
('yuding-47','偶作因懷大同道友','貫休','唐','御定全唐诗','yuding','','[]','蠻木葉不落，微吟漳水濱。二毛空有雪，萬事不如人。',49,'御定全唐詩/json/832.json','["蠻木葉不落，微吟漳水濱。二毛空有雪，萬事不如人。", "df水準芳草，山花落淨巾。天童好真伴，何日更相親。"]'),
('yuding-48','邊上行','貫休','唐','御定全唐诗','yuding','','[]','黑松林外路，風角遠嗈嗈。朔氣生荒堡，秋塵滿病容。',48,'御定全唐詩/json/832.json','["黑松林外路，風角遠嗈嗈。朔氣生荒堡，秋塵滿病容。", "豺掊沙底骨，人上月邊烽。休作西行計，西行地漸凶。"]'),
('yuding-49','江西再逢周璉','貫休','唐','御定全唐诗','yuding','','[]','六七年不見，相逢鬢已蒼。交情終淡薄，詩語更清狂。',48,'御定全唐詩/json/832.json','["六七年不見，相逢鬢已蒼。交情終淡薄，詩語更清狂。", "未得丹霄便，依前四壁荒。但令吾道在，晚達亦何妨。"]'),
('yuding-50','登鄱陽寺閣','貫休','唐','御定全唐诗','yuding','','[]','寺樓閑縱望，不覺到斜暉。故國在何處，多年未得歸。',48,'御定全唐詩/json/832.json','["寺樓閑縱望，不覺到斜暉。故國在何處，多年未得歸。", "寒江平楚外，細雨一鴻飛。終斅于陵子，吳山有綠薇。"]'),
('yuding-51','秋晚野居','貫休','唐','御定全唐诗','yuding','','[]','僻居人不到，吾道本來孤。山色園中有，詩魔象外無。',48,'御定全唐詩/json/832.json','["僻居人不到，吾道本來孤。山色園中有，詩魔象外無。", "霜禾連島赤，煙草倚橋枯。何必求深隱，門前似畫圖。"]'),
('yuding-52','酬杜使君見寄','貫休','唐','御定全唐诗','yuding','','[]','軋軋複軋軋，更深門未關。心疼無所得，詩債若為還。',48,'御定全唐詩/json/832.json','["軋軋複軋軋，更深門未關。心疼無所得，詩債若為還。", "露灑一鶴睡，鐘餘萬象閑。慚將此時意，明日寄東山。"]'),
('yuding-53','湖上作','貫休','唐','御定全唐诗','yuding','','[]','我竟胡為者，嘮嘮但愛吟。身中多病在，湖上住年深。',48,'御定全唐詩/json/832.json','["我竟胡為者，嘮嘮但愛吟。身中多病在，湖上住年深。", "山溜穿苔壁，風鐘度雪林。近來心更苦，誰複是知音。"]'),
('yuding-54','送僧歸天臺寺','貫休','唐','御定全唐诗','yuding','','[]','天臺四絕寺，歸去見師真。莫折枸杞葉，令他十得嗔。',48,'御定全唐詩/json/832.json','["天臺四絕寺，歸去見師真。莫折枸杞葉，令他十得嗔。", "天空聞聖磬，瀑細落花巾。必若雲中老，他時得有鄰。"]'),
('yuding-0','壽春節進','貫休','唐','御定全唐诗','yuding','','[]','聖運關天紀，龍飛古帝基。振搖三蜀地，聳發萬年枝。',577,'御定全唐詩/json/833.json','["聖運關天紀，龍飛古帝基。振搖三蜀地，聳發萬年枝。", "出震同中古，承幹動四夷。恩頒新命廣，淚向舊朝垂。", "大寶歸玄讖，殊祥出遠池。法天深罔測，體聖妙難知。", "儉德為全德，無思契十思。丕圖非力致，英武悉天資。", "正直方親切，回邪豈敢窺。將排頗與牧，相得稷兼夔。", "鹽出符真主，麟來合大規。賡歌隨羽鑰，奕葉斅伊祁。", "寡欲情雖泰，憂民色未怡。盛如唐創業，宛勝晉朝儀。", "旰食宮鶯囀，宵衣禁漏遲。多於湯土地，還有禹胼胝。", "視物如傷日，勝殘去殺時。守文情的的，無逸戒孜孜。", "軒頊風重振，皇唐鼎創移。始聞呈瑞石，又報產靈芝。", "覆幬高緣大，包容妙在卑。兄呼春赫日，師指佛牟尼。", "佳氣宸居合，淳風樂府吹。急賢彰帝業，解網見天慈。", "粟赤千千窖，軍雄萬萬兒。八蠻須稽顙，四海仰昌期。", "玉輦嬪嬙擁，宮花錦繡欹。堯雲同靉靆，漢祖太驅馳。", "氛祲根株盡，澆訛朕兆隳。山河方有截，野逸詔無遺。", "境靜消鋒鏑，田香熟稻r1。夢中逢傅說，殿上見辛毗。", "金鏡懸千古，彤雲起四維。盛行唐典法，再睹舜雍熙。", "祝壽幹文動，郊天太一隨。煌煌還宿衛，亹亹葉聲詩。", "飲醴和甘雨，非煙繞禦帷。銀輪隨寶馬，玉沼見金龜。", "杳杳聞韻濩，重重降撫綏。魏征須卻出，葛亮更何之。", "簡約逾前古，升平美不疑。觸邪羊唅唅，鼓腹叟嘻嘻。", "邁五方雲大，超三始見奇。錦霞連紫極，仙鳥下峨眉。", "謝傅還為傅，周師又作師。納隍為永任，從諫契無為。", "子子寰瀛主，孫孫日月旗。壽春嗟壽域，萬國盡虔祈。"]'),
('yuding-1','送僧之安南','貫休','唐','御定全唐诗','yuding','','[]','安南千萬里，師去趣何長。鬢有炎州雪，心為異國香。',48,'御定全唐詩/json/833.json','["安南千萬里，師去趣何長。鬢有炎州雪，心為異國香。", "退牙山象惡，過海布帆荒。早作歸吳計，無忘父母鄉。"]'),
('yuding-2','送僧歸剡山','貫休','唐','御定全唐诗','yuding','','[]','遠逃為亂處，寺與石城連。木落歸山路，人初刈剡田。',48,'御定全唐詩/json/833.json','["遠逃為亂處，寺與石城連。木落歸山路，人初刈剡田。", "荒林猴咬栗，戰地鬼多年。好去楞伽子，精修莫偶然。"]'),
('yuding-3','送僧入幽州','貫休','唐','御定全唐诗','yuding','','[]','高士高無敵，騰騰話入燕。無人知爾意，向我道非禪。',48,'御定全唐詩/json/833.json','["高士高無敵，騰騰話入燕。無人知爾意，向我道非禪。", "栗徑穿蕃塚，狼聲隔遠煙。盤山多道侶，應未有歸年。"]'),
('yuding-4','送僧遊五台','貫休','唐','御定全唐诗','yuding','','[]','羨師遊五頂，乞食值年豐。去去誰為侶，棲棲力已充。',48,'御定全唐詩/json/833.json','["羨師遊五頂，乞食值年豐。去去誰為侶，棲棲力已充。", "濁河高岸拆，衰草古城空。必到華嚴寺，憑師問辨公。"]');
